const DATA=[
{"no": 1, "corp": "イオンアグリ創造株式会社", "name": "福永 庸明", "role": "代表取締役社長", "star": 3, "head": "サプライチェーン一貫型農業ビジネスの「AEON農場」ブランド", "prof": "1995年4月、ウエルマート㈱（現マックスバリュ西日本㈱）入社。2006年4月、マックスバリュ西日本㈱ 農産商品部長就任。2009年7月、イオンアグリ創造㈱生産本部長兼管理本部長就任。2012年4月、イオンアグリ創造㈱代表取締役社長（現任）。", "url": "https://aeonagricreate.jp/", "photo": "assets/photos/post-65_t.jpg", "hero": "assets/photos/post-65_h.jpg", "secs": [{"h": "サプライチェーン一貫型農業ビジネスの「AEON農場」ブランド", "ps": ["イオンアグリ創造株式会社は千葉市に本社機能を持つイオンのグループ会社で、「農業の発展とお客さまの価値を創造する」を理念にかかげ、イオン直営農場の運営および農産物の生産委託に取り組んでいる。直営事業、オーガニック事業、パートナー事業の3つの事業を柱に、若い力による未来の農業の創造に向け様々なことにチャレンジしている企業だ。", "イオンは、小売業を起点に消費者のくらしの変化を先取りしながら多様な事業を成長させてきた。店舗に寄せられる「お客さまの声」を経営に反映し、サプライチェーン発想での価値創造を大切にしている。農作物の調達においても、高齢化や後継者不足による農業人口の減少など、日本全体が抱える課題の解決に向けて積極的に取り組むべく農業法人を立ちあげた。持続可能な農業の実現、地域農業を支える次世代農業者の育成、農業の脱炭素化・DX化、プロダクションロス削減など、その挑戦は多岐にわたる。"], "imgs": ["assets/photos/post-65_b1.jpg"]}, {"h": "“受け皿”が求められていた…農業を志望する学生の存在", "ps": ["2009年、イオンは「イオンアグリ創造」を設立し、農業分野に参入した。日本の農業は生産者の高齢化や担い手の不足、耕作放棄地の拡大など、長年にわたり多くの課題を抱えていた。イオンは、農地法が改正された2009年にイオンアグリ創造を設立し、同年7月に茨城県牛久市との間で、農業参入に関する協定と土地の賃貸借に関する契約を締結、2.6ヘクタールの耕作放棄地解消プログラムを活用して農業に参画。第1号農場となる「茨城牛久農場」を開場することとなる。以来、新しい農業経営モデルの確立に向けて挑戦を続けている。", "イオンアグリ創造は、店舗から届くお客さまの声を生産に反映するだけでなく、生産現場の課題を企業経営視点で捉え、小売業が持つインフラや知見を新たな農業経営に取り入れ、順調に規模を拡大していく。設立から6年目の2015年度には「どれぐらいの応募があるだろうか」と不安な気持ちを抱えつつも初の新卒採用を行った。当時、社内の誰もが「農業は若年層から敬遠される職業なのだろう」と思っていた。ところが、最終的にはエントリー数が3,000人以上、なんと倍率は100倍超を記録。志望してくる学生は農学部出身者だけではなく､経済学部や商学部など様々だった。", "農作物の生産や流通に携わる職は、専門性も高くそもそもの採用人数が少ない。メーカーや小売店に就職して、すぐに希望する職に就けるかどうかもわからない。かといって、学校を卒業してすぐに独立就農するのもハードルが高い。そういった若い世代がイオンアグリ創造への入社を希望してくれたのだろう。未来の農業を担う若い世代が、安心してイキイキと働ける、持続可能な農業に携われる、そういった環境を整えることがイオンアグリ創造の使命のひとつなのだということを初めて明確に認識した出来事だったという。"], "imgs": []}, {"h": "平均年齢36歳。若さで農業を改革せよ", "ps": ["創業から15年経ったイオンアグリ創造。社員の平均年齢は36.2歳と、日本の農業従事者の平均年齢68.4歳と比べて、圧倒的に若い。先人の熟練された技術が彼らに継承され、同時に先端技術を活用することで栽培技術と経営力が底上げされる。加えて、各農場間で農場運営に関わるさまざまな情報を日々共有することで、かつてない安定した農業生産活動が実現できているのだ。", "お客さまの意見を直接農場に反映できる強みを持つイオンアグリ創造は、お客さまと直接対話するべく、さまざまな販売方法や情報発信にも取り組んでいる。自社で運用している Instagram ではフォロワー100万人を目標に、日々の農場の様子や栽培のこだわり、おススメの料理方法を紹介し、ワクワクする農場発信に努めている。", "店頭での立売販売については、お客さまが「なぜその商品を購入したのか」を直接聞き、データ上からは読み取ることができない購買理由を見つけることを心がけている。そして3年目を迎える 自社ECサイト ではヴィーガン認証商品セットや、農場から直接お届けする季節限定の特大トマトといった、まさに「ここでしか買えない商品」を販売するべく取り組んでいるという。"], "imgs": ["assets/photos/post-65_b2.jpg"]}, {"h": "イオンアグリだからできる「持続可能な農業」の実現", "ps": ["イオンアグリ創造は持続可能な農業を実現するために、オーガニック栽培に注力し、オーガニック生産者との連携の輪を広げている。原則有機JAS認証が認められていない養液栽培のみを行っているイオン埼玉久喜農場を除く全国20農場で段階的にオーガニックに転換するよう取り組んでおり、すでに直営の5農場で有機JAS認証を取得している。また「イオンオーガニックアライアンス」を設立し、全国の生産者同士がつながる場を提供している。", "また世界共通の課題である「脱炭素」にも注力している。埼玉久喜農場ではJクレジット（日本版カーボンクレジット）にいち早く取り組んでおり、年間で約120トンのCO2の削減に取り組んでいることを認定された。また島根安来農場のいちご栽培においては「温室効果ガス（GHG）排出ネットゼロ」プロジェクトが始動しており、パートナー企業である株式会社タクマと協業して、町田市のごみ処理施設から排出されるCO2を農業ハウスで利用する実証実験に取り組んでいる。", "そしてプロダクションロス削減の取り組みにも注力している。生産段階で生じる「食べられるけれど廃棄せざるを得ない」規格外農産物を活かす取り組みとして、オフィスビルで販売会を開催したり、ジュースなどの加工食品にして販売したり、地域の子ども食堂に寄贈したり、町の動物園に寄贈したりしているという。またハナマルキ株式会社と協業して、これまで食べられないものとして廃棄されていた未成熟な青いトマトをはじめ規格外の野菜を、調味料「液体塩こうじ」でおいしく食べるという企画を立ち上げて、レシピ提供とともに販売を開始している。"], "imgs": ["assets/photos/post-65_b3.jpg"]}, {"h": "「はじまりの日」を忘れずに", "ps": ["今後は直営農場を順次、有機栽培に移行していく予定だと語る福永社長。付加価値を追求した「まるまる赤トマト」や「まるまる赤いちご」、「今朝採り野菜」の生産と販売に取り組み、川上から川下までのサプライチェーンを持つ、「イオングループだからこそできる商品化」の実現に向けて取り組んでいる。", "そして2025年には農業のゼロカーボン宣言、2028年までには直営20農場のオーガニックシフトを掲げている。農業を仕事にしたい若者の受け皿になりつづけるべく、積極的に技術革新を取り込み、気象環境に左右されない安定した農場経営を実現し、これらを実現できる人材の確保と育成に注力し続けるという。", "「当社は、お客さまを原点にした小売業から生まれた農業法人として2009年に設立されました。「はじまりの日」を忘れずに、当社メンバーが力を合わせて持続可能で、若者に魅力あふれるイオンアグリ創造であり続けたいと思います。」と語る福永社長。イオンアグリ創造の今後に注目したい。"], "imgs": ["assets/photos/post-65_b4.jpg"]}]},
{"no": 2, "corp": "株式会社ウェザーニューズ", "name": "草開 千仁", "role": "", "star": 3, "head": "千葉が誇る世界最大規模の民間気象情報会社", "prof": "", "url": "https://jp.weathernews.com/", "photo": "assets/photos/post-59_t.jpg", "hero": "assets/photos/post-59_h.jpg", "secs": [{"h": "千葉が誇る世界最大規模の民間気象情報会社", "ps": ["海に面した千葉市美浜区に本社・グローバルセンターを置く株式会社ウェザーニューズは、世界初、そして世界最大規模の民間気象情報会社である。日本国内の主要な天気予報の中で予報精度No.1を2年連続で獲得してきた実績を持ち、10分間隔で業界最長の30時間先まで表示可能な超高解像度の「雨雲レーダー」など人気コンテンツが充実している。2021年のNHK連続テレビ小説「おかえりモネ」では台本考証および美術協力に携わっており、気象予報士の社会的ニーズにも多大なる影響を与えていたのは記憶に新しい。", "気象庁が管理している1,300ものアメダスの約10倍の観測網を持っており、さらに取得したデータをより実践的に活用できるように独自のロジックを組んでいる。例えば停電が発生したとき、停電したエリアと停電時の気象情報とをAIで分析し、分析結果と今後の停電予測地域がわかるようにしているという。", "「いざという時、人の役に立ちたい」を合い言葉に、世界約50カ国の顧客へ24時間365日、気象に関するさまざまなリスクコミュニケーションサービスを行っているウェザーニューズ。こと近年さらなる猛威を振るっている台風やハリケーン、そして豪雨による洪水の増加など、災害リスクへの対策がより重要なテーマとなってきている昨今、世界最大各地で発生する気象現象を正しく把握するための独自の観測インフラの開発や、各国の気象・地象リスクを深く理解するための研究に日夜取り組んでいる。"], "imgs": ["assets/photos/post-59_b1.jpg"]}, {"h": "気象情報を肌で感じられる海浜幕張", "ps": ["株式会社ウェザーニューズは1970年1月に発生した福島県沖の海難事故から生まれた、創業者・石橋博良の「船乗りの命を守りたい」という熱い使命が創業のきっかけとなり、1986年に設立。海から始まった気象サービスの市場は、空そして陸へと様々なニーズへ拡大していくこととなる。", "今や世界規模で活躍中のウェザーニューズ。グローバルセンターとして位置づけている本社は、幕張メッセやZOZOマリンスタジアムなどがある幕張新都心にある。海浜幕張は東京湾に面しているだけでなく、高速道路や鉄道がすぐ近くを通っており、成田空港、羽田空港といった大規模な国際空港にもアクセスしやすい。ウェザーニューズのクライアントである交通事業者が今どのような気象の影響を受けているかを肌で感じながらサービスを提供できる環境であることから、海浜幕張を選択したという。"], "imgs": ["assets/photos/post-59_b2.jpg"]}, {"h": "止まらない快進撃を支える社員の存在", "ps": ["現在、会社全体では1,100名規模になっているウェザーニューズ。一般向けのお天気アプリ「ウェザーニュース」は累計3,700万ダウンロード（2024年3月時点）を突破し、YouTubeのチャンネル登録者数は118万人を記録。法人としては国内の主要な交通インフラ企業のほとんどと連携しており、各企業向けにカスタマイズされた気象情報をリアルタイムに提供している。", "最近ではサービスコンテンツ自体の開発スピードを上げ、より世の中に新しいコンテンツを出していく方針を取っており、システム開発に必要な人材も新卒・中途問わず積極的に採用しているという。", "今回インタビューに応えてくれた竹本さんは大学で地質学を専攻していたが、減災や防災に役立つ人材になりたいと考えウェザーニューズに入社。各クライアントの事業に最も適した気象情報を提供する営業活動を経験し、現在は広報担当としてより多くの方々にサービスを知ってもらうよう、さまざまな取り組みに挑戦している。"], "imgs": ["assets/photos/post-59_b3.jpg", "assets/photos/post-59_b4.jpg"]}, {"h": "ビジネスにもっと天気を", "ps": ["ウェザーニューズでは2023年より「船乗りの命を守りたい。地球の未来も守りたい。」という新しいスローガンを掲げて取り組みを進めている。とりわけ重点的な施策として、SaaSモデルによる新たな顧客層の開拓に力を入れているという。", "特に現在は「ウェザーニュース for business」というSaaS型のサービスに力を入れている。比較的安価に利用可能なプラットフォームで、ドローン、小売、ダムといった業界ごとにカスタマイズされた気象情報をPCやアプリで簡単に確認できるサービスを提供している。", "また独自のIoT気象観測センサーも開発している。ソラテナProと呼ばれるこのセンサーは片手で持てるほどのサイズで、雨量、風向・風速、気温、気圧など7つの要素を測定できる代物だ。1分ごとのデータをスマホアプリやパソコンで確認でき、リアルタイムに熱中症のリスクを判定することもできる。例えば農家の方はこれを活用して土壌の酸素量を管理し、作物の生産性を向上させることが可能になる。安全対策はもちろん、これからは気象情報を、ビジネスをより効率的にさせるものとして活用の幅を広げようとしているのだ。"], "imgs": ["assets/photos/post-59_b5.jpg", "assets/photos/post-59_b6.jpg"]}]},
{"no": 3, "corp": "日本空港無線サービス 株式会社", "name": "増澤 俊也", "role": "", "star": 3, "head": "空の玄関口たらしめる航空無線技術とは", "prof": "2022年5月、日本空港無線サービス株式会社に入社。サービスエンジニアとして設備更改計画の策定、設備設計、施工会社との契約、新旧設備の切り替えに伴うお客様対応を行っている。", "url": "https://www.airportradio.co.jp/", "photo": "assets/photos/post-46_t.jpg", "hero": "assets/photos/post-46_h.jpg", "secs": [{"h": "空の玄関口たらしめる航空無線技術とは", "ps": ["千葉県成田市にある成田国際空港。羽田空港と並んで言わずと知れた日本の空の玄関口であり、その利便性や規模、グランドスタッフのサービス品質など多岐に渡って世界中から高い評価を受けている。", "そんな成田国際空港の開港に合わせて創設された企業である日本空港無線サービス株式会社は、常に空港関係各社、航空業界各社の声に耳を傾け、サービスの維持・向上を図り、成田国際空港の敷地内にオフィスを構えて活動している。主に電気通信事業と電気通信設備に関連するサービスを提供しており、特に空港内のコミュニケーション用無線通信サービスに特化しているのが特徴だ。", "今もなお、日本の国際インフラを支え続けている日本空港無線サービス株式会社。航空業界で働くことを夢見て航空系学校に進学し、2022年に入社、現在サービスエンジニアとして活躍している山口さんに話を聞いてみた。"], "imgs": ["assets/photos/post-46_b1.jpg"]}, {"h": "40年以上の信頼と実績", "ps": ["日本空港無線サービス株式会社は、成田国際空港開港前年の1977年に、空港運営に必要となるパイロットと地上オペレーションセンター間の無線通信や空港内で働く方々のコミュニケーション用無線通信サービスを提供する会社として創業した。", "以来航空業界の拡大と無線技術の進化とともに、システムの高度化と利便性向上をはかり、40年以上にわたって主要空港の業務と安全・安心を支えてきた。特にA/G無線電話サービスは、国内外の航空会社に広く利用されている。"], "imgs": ["assets/photos/post-46_b2.jpg"]}, {"h": "国内外で高く評価されている無線技術", "ps": ["パイロットと地上のオペレーションセンターを繋ぐA/G（Air to Ground）無線電話サービスは、国内外の航空会社を中心に日本全国13の拠点にて約170社が利用している。昨今は、運行管理拠点の集約や分散に対応したリモート接続の要望に応えるため、PC1台から複数空港の無線送受信可能なシステムをワンストップソリューションで提供している。", "また、地上の様々な組織が利用している空港MCA無線サービスは、日頃の空港業務だけでなく、災害時の情報連絡手段としても重要な通信基盤であり、現在は成田国際空港、那覇空港、中部国際空港、関西国際空港といった日本の代表的な空港で利用されているという。", "このサービスを支える公共安全向け業務用無線の国際標準方式の「TETRA」は、その品質と信頼性に高い評価を得ており、最近は国際的スポーツイベント開催期間のオペレーションや、感染水際対策の最前線である空港検疫業務の主要な連絡ツールとしても活躍している。またTETRAの相互接続機能を活かしたスマートフォン接続機能も好評で、テレワーク中の空港管理者様の業務状況把握や緊急連絡用として活用されることが期待されるという。"], "imgs": ["assets/photos/post-46_b3.jpg"]}, {"h": "逆境の航空業界を支える存在として", "ps": ["現在、航空業界ではコロナ禍により停止していた就航路線の再開や新規就航開始がなされ、グランドハンドリングを始めとした現場業務の人員確保が急務となっている状況だ。国交省もエアラインや空港運営会社と連携して人材確保のため職場環境の改善に業界を挙げて取り組むとともに、人手不足への対応として、空港運営に関わる現場業務の省人化・自動化に寄与する各種施策・取組みを加速している。", "また航空需要拡大に伴うフライト数の増加や航空機離着陸の混雑に伴う滑走路・誘導路への誤進入の防止等を始めとした空港内業務の更なる安全強化も課題となっており、これまで人手でカバーしていた空港内旅客機周辺業務に関する安全確保についても、新たな技術を用いた取組みなどが強く求められている。", "「今後の展望として、日本空港無線サービスは航空業界の需要拡大に伴い、サービスシステムの更改・アップデートを進め、より機能拡充と利便性向上を図る計画です。無線通信技術の進化に注視し、私たち自身も技術などのアップデートを日々おこなっていきます。」と語る山口さん。これからも日本空港無線サービス株式会社は、空の安全を成田から支えていくに違いない。"], "imgs": ["assets/photos/post-46_b4.jpeg"]}]},
{"no": 4, "corp": "プレシジョン・システム・サイエンス株式会社", "name": "田島 秀二", "role": "代表取締役社長", "star": 3, "head": "日々の研究に欠かせない存在・PSSとは", "prof": "1976年4月アドパンテック東洋株式会社入社。1989年2月当社入社、4月取締役就任。1989年6月当社代表取締役社長就任（現任）。2021年1月、全自動PCR検査システムがそれぞれ「2020年日経優秀製品・サービス賞：日経産業新聞賞」（エリート インジーニアス）、「2020年日刊工業新聞・第63回十大新製品賞：本賞」（ジーンリード エイト）を受賞。2022年11月、令和4年秋の叙勲にて「旭日単光章」を受章。", "url": "https://www.pss.co.jp/", "photo": "assets/photos/post-52_t.jpg", "hero": "assets/photos/post-52_h.jpg", "secs": [{"h": "日々の研究に欠かせない存在・PSSとは", "ps": ["千葉県松戸市にあるプレシジョン・システム・サイエンス株式会社は、バイオ関連業界向けに臨床検査の実用化に関する事業を、ワールドワイドに展開しているグローバル企業だ。", "田島代表が学生だった当時、日本は高度経済成長期の真っ只中で、いわゆる公害が問題視されていた時期であった。応用化学科に在籍していた田島代表は、もともと興味があった環境物質の分析についてもっと深く知りたいと感じ、卒業後は理化学機器を取り扱う会社に入社。数々の研究所や臨床検査会社、検査センターの現場を相手に仕事をしていた。", "まだ手作業で対応するような臨床現場が多かった1980年代、検査技師の方の苦労を解消しようと、田島代表は海外製の理化学機器（臨床検査機器）自動化装置を日本人向けに特注機として取引先に納めていた。もちろん作業効率は格段に向上したが、定期的な保守メンテナンスが必要不可欠だった。 そこで田島代表が知人に依頼し、納品した理化学機器の保守メンテナンスを目的として、1985年7月17日に設立した会社がPSSだった。"], "imgs": ["assets/photos/post-52_b1.jpg"]}, {"h": "コロナ禍の世界各地に普及した松戸のテクノロジー", "ps": ["1995年、PSSは微量分析技術として、マイクロ磁性ビーズによる目的物質を自在に分離、そして抽出できるマグトレーション技術（Magtration® Technology）を世界で初めて開発、国内外各国で特許を取得した。", "そしてこのマグトレーション技術によって、様々な変化を間近で見ることができたのだ、と田島代表は語る。", "最初の大きな変化は、遺伝子・DNA情報の活用技術分野において劇的におこった。その分野には極微量のDNAを数百万倍にも増幅できる技術（PCR）が不可欠だが、そのPCR技術を所有するヨーロッパ大手の会社に、PSSが開発したマグトレーション技術を持ち込んだところ、彼らは一目見ただけで採用を決定したのだ。その後もトントン拍子に話は進み、なんと欧州にある複数の有力会社とOEM契約を結ぶことに。現在では世界規模で影響力を持つ事業となっている。"], "imgs": ["assets/photos/post-52_b2.jpg"]}, {"h": "高分子から細胞へ。PSSの新たなる挑戦", "ps": ["そして今、PSSは次の革命に順応しようとしている。 それはがんや免疫等の細胞の世界だ。", "今までPSSが研究開発の対象だったのは、DNAやたんぱく質といった高分子だった。これからは、それらを内包した、あるいは作りだしている生体物質そのもの、つまり細胞を対象とした分析分野にも対応していきたい考えだ。", "世界の研究者、医療関係者の方々が苦心しながら取り組んでいる色々な手法やテーマが、PSSの目の前に並んでいる。今後、医療業界や学会にPSSがまた革命を起こすかもしれない。"], "imgs": []}]},
{"no": 5, "corp": "いすみ鉄道株式会社", "name": "古竹 孝一", "role": "代表取締役", "star": 3, "head": "房総半島の架け橋を支えている若き代表", "prof": "1971年7月27日香川県生まれ。1997年、日本大学大学院理工学研究科交通土木工学専攻（現・交通システム工学専攻）修士課程修了。大学院修了後に香川へ戻り、高松市の日新グループのために尽力。さまざまな経験を経て、人を辞めさせない会社づくりをモットーに、35歳で日新グループ全体の社長に就任。40歳で取締役会長。2018年11月に社長公募により、いすみ鉄道株式会社の代表取締役に就任。", "url": "https://isumirail.co.jp/", "photo": "assets/photos/post-58_t.jpg", "hero": "assets/photos/post-58_h.jpg", "secs": [{"h": "房総半島の架け橋を支えている若き代表", "ps": ["千葉県大多喜町、そしていすみ市の各地域をつなげているいすみ鉄道株式会社は、第三セクター鉄道会社であり、黄色い車体とその景色が広く知られている。毎年3月中旬になると沿線に菜の花が咲き誇り、菜の花の中を1両の列車が颯爽と走る、のどかな風景を見ることができる。", "ここに、一般公募を通じて社長に就任した人物がいる。古竹孝一氏だ。古竹代表は、香川県高松市を拠点に事業を展開している日新グループの会長を務めている。", "「自分の47歳の誕生日にいすみ鉄道の社長公募がありまして、当時大学で習っていたことをもう一度ちゃんと生かしたいと思い、アタックしたんです。」朗らかにそう語る古竹代表。"], "imgs": ["assets/photos/post-58_b1.jpg"]}, {"h": "国鉄から受け継いだ地域への想い", "ps": ["いすみ鉄道株式会社が使用している路線は、実は元々日本国有鉄道（現JR）が房総半島を横断する路線をつくるためにできたものである。内房の木更津と外房の大原を繋ぐ路線として、当時は木原線という名前で開業した。", "しかし今日に至るまで両方の線路は繋がることはなかった。内房側はJR東日本の久留里線として運用され、外房側は収益性が芳しくなかったため、自治体などが補助金を出して運行するいわゆる第三セクターとして株式会社化されることとなった。これがいすみ鉄道株式会社の創業の発端である。", "株式会社ではあるものの、第三セクター鉄道という特殊な立ち位置のいすみ鉄道株式会社・地域自治体との連携を大切にしつつ公共交通機関の役割を担うことをモットーに、日々運営に励んでいるという。"], "imgs": ["assets/photos/post-58_b2.jpg"]}, {"h": "小規模だからこそ実践できる型破りな発想とは", "ps": ["実は全国に数ある第三セクター鉄道やローカル線の中でも、いすみ鉄道株式会社は比較的都心に近いという特徴がある。東京駅から特急や高速バスに乗ることで2時間程で到着できるという立地の良さ、小湊鐵道という別の鉄道会社に乗り換えることで房総半島を横断できる鉄道として乗り通しの需要も多く、週末になると多くのお客様がやってくる。", "古竹代表が代表に就任してからは、規模の小さい会社であることを逆手にとり「全国いすみ鉄道支店長制度」や「い鉄クリエイター」、アイドルの写真集の撮影場所の提供など、型にとらわれない地域に根ざした施策を積極的に行いつつ、若手社員の意見やアイデアを積極的に取り入れているという。"], "imgs": ["assets/photos/post-58_b3.jpg"]}, {"h": "これからのいすみ鉄道", "ps": ["2022年には18歳の新入社員が26年ぶりに入社し、翌年、翌々年も新入社員を次々と獲得。古竹代表率いるチームいすみ鉄道は順調な躍進を見せている。 地域交通の生き残りを図るべく、いすみ鉄道株式会社はこれからも走り続ける。"], "imgs": []}]},
{"no": 6, "corp": "チーズ工房【千】sen", "name": "柴田 千代", "role": "", "star": 2, "head": "0.01gにこだわるチーズ工房", "prof": "千葉県富里市出身。18歳でチーズ職人を志し、東京農業大学卒業後は北海道とフランスでの修行。2014年に大多喜町で築120年の古民家を改装しチーズ工房【千】senを開業。2017年11月1日には、国内のチーズ生産者にとって最高賞にあたる農林水産大臣賞を受賞、史上最速、女性初、関東初の受賞となる。国内産の乳酸菌酵母を利用した「産土（うぶすな）」がWorld Cheese Award 2019-20 銅賞受賞。2022年フランス本部があるギルド協会よりギャルド・エ・ジュレ Garde et Juréを叙任。日本酒で表面を磨いたウォッシュチーズ「鼓動」がJapan Cheese Awards 2024 で最優秀部門賞受賞、Would Cheese Award 2024 GOLD（世界1位）の快挙を達成。", "url": "https://fromage-sen.com/", "photo": "assets/photos/post-3882_t.jpg", "hero": "assets/photos/post-3882_h.jpg", "secs": [{"h": "0.01gにこだわるチーズ工房", "ps": ["千葉県夷隅郡大多喜町。山林に囲まれた静かな集落に、築120年の古民家を改装したチーズ工房がある。チーズ工房【千】sen。2014年に開業したこの小さな工房は、日本独自の乳酸菌と酵母を駆使し、機械に頼らない手仕事でクラフトチーズを生み出している。", "主力商品は「竹炭」「鼓動」「産土（うぶすな）」といった個性的な名前のチーズたち。地元の素材にこだわり、0.01g単位で調合された微生物が織りなす味わいは、国内外のコンクールで次々と賞を獲得してきた。", "普段はオンラインショップの予約販売が中心。月1回の直売日やイベントでは、予約は不要なものの限定数のみ販売されるそのチーズは、その希少性もさることながら、チーズそのものから溢れ出るこだわりが、熱心なファンを惹きつけてやまない。"], "imgs": ["assets/photos/post-3882_b1.jpg"]}, {"h": "給与ゼロから世界3位へ", "ps": ["千葉県富里市出身の柴田。兄弟4人の3人目として育ってきた。幼い頃から食べることが大好きだった彼女にとって、食卓は家族の絆を結ぶ聖域だった。母の手作り味噌や厳選された醤油に囲まれた生活は、自然の恵みを尊ぶ価値観を養うきっかけとなった。", "18歳、高校卒業を控えた進路選択の岐路で、彼女は決意する。「食べることは人間が絶対にやめられない行為だ。なら、食で人を良くする職業に就こう…そう思うようになりました」。進学先の東京農業大学オホーツクキャンパスでは乳製品（チーズ製造）を専門に学び、卒業論文では『カマンベールの熟成チーズについて』をテーマに研究を行った。大学卒業後は北海道内の酪農家のチーズ工房で汗を流し、チーズ作りの基礎を叩き込んだ。", "さらに27歳でフランスへ渡り、バックパックを背負って農家を巡る1年間の修行旅へ。カマンベールへの憧れを胸に、4軒のチーズ農家で技術を吸収した。だが、そこで彼女が見たのは、日本のチーズ文化の未熟さだった。「日本でチーズを作ってる人は本当にいるの？」とフランス人に呆れ顔で問われ、悔しさと使命感が燃え上がる。そして帰国後、10年ぶりに故郷へ戻った彼女を待っていたのは、団地とベッドタウンに変わり果てた富里の姿。畑や栗林が消え、大自然から遠ざかった故郷に愕然としつつ、彼女は日本の美しさを、チーズを通して世界に届けたいと思うようになる。"], "imgs": ["assets/photos/post-3882_b2.jpg"]}, {"h": "私しか作れないものを作る", "ps": ["チーズ工房千の強みは、愛の詰まった手仕事とその道程にある。主力商品は18種類に及び、「竹炭」は農林水産大臣賞、「鼓動」は2024年の日本チーズアワード金賞とワールドチーズアワード金賞、「産土（うぶすな）」は2019年の世界銅賞を獲得。地元の乳酸菌や九十九里の塩、350年続く酒蔵の日本酒で洗ったチーズまで、千葉のテロワール（風土）を凝縮した作品群は、他では味わえない独自性を持つ。副産物のホエイを使ったドレッシングも農福連携で開発しており、廃棄ゼロを目指す持続可能性への取り組みも評価が高い。", "量産ではなく品質と物語に徹するのが、彼女のこだわり。500円のモッツァレラを1000個売るより、5万円のチーズを10個売る道を選ぶ。「私しか作れないものを作り、提供するのが今のベスト」と言い切る彼女は、家庭の食卓を彩る手に取りやすい商品と、大使館や富裕層向けに作る特別なチーズの両方で、それぞれの戦略を描く。", "工房の扉が開くのは、月に1回だけだ。日常の喧騒から離れた静かな山林に、ひっそりと客が集う。普段はオンラインでしか買えないチーズを直接手にするため、訪れる者たちはその日を待ち焦がれる。機械では再現できない手仕事の美しさを、千葉の風土と共に世界に放っている。"], "imgs": ["assets/photos/post-3882_b3.jpg"]}, {"h": "自分自身を信じる覚悟", "ps": ["柴田千代の事業は、単なるチーズ作りではない。日本の手仕事文化を残し、まさに千葉の酪農を次世代に繋ぐ使命といえるだろう。後継者不足や輸入飼料の高騰で酪農が衰退するこの時代、飼料を地産地消で賄う仕組みを築く地域の酪農家と連携し、最終ランナーとして、微生物研究者、酪農家、酒蔵の職人たちのバトンを握り、世界に勝つことで文化を守ると考える柴田は、10年後に千葉からオーガニックな村を作りたいと語る。", "「自分の『好き』を見つけて、一心不乱に信じて進むのが、怖いけど一番幸せなことだと思います。時間がなくても、お金がなくても、動けば道は開ける。私だって研究所で働きながら工房を始めたわけですからね。人の3倍努力する意志さえあれば、その人の人生がすごい旅になるのは間違いないです」", "神頼みではなく、自分自身を信じる覚悟。20代の、決して資金的には恵まれていなかった夢追い人が今、2024年には世界1位のチーズ職人になった事実が、大多喜町にある。"], "imgs": ["assets/photos/post-3882_b4.jpg"]}]},
{"no": 7, "corp": "千葉大学医学部附属病院", "name": "生坂 政臣", "role": "", "star": 2, "head": "総合診療科の先駆者", "prof": "1958年福岡県生まれ。鳥取大学医学部卒業後、米国アイオワ大学で家庭医療学を修め、米国医師免許および家庭医療学専門医取得。2003年、千葉大学医学部附属病院に総合診療科を創設、同科教授に就任。2024年、千葉大学名誉教授に就任。総合診療の普及や診断精度向上のため教育活動にも尽力している。", "url": "https://www.m.chiba-u.ac.jp/dept/soshin/", "photo": "assets/photos/post-3870_t.jpg", "hero": "assets/photos/post-3870_h.jpg", "secs": [{"h": "総合診療科の先駆者", "ps": ["米国に家庭医と呼ばれる専門医がいる。単なる町医者を超えて、家庭全体を診る医者だ。小さな子どもの発熱から、祖父母の慢性病のケア、さらには心の悩みまで、あらゆる世代の健康を守る。医療の専門分化が進んだ今、なんでも気軽に相談できる存在というのは頼もしい。家庭医は地域のコミュニティに深く根ざしており、患者と医師は、時に数十年にわたる付き合いとなることもあるのだとか。", "そんな、地域住民の健康のために医療サービスを幅広く提供している家庭医。日本では総合診療医と称して、普及が始まっている。なかでも総合診療科のメッカとして位置づけられている千葉で、総合診療科の第一人者として今もなお第一線で活躍しているのが、千葉大学名誉教授の生坂政臣先生だ。", "彼の物語は、平凡な成功譚などではない。むしろ、それは必然的な運命と偶然が交錯する、一種の鮮烈な小説のような人生といえるかもしれない。"], "imgs": ["assets/photos/post-3870_b1.jpg"]}, {"h": "わずかな問診で得た感動", "ps": ["福岡県で生まれ育ち、鳥取大学医学部に進学した生坂は、入学早々クロスカントリースキー部に誘われる。「スキー部だから冬はたくさん遊べるじゃないか、と安易に考えていました。それが入部してみると、みんなスキー板で、滑るんじゃなくて登るんですよ。まるで自衛隊みたいで…騙された！って思いました（笑）」と朗らかに語る生坂。知らないうちに過酷なスポーツの世界に引き込まれたのだという。", "在学中には「医者になる前に、医学以外の道にも触れておきたい」と留学を決意。米国アリゾナの大学で宗教学を学び、バプテスト教会に通う日々を送っていた。そこで生坂は医療の本質に触れる事件を経験する。", "実は生坂には、学生時代から悩まされていた謎の顎の痛みがあった。もちろん日本でも診察を行ったものの「ストレスのせいではないか」と片付けられてしまい、結局解決策がないまま、発症から2年もの間、苦しんでいた。"], "imgs": ["assets/photos/post-3870_b2.jpg"]}, {"h": "診療科目のカベを壊せ", "ps": ["2003年、千葉大学医学部附属病院に総合診療科を創設した生坂。そのとき、国内にはいわゆる総合診療医と呼べる医師が非常に少なかった。よって、原因臓器の特定が難しく、総合的に診察する必要があると考えられる患者であっても、適切な診断や治療が受けにくい状況だった。これは日本の診療科目が臓器別で専門的に細分化されてきたという、言うなれば医学の進歩の副作用といえる。", "その問題に気づいた生坂はいち早く「問診」というシンプルだが難しい技術に注目し、それを徹底的に追求。卓越した問診スキルを総合診療領域で普及することに務めたことで、より多くの患者を救う道を切り拓いていったのである。", "また、NHKの医療番組制作にも関与。診療科目の垣根を越えて、症状から病気の本質を見抜く問診の過程を一般視聴者に伝えることで、総合診療という新しい診療スタイルの重要性を広く知らしめた。その勢いはとてつもなかった。番組は当初BS放送で始まったものの、視聴者の圧倒的な反響を受けて地上波での放送に格上げされ、ついにはシリーズ化されるほどの影響力を持つに至った。生坂が手掛けたこの番組は、総合診療という言葉を日本中に浸透させるきっかけとなったのである。"], "imgs": ["assets/photos/post-3870_b3.jpg"]}, {"h": "日々向上", "ps": ["生坂の口癖は「日々向上」だ。昨日よりも今日、今日よりも明日、自分自身が向上し続けること。その小さな積み重ねがやがて大きな夢を現実にすると信じている。そして今、総合診療医の全国展開という巨大な課題に挑み続けている。小さな進歩を重ねることが、結局は大きな目標に到達するための最良の道だと、自身の体験を通して確信しているのだ。これは単なる激励ではなく、生坂自身が実際に歩んできたリアルな人生哲学といえよう。", "大人になるにつれて忘れてしまいがちな、小さな成長への喜び。しかし、毎日ささやかな進歩を感じることで、人生はより、確実に豊かになる。日々向上、とは特別な何かを成し遂げることではなく、日常のなかで少しだけ前に進もうとする、そんな姿勢なのだと、生坂を通じてひしひしと感じるのだ。", "結局のところ、と生坂は続ける。「人生は予測不可能なものだと思うんですよね。ただその予測不可能性を受け入れ、日々自らを謙虚に更新し続けることによって、想像もしていなかった新しい景色が現れます。私はそれが楽しくて仕方がないんです」。"], "imgs": ["assets/photos/post-3870_b4.jpg"]}]},
{"no": 8, "corp": "IBM BIG BLUE", "name": "松本 宗樹", "role": "", "star": 2, "head": "幕張の青い鎧球軍団", "prof": "1976年にIBM社内の同好会として創設。東日本実業団リーグでの経験を経て2001年にXリーグ1部へ昇格する。日本IBMスポーツ株式会社の支援のもと、千葉市美浜区を拠点とし、伝統と革新を両立するクラブチームとして運営される。現在はXリーグ1部：X1 Superに所属し、ライスボウル優勝に向け活動中。", "url": "http://www.bigblue-football.com/", "photo": "assets/photos/ibm-big-blue_t.jpg", "hero": "assets/photos/ibm-big-blue_h.jpg", "secs": [{"h": "幕張の青い鎧球軍団", "ps": ["クォーターバックが放つロングパス。守備の隙を突いて走り抜けるワイドレシーバー。絶妙なタイミングでボールをキャッチすれば、シナリオが用意されていたかのようにスタジアムが熱狂に包まれる。その背後ではラインマンたちが重厚な肉体をぶつけ合い、目に見えない戦いを繰り広げる。まるで協奏曲のような連携プレーで、チーム一体となって勝利を目指す。アメリカンフットボールと呼ばれるその競技には、剛と柔が交差するドラマがある。", "幕張新都心エリアに、青く輝くアメリカンフットボールチームがある。日本IBMグループが運営する、約50年の歴史をもつIBM BIG BLUEは現在、日本の最上位に位置する社会人リーグの”Xリーグ”1部：X1 Superに所属している強豪だ。"], "imgs": ["assets/photos/ibm-big-blue_b1.jpg"]}, {"h": "強豪たる所以", "ps": ["BIG BLUEは1976年、日本IBM社内のアメフト経験者たちによって、同好会として創部されたのが始まりだ。1996年のリーグ再編によりXリーグが発足し、BIG BLUEは2部リーグからスタート。昇格のための決定的な一戦が起こったのは2001年、全選手が一丸となって、1点差の優勢を死守して勝利。創部から四半世紀を経てついに1部昇格を決めた瞬間であった。", "そして2010年には元Xリーグの名ラインバッカー・山田晋三がヘッドコーチに就任。春の公式戦パールボウルで2016年に初優勝したのを機に、名実ともに東日本の強豪として認知されるようになる。", "2019年には日本IBMの100％出資の子会社として日本IBMスポーツ株式会社が設立され、チーム運営力強化を専門に担わせる体制が構築された。翌年には本拠地を千葉市美浜区へ移転し、BIG BLUEはさらなる勝利を見据えて鍛錬を重ねている。"], "imgs": ["assets/photos/ibm-big-blue_b2.jpg"]}, {"h": "「ハイブリッド型」チーム編成", "ps": ["BIG BLUEに、影の立役者がいる。日本IBMスポーツ株式会社の代表取締役社長、松本宗樹だ。", "学生時代からアメリカンフットボールに情熱を燃やしていた松本は、日本IBM入社と同時にBIG BLUEのメンバーとして芝生に立った。以後9年間にわたり、BIG BLUEの選手として副将、さらにはキャプテンとしてチームを牽引。選手として戦場を駆け抜ける日々は、まさに己との戦いだった。", "その後、引退を迎えた彼は、さらなる高みを目指して大学院でマネジメントを学ぶという選択をする。そしてチームのゼネラルマネージャーを約10年間務め、現場と経営の両面からチームを成長させる重要な役割を果たす。2024年に日本IBMスポーツ株式会社の代表として再び経営に戻り、現在は日本IBM本体の人事労務部長を務める傍ら、BIG BLUEの経営戦略や地域貢献活動を指揮している。"], "imgs": ["assets/photos/ibm-big-blue_b3.jpg"]}, {"h": "挑戦できる機会は限られている", "ps": ["デジタル技術を駆使した戦術分析、選手のパフォーマンス管理、そして地域社会との一体感をさらに深化させることで、BIG BLUEは未来のスポーツマネジメントの新たなスタンダードを打ち立てようとしている。そして、競技人口が減少傾向にあるアメリカンフットボールの課題を直視しつつも、その魅力をどう伝えるかを真摯に、つねに模索している。", "松本は語る。「人生は有限です。挑戦できる機会は、実は限られている。だから、挑戦するか迷った時こそ、勇気をもって飛び込むという選択をしていただきたいと思っています。自信を持って挑戦すれば意外と通用することが多いですし、失敗したとしても糧にならないわけがない。そして、自分の枠を超えないといいプレーなんてできませんから」", "松本 宗樹（まつもと むねき）慶應義塾大学卒。1998年、日本IBM株式会社に入社。IBM BIG BLUEの選手として9年間活動し、うち副将およびキャプテンを務める。選手引退後は大学院でマネジメントを学び、チームのGMを約10年間担当。2019年の日本IBMスポーツ株式会社設立後、2024年6月から代表取締役社長としてチーム経営に復帰。現在は日本IBM本体で人事労務部長として活躍しつつ、IBM BIG BLUEの経営戦略、財政基盤の強化、地域貢献活動などを統括。"], "imgs": ["assets/photos/ibm-big-blue_b4.jpg"]}]},
{"no": 9, "corp": "株式会社ベストマッチ", "name": "玉井 幸太郎", "role": "代表取締役", "star": 3, "head": "千葉県の雇用創出に尽力し続ける人材企業", "prof": "1988年、新卒で株式会社リクルートへ入社。一貫して人材採用領域を担当し、2004年に当時の上司と共に独立。株式会社ベストマッチを立ち上げ、取締役営業部長を経て2022年4月に代表取締役へ就任。現在に至る。", "url": "https://www.bestmatch.co.jp/", "photo": "assets/photos/post-61_t.jpg", "hero": "assets/photos/post-61_h.jpg", "secs": [{"h": "千葉県の雇用創出に尽力し続ける人材企業", "ps": ["株式会社ベストマッチは、千葉県に特化して人材採用の総合支援サービスを展開している企業だ。県内の多種多様な業界で約5000社のクライアントを持つほか、グループ会社へ移管した人材紹介事業では年間約8000名の就職・転職希望者と接点を持つなど、企業と求職者の双方にとって文字通りベストなマッチングを創造し続けている。", "「千葉県は有効求人倍率が全国47都道府県中46位（厚生労働省2024年3月公表）という立ち位置にいます。数字だけ見れば人の流動が少ないマーケットだと思われがちです。しかし、“雇用創出”という視点で見れば逆に全国屈指の伸びしろを持つマーケットと言えます。そこにこそ、私たちの存在価値があるのです」と熱く語るのは、代表の玉井幸太郎氏だ。", "今日に至るまで人材採用領域一筋の道を歩み続けている玉井代表に、業界人として思う千葉県のマーケットの魅力や今後の展望について話を聞いてみた。"], "imgs": ["assets/photos/post-61_b1.jpg"]}, {"h": "クライアントの採用成功に、とことん伴走", "ps": ["2004年の立ち上げ当初から”千葉を元気に！！”というスローガンを掲げている株式会社ベストマッチは、千葉県内の企業や店舗と求職者のベストなマッチングを追求していく中で、採用成功に向けた伴走力を磨いてきたという。リクルート出身で同社の求人メディアを取り扱うパートナー企業としての実績を積み重ねてきたこの21年間、玉井代表はどのような想いを持ち続けてきたのだろうか。", "「”採用成功”とひとくちに言っても、単に求人メディアへの出稿を取り扱うだけでは成し得ません。クライアントである企業や店舗の採用課題を見つけ、どのポジションや役割に就く人材が何名必要なのかを明確にすることから私たちのサービスは始まります。さらに応募があった後の受付や面接、入社後の育成など”定着”までを採用成功と置くならば、私たちはその全プロセスにおいて支援できる企業であるべきだと考えています。」", "設立から21周年を迎えた2025年現在、株式会社ベストマッチは取り扱う求人メディアの拡充だけでなく、市場調査からホームページやパンフレットなどの採用ツール・コンテンツ制作、応募受付や面接の代行といった採用実務をはじめ幅広いサービスを展開している。すべては”採用成功”がもたらす雇用創出を通じて、クライアントにとことん伴走していく同社のスタンスを具現化させたものだ。その想いの原点は、新卒で株式会社リクルートへ入社した1年目にあるという。"], "imgs": ["assets/photos/post-61_b2.jpg"]}, {"h": "“スキルの抽象化”でAI全盛の時代に挑む", "ps": ["現在も千葉全域の人材業界を牽引している株式会社ベストマッチ。すでに同県の人材マーケットにおいて約11%のシェアを獲得しているが、あえて営業エリアを拡げずに千葉県内でのシェア拡大に尽力し続けるという。今後の展望として、人材業界をどう捉えているのだろうか。", "「近年ではAIの技術革新が急速に進み、企業と求職者をスキルでマッチングさせるサービスがどんどん磨かれています。いわゆるジョブ型雇用には最適である一方、人の潜在的なスキルや志向にフォーカスした異業種・異職種への転職支援においては、長年にわたり培ってきた弊社の強みを発揮できると考えています。」", "例えば株式会社ベストマッチのグループ会社に分社・移管した人材紹介事業ではこんな話がある。"], "imgs": ["assets/photos/post-61_b3.jpeg"]}, {"h": "採用成功のトータルコンサルティング企業として", "ps": ["千葉県内に特化して存在価値を発揮する中で、株式会社ベストマッチは採用のトータルコンサルティング企業として市場専有率のさらなる向上に挑んでいる。営業や制作のほか営業サポート、広告運用、マーケティング、自社運営のコールセンターなどに従事するスタッフはグループ合計で100名を超えた。直近2024年度においても「Indeedプラチナムパートナー」に認定されるなど、成長著しい同社が牽引する千葉県の雇用創出には大きな期待が寄せられている。", "＜参考リンク＞ ・ 株式会社ベストマッチ ・ 株式会社ベストマッチキャリア（グループ会社） ・ 採用お役立ち情報サイト「ベストレ」（自社運営）"], "imgs": []}]},
{"no": 10, "corp": "有限会社幸和商事", "name": "大吉 誠司", "role": "代表取締役", "star": 3, "head": "長生郡から世界へ。バイオガスのトップランナーとは", "prof": "1991年、有限会社幸和商事に入社。2020年、同社執行役員就任、長野市バイオマスタウン構想協議会会員就任。 2021年、信州大学『信州そるがむで地域を元気にする会』理事就任。2023年、同社代表取締役専務就任。", "url": "http://kowashouji.com", "photo": "assets/photos/post-31_t.jpg", "hero": "assets/photos/post-31_h.jpg", "secs": [{"h": "長生郡から世界へ。バイオガスのトップランナーとは", "ps": ["有限会社幸和商事は千葉県長生郡白子町にある会社だ。バイオガス発電装置の企画開発・サーキュラーエコノミーシステム（バイオガス装置+陸上養殖+植物栽培）の企画開発から、再生エネルギー関連施設の運営に関するコンサルタント業務、また自社工場にてFRP（繊維強化プラスチック）製タンクの製造や各製造工場などでのメンテナンス工事を行なっている。", "会社本体は10名と少人数ではあるものの、協力会社の力を借りながら小回りをきかせ、ときには大型の案件にも対応している。FRP製品製造には30年以上も携わっており、製造した製品は世界各国で使用されている。", "「自社工場でプラスチックと鉄やステンレス素材の製品を一気通貫で製造出来るのが弊社の強みです。バイオガス・サーキュラーエコノミー分野でも自社設計から製造、設置工事、運営、コンサルタント業務まで全て行うことが可能なんです。」そう語るのは、代表取締役専務の大吉充氏だ。"], "imgs": ["assets/photos/post-31_b1.jpeg"]}, {"h": "たどり着いた先は『環境・エネルギー・食』", "ps": ["プラスチック材料商社に勤めていた大吉専務の父が、当時急速に普及していたFRP（繊維強化プラスチック）に興味を持ち、材料商社として独立したのが幸和商事の始まりだ。FRPは薬品に非常に強く、さらに錆びない・軽い素材として知られており、工業分野で今でも必要不可欠なマテリアルとして重宝されている。その後、本来ものづくりの好きな父が自分で製造を開始したのをきっかけに手伝うような形で大吉専務は幸和商事に入社した。", "しかし当時はバブルが崩壊した真っ只中で経営もとても苦しい状態が続いていた。そこで新たな分野への挑戦を決意し、何が将来的に伸びる分野なのか、人に喜ばれる仕事とは何なのか、と様々な分野を調べたという。", "「ようやくたどり着いたのは、『環境・エネルギー・食』という3文字でした。私の子供の頃はしょっちゅう夏になると光化学スモッグ警報が発令されていた時代で、空がいつもよどんでいたのを覚えています。これを思い出すたびに高村光太郎の『智恵子抄のあどけない話』を思い出したものでした。美しい空を取り戻すには環境に優しいクリーンなエネルギーでなければいけない、そう考えたときにバイオマスというキーワードにたどり着きました。」と当時を思い返しながら語る大吉専務。"], "imgs": ["assets/photos/post-31_b2.jpg", "assets/photos/post-31_b3.jpg"]}, {"h": "よりたくさんの方に寄り添える会社に", "ps": ["現在、バイオガス発電装置やサーキュラーエコノミーシステムは今後の事業展開において最も大切な事業に位置づけていると語る大吉専務。まだまだ全国では成功例の少ないバイオガス発電だが、12年前から社内で様々な実験を通じて取得したそのデータを元に、数多くの企業や大学へアドバイスをおこなっている。", "また今後はバイオガス発電を中心としたサスティナブルな街作りへの参画を検討中だ。耕作放棄地や荒れた山に養殖場を作り、バイオガスプラントから発生した消化液（発酵残渣）を堆肥とし田畑で米や野菜、牧草を育て、畜産をおこなう。排出された糞尿や観光に訪れたお客様の食残などはバイオガス発電の原料となる。棄てる物がないサスティナブルな環境を作りそこに働く場を提供し、過疎化問題も解決し、観光の名所となれば外からの人の流れが増え、活気のある街が出来上がる。行政やファンドの方々と連携をとりこのような街を沢山作っていきたいと考えているという。", "『環境・エネルギー・食』というキーワードを中心にそれに関係する分野へ関わっていくことが重要だと語る大吉専務。再生可能エネルギーを利用できる装置の開発やペロブスカイト太陽電池と全個体バッテリーを合致させた施設の開発、陸上養殖技術の向上を目指し、安心した生活を送れる手助けの出来る企業を目指していきたいという。"], "imgs": ["assets/photos/post-31_b4.jpg"]}]},
{"no": 11, "corp": "株式会社マザープラネット", "name": "藪本 敦弘", "role": "", "star": 2, "head": "地域と交わりながら、子育て環境をつくる", "prof": "1977年、北九州市生まれ。神戸大学を卒業後、システムエンジニア、法人営業、新規事業開発などを経験。2009年にはぐるなびの事業戦略部門に在籍。2011年、株式会社マザープラネットを創業し、病児保育「オハナ☆キッズケア」を皮切りに、認可保育園や学童を開設し、地域密着の子育て環境を構築。保育士資格を持ち、現在はグループ経営および後継者育成に注力している。", "url": "https://motherplanet.co.jp/", "photo": "assets/photos/post-3807_t.jpg", "hero": "assets/photos/post-3807_h.jpg", "secs": [{"h": "地域と交わりながら、子育て環境をつくる", "ps": ["千葉県流山市。マザープラネットは、「地域深化」と「交わる」を旗印に掲げ、認可保育・病児保育・放課後児童健全育成・コミュニティ創出・メディア事業などを幅広く展開する、子育て環境創出企業である。", "藪本は、事業を拡大しながらも「地域に根ざすこと」に軸足を置き続けてきた。震災を契機に強く芽生えた「家族のそばで働きたい」という原体験が、その根底にあるという。", "一見すると穏やかな語り口の持ち主だが、その内には強い信念と熱量を秘めている。地域の子どもたちを見つめる視線は、常にまっすぐだ。"], "imgs": ["assets/photos/post-3807_b1.jpg"]}, {"h": "保育に携わる人々に寄り添う決意", "ps": ["彼の経歴は波乱に富んでいる。中学受験を経て進学した学力至上主義を掲げる中高一貫校の校風に違和感を抱き、中学3年時に家出。ホームレス同然の生活を送った時期もあったという。その後復学し、最終的には高校を中退したものの猛勉強の末、神戸大学に合格した。 しかし当時は就職氷河期。就職活動は厳しいものだったが、「社会に期待しすぎず、自分でなんとかする力が身についた」と振り返る。卒業後、IT企業にてシステムエンジニアや法人営業、新規事業の立ち上げを経験した藪本は、次第に経営という舞台に目を向けるようになる。", "そんななか2011年3月11日。藪本は都内で東日本大震災に遭遇した。家族の無事が確認できたのは、地震が発生してから数時間経ってからのことだった。安堵とともに湧き上がった「地元回帰」の想いから、藪本は「地元で起業する」という道へと突き動かされることとなった。", "もともと起業志向があり経営大学院でMBAの取得を目指していた。そうした状況での起業への想いから、昼は会社員、夜は経営大学院の学生、そして深夜には起業人として自社の事務所で起業準備に明け暮れる日々を、4か月以上にわたって続けた。終電後の柏駅で夜明けまで資料を作り、朝を迎えてオフィスへ向かう…当時の睡眠時間は人生で2番目に短かったという。心の奥底を支えたのは「この街の子どもたちに安心できる環境を創りたい」という揺るがぬ信念だった​​。"], "imgs": ["assets/photos/post-3807_b2.jpg"]}, {"h": "地域に必要とされる存在を目指して", "ps": ["現在マザープラネットは、流山市・柏市を中心に、子育てに関する支援を包括的に提供している。その最大の強みは「病児保育」という現代に必要なインフラを自ら創出し、その経験を通じて見えてくる地域ニーズを事業に反映している点にある​​。", "地域の子育てとその多様性に寄り添い、未来を育む。子どもは明日へ続く希望であり、社会の礎だ。多様な家族と地域の人々が交わり、「子育てが楽しい」と語り合える街をつくる…それがマザープラネットの流儀だと藪本は言う。異なる想いと生き方を尊重し、子どもから大人まですべての人がイキイキと暮らせる幸せな街を東葛エリアに描き続けている。"], "imgs": ["assets/photos/post-3807_b3.jpg"]}, {"h": "地域に果たすべき役割", "ps": ["藪本は2030年を目途に、グループ経営体制によって「地域深化」を図れる体勢にするつもりだ。そのために、まずはグループ社数を約10社程度まで増やし、売上数十億円規模の企業グループへ育て上げるというビジョンを描き、その実現に向けて日々社内研修やリーダー育成を推進している​​。最終目標は「圧倒的地域No.1」。60歳での引退を見据え、残りの時間を後継者育成に充てながら、次世代のリーダーへ舵を託す準備を進めているという。", "「我々は、行政から皆様の税金をいただいて事業を運営している面があります。だからこそ、地域社会からどんな役割で任されているのか、何のために仕事をしているのかを理解し、その責任をしっかりと果たす必要があります。", "どんな役割で任されているのか都度立ち返り、業務の意味を確認し、しっかりと遂行する。どこの会社や組織に属していても、その大切さは変わらないでしょう。特に若いうちから、それができるようになれば、必ず社会で必要不可欠な人材となりますし、何より自分の目標を自分で達成できる、そんな人間になれるはずです。」"], "imgs": ["assets/photos/post-3807_b4.jpg"]}]},
{"no": 12, "corp": "稲村工業株式会社", "name": "速水 雅之", "role": "代表取締役", "star": 3, "head": "千葉県民の暮らしの根底を創る会社", "prof": "1971年兵庫県西宮市生まれ。市川工業高校卒業後、1995年に稲村工業へ入社。現場監督として施工管理に従事し、2012年取締役就任。福利厚生改革など組織改善を進め、2024年に創業社長の後を受け代表取締役に就任。水道本管更新工事を中心に30年の実績を積み、社員と家族の満足度向上を経営方針に掲げる。現在も現場に立つ。 ​", "url": "https://inamura-k.co.jp/", "photo": "assets/photos/post-3782_t.jpg", "hero": "assets/photos/post-3782_h.jpg", "secs": [{"h": "千葉県民の暮らしの根底を創る会社", "ps": ["約10,000キロメートル。これは、千葉県内の地下に埋まっている水道管の総延長だ。アスファルトの下を、水道管が静かに軋みながら、今もなお横たわっている。東京の日本橋から市川市、船橋市を抜け、千葉県千葉市中央区まで至る、国道14号線。ヘッドライトがまだまばらな闇の中で、速水雅之は路面に立ち、耳を澄ませる。", "速水率いる稲村工業株式会社は、行政と二人三脚でこの見えない血管を更新し、街の新陳代謝を支える、まさに小さな臓器だ。従業員はわずか12名。だが、この12の鼓動が止まれば、千葉県民の暮らしのリズムもたちまち狂ってしまう。"], "imgs": ["assets/photos/post-3782_b1.jpg"]}, {"h": "福利厚生の真の目的", "ps": ["稲村工業は昭和51年の創業以来、千葉の地下で水が流れる道をつくり続けてきた。水道管の耐震化、水道本管の更新、下水道の改修…いずれも派手な看板を掲げる仕事ではない。しかし、たとえば震災で水が止まったとき、人々は初めてその名を探す。ライフラインとは文字どおり、人の生をつなぐ線であり、その継ぎ目を縫う手は、工場の旋盤よりも繊細で確かな感覚を要する。", "兵庫県西宮で生まれ育った速水は、24歳で会社に入った。入社理由は、たまたまだという。結婚を機に「ちゃんと稼げる仕事」を探し、掴んだ縁。上司にも恵まれ30年以上、彼は現場に身を投じ続けた。", "東日本大震災、液状化した浦安の街で、泥に膝まで埋まりながら、復旧工事に明け暮れた1ヶ月があった。バックホウの油の匂いとガス灯の明滅の中で、彼は「誰かに水を届けるために、自分は生きている」ことを骨に刻みつけた。 そして2024年春、代表取締役へ就任した。「働き方改革」も始まっていない平成の時代を知る男は、まず「社員を大事にする」ことに舵を切る。企業年金の導入、空気清浄機の設置、制服の刷新。細部は小さくても、そこに込める意図は大きい。「これらは、本人のためだけじゃないんです。彼らには、帰宅すると待っている家族がいます。家族の方にも 、 稲村工業と付き合って良かったと、心から思われたいので」"], "imgs": ["assets/photos/post-3782_b2.jpg"]}, {"h": "稲村工業式組織論", "ps": ["稲村工業の強みはシンプル。千葉県企業局発注の水道本管工事で30年の実績を積み、高いリピート率を誇る、安定受注。その実績を可能にしているのは、約10名というミニマム編成に秘めた柔軟性だ。", "速水は「完璧な監督」を求めない。2名、3名で現場を張り、それぞれの得意分野を細分化するのである。住民対応が巧みな者、どんな現場でも測量を任せられる者、PCで図面を操る者…それぞれの個性をパズルのように組み合わせ、プロジェクトを駆動させるのだ。", "ICTも導入した。クラウド図面共有と遠隔カメラで、深夜の現場でもデータはリアルタイムに本社へ届く。だが最新機器より重要なのは、路面を叩くドリルのリズムを耳で覚えた職人の勘だ、と彼は笑う。技術と感覚…硬質な鋼管と、水面のさざ波のようなチームワーク。その対比こそ、この会社の詩学であり、そして積み上げてきた速水の仕事観でもある。"], "imgs": ["assets/photos/post-3782_b3.jpg"]}, {"h": "自分らしく", "ps": ["目標を問われると、速水は少しの沈黙の後「まだ模索中です」と言った。けれど、その沈黙は逃避ではなく、真摯な空白に他ならない。安定した受注の上にあぐらをかくのではなく、社員一人ひとりの「自分らしく」を丹念にすくい上げ、会社という器の形をゆっくりと、しかし強固な意志を持って確実に変えていく。その、芯の太さが垣間見える。", "若者へのメッセージを、と求めると、彼は照れくさそうに笑ってこう結んだ。「自分らしく、そして何事にも前向きに歩いてみるのが大事だと思います。単に頑張ること自体はできますけど、それだと次第に疲れてきますから。私も、若い社員でもなるべく自分らしさを出せるような環境をつくるようにしています。自分らしさを出すことで積み上げた成果には、ひときわ光るものがありますね」", "都市の灯が落ち、夜が深くなるほど、地下を走る水音は澄む。稲村工業は、その透明な響きを聞き分ける耳を持っている。12人の小さな鼓動は、今日も千葉の地層をその手で震わせ、見えない未来へと脈打ち続ける。 ​"], "imgs": ["assets/photos/post-3782_b4.jpg"]}]},
{"no": 13, "corp": "株式会社武田設備", "name": "武田 儀幸", "role": "", "star": 3, "head": "日常に向き合い続ける会社", "prof": "千葉県九十九里町出身。中学卒業後父が営む水道設備業に入り、約20年間実務経験を積む。2022年に独立し個人事業を開始、2024年には株式会社武田設備を設立。現場経験に裏打ちされた技術力と挑戦的な経営姿勢で、地域に密着したリフォーム事業を展開している。", "url": "https://chiba-takeda-reform.com/", "photo": "assets/photos/post-3730_t.jpg", "hero": "assets/photos/post-3730_h.jpg", "secs": [{"h": "日常に向き合い続ける会社", "ps": ["日々の暮らしを支える住宅設備が、近年めざましく進化している。蛇口をひねれば即座に適温のお湯が流れ、調理器具は精密な温度管理をこなす。「便利」を超えて、「快適」が求められる時代になった。かつては「使えればよい」と考えられた設備も、今では使い勝手や心地よさが重視されるようになった。日常生活の質を向上させることは、日々の小さな満足感を積み重ねることに他ならない。", "株式会社武田設備の代表取締役、武田儀幸氏は、職人の世界で長年研ぎ澄まされた鋭敏な感性と、稀有な実行力を持つ人物である。その卓越された住宅設備の技術と、長年培ってきた信頼で、クライアントからの依頼は留まるところを知らない。"], "imgs": ["assets/photos/post-3730_b1.jpg"]}, {"h": "「やってみなければ何も変わらない」", "ps": ["2024年に千葉市中央区で株式会社武田設備を設立した武田は、もともと個人事業として活動していた水道設備業を法人化し、地域に密着した住宅リフォームをはじめ、店舗やガソリンスタンドの設備改修など、多彩な工事を幅広く手掛けている。武田氏が創業を決意した背景には、父のもとで水道設備工事に20年以上携わり、多くの現場を経験したことで培われた強い実務能力と深い業界知識がある。", "父親の会社は主にガソリンスタンドの新築工事を行っていたが、年間を通じて仕事が安定的に入るわけではなかった。その不安定さを目の当たりにした武田は、自らが中心となって安定的に仕事を生み出せる新たな分野を探求し始めた。そして、辿り着いたのが住宅リフォームという市場だった。地元密着型の事業であれば継続的な需要を見込めると判断した彼は、自ら未知の分野へと大胆に踏み込む決意を固めた。", "さらに独立直後、地元の信頼できる友人であり、長年の現場経験を持つ人物を工事主任として迎えることに成功。これにより、武田設備は設計から施工までを一括で提供する独自の施工体制を構築することができた。経験豊かな工事主任の力を借りて迅速かつ高品質なサービスを実現し、武田設備の強固な基盤構築と業績向上に大きく貢献した。"], "imgs": ["assets/photos/post-3730_b2.jpg"]}, {"h": "お客様の前で120％のものを", "ps": ["彼の経営する武田設備の特徴は、設計から施工まで自社で完結する一貫体制だ。通常、異なる専門職がそれぞれの仕事を分担して行う業界の中で、この体制を構築することは容易ではない。しかし、武田氏は友人であり現場経験豊富な工事主任を迎え入れ、難易度の高い業務を迅速かつ高品質に仕上げる独自の施工スタイルを確立した。この独自のアプローチが顧客や取引先から大きな信頼を得ている。", "武田氏には仕事への強いこだわりがある。顧客の視点に立ちつつ、「不可能を可能にする力」をモットーとしており、その姿勢は日々の仕事ぶりに明確に現れる。工事中に不安を感じる顧客の心情を察知し、可能な限り120％の完成度を目指すことを常に従業員にも伝えている。彼は顧客とのコミュニケーションを何よりも重視し、それが大きなトラブルを未然に防ぐ鍵だと考えている。", "また、武田は言う。「独立して増えたあぶく銭で失敗してきた人をたくさん見てきました。私も独立したばかりです。ただ、私は従業員を使用している立場じゃないですか。ということは、従業員の家族も背負っているんです。だから彼らにはお客様の前で120％のものを提供できるように心がけてもらいつつ、頑張った見返りをちゃんと渡せるようにしております」"], "imgs": ["assets/photos/post-3730_b3.jpg"]}, {"h": "目指す大規模プロジェクト", "ps": ["現在、武田設備はさらなる飛躍を目指して資格取得を促進し、施工範囲の拡大を進めている。将来的には元請けとして大規模なプロジェクトを直接請け負う体制を目指し、会社の規模を3年以内に従業員10名規模へと拡充するビジョンを掲げている。", "武田儀幸氏という人物の核心を描くとすれば、「信頼」と「挑戦」の二語に集約されるだろう。彼は、幼少期から周囲の人々に慕われて育ち、人々の信頼を力に変えてきた。困難に直面したときに逃げずに立ち向かい、失敗を恐れず前に進む彼の生き方は、多くの人々にとって模範となる。武田設備が今後どのような飛躍を遂げるか、千葉県の地元社会はもちろんのこと、業界全体が彼の動向を注視している。"], "imgs": ["assets/photos/post-3730_b4.jpg"]}]},
{"no": 14, "corp": "株式会社友愛メディカル", "name": "尾崎 汐里", "role": "代表取締役", "star": 2, "head": "ぬくもりを大切にする調剤薬局", "prof": "千葉県松戸市生まれ。東邦大学薬学部卒業後、2012年に株式会社友愛メディカル入社。入社後は薬剤師を経て、店舗責任者、新店舗の立ち上げ、新人研修担当などに携わる。2021年4月、同社代表取締役に就任。患者とスタッフ双方に寄り添う経営で34店舗・285名を率いる。母の創業精神を受け継ぎ、薬局経営を通して、地域医療の安全確保と質向上を目指す。", "url": "https://www.yuai-medical.com/", "photo": "assets/photos/post-3799_t.jpg", "hero": "assets/photos/post-3799_h.jpg", "secs": [{"h": "ぬくもりを大切にする調剤薬局", "ps": ["株式会社友愛メディカル。創業地である千葉をはじめ東京・埼玉・茨城、そして長野へ30店舗以上を構え、述べ280名以上のスペシャリストが「安心」という名の見えない通貨を受け渡す、今熱い調剤薬局ブランドだ。医療という厳粛な営みのなかで、人間性を失わずに患者と同じ目線で向き合うという理念が込められている。", "その舵を握るのは、代表取締役の尾崎汐里。患者と視線を交わしながら薬を手渡すその姿は、先代の社長であった母の背中を見上げていた少女の延長線上にある。"], "imgs": ["assets/photos/post-3799_b1.jpg"]}, {"h": "友愛メディカルは「近道だった」", "ps": ["1988年4月、友愛メディカル1号店「友愛薬局」が開局。そのわずか4カ月後に尾崎は産まれた。いつも家族を大切にしながらも、全力で仕事に向き合う母の後ろ姿と多くのスタッフに囲まれその一人一人を大切にする姿…それが幼少期からの光景だった。", "東邦大学薬学部で6年間を研ぎ澄ました彼女は2012年、新卒薬剤師として友愛メディカルに入社。著名なナショナルチェーン薬局からのオファーもあったが、最終的にすべて辞退したという。「他社を経験してからのほうがいいんじゃないかという意見をいただくこともありましたが、私は昔から母のように、自分の理想的な薬局をもちたい薬剤師になりたいと思っていました。そしてそれを叶えるためには、実は一番身近にある友愛メディカルに入社するのが近道だと確信したんです」", "もちろん社長の娘だからといって、医療に携わる一員として、他の社員同様少しの油断も許されないのは当たり前。入社後は臨床薬剤師として、調剤、服薬指導などの業務に邁進する日々を過ごした。"], "imgs": ["assets/photos/post-3799_b2.jpg"]}, {"h": "効率性と人間の温かみの両立", "ps": ["友愛メディカルの薬局には、必ず座って話すための投薬台がある。立ったまま早々と薬を渡すチェーンの合理性をあえて取り入れず、患者一人ひとりの距離感を毎回測り、患者自身がしっかりと理解できるように懇切丁寧に説明するスタイルを構築した。「もちろん急いでいる人は引き止めません。ただ、安心の速度は人それぞれですし、患者さんが納得できるように対話することは、AIにはできませんから」と尾崎は笑う。", "そして業務の効率化を進める一方、尾崎は“人にしかできないこと”にも時間を使えるように苦心してきた。近年は調剤ロボやAI監査を積極的に導入し、空いたその時間を“人間同士の対話”に再投資。DXは人を薄めるためでなく人間関係をより濃くするための装置であること、それが彼女の哲学だ。", "地域貢献も飾りではない。在宅医療には20年以上前から挑んでおり、自宅や施設で療養生活を送る患者のもとに訪問して、その薬物療法を支えている。また、訪問医師や看護師、介護などとの関連職との連携を深め、療養生活の安全向上に寄与している。千葉県総合救急災害医療センターの門前薬局公募に中小ながら選ばれたのは、「災害時にはグループ全店で薬と人員を投下する」というプレゼンの説得力だった。薬局のカウンターから災害拠点まで、彼女の視界には“一人でも多くの命を支える導線”がいつも描かれている。"], "imgs": ["assets/photos/post-3799_b3.jpg"]}, {"h": "温故創新", "ps": ["両親が友愛メディカルを築いてきたカリスマ性が圧倒的であることを、彼女自身よく理解している。それだけに、2代目としての不安は尽きない。だが、その重圧を跳ね返すように、彼女は次々と新しい挑戦を打ち出している。制度ビジネスの限界を超える挑戦、医療DXの先鋭化、SDGsと女性活躍の加速、そして災害時に“動ける薬局網”の構築。それらを束ねる熱源は、母から継いだ“人への愛情”であり、自身の手で研磨した“変革への執念”だ。", "「千葉県は農業、漁業、工業、そしてエンターテインメントまで、自分が強く望めばどんなことでも叶えられる、全国的に見てもなかなか珍しい土地です。こんなに挑戦できる舞台はないかもしれません。若い方にエールを送るとすれば、どんなことでも構わないから、やってみたいことにぜひ挑戦してほしいなと思います」", "温故創新。温故知新ではなく、過去を抱きしめ、未来を創り直す造語を座右の銘として、尾崎は今日も最良の薬局経営を模索し続ける。"], "imgs": ["assets/photos/post-3799_b4.jpg"]}]},
{"no": 15, "corp": "株式会社SAHエレテクティカルワークス", "name": "高杉 旭", "role": "", "star": 2, "head": "“真摯さ”を追求する会社", "prof": "1992年生まれ、千葉県出身。市川工業高校建築科卒業後、建築・通信関連企業で経験を積み、第一種電気工事士や消防設備士甲種4類などを独学で取得。2024年に株式会社SAHエレテクティカルワークスを設立し、法人向けに電気・消防・空調・防犯・通信設備工事などを提供している。", "url": "https://sahinc.co.jp/", "photo": "assets/photos/post-3722_t.jpg", "hero": "assets/photos/post-3722_h.jpg", "secs": [{"h": "“真摯さ”を追求する会社", "ps": ["壁の中や天井の裏側を通り抜ける無数の電線。それは目に見えないけれど、まさに暮らしを支える大動脈だ。ビルが建つたび、家が生まれるたび、その内部では数え切れないほどの配線作業が緻密に行われている。建物が完成したときには既に見えなくなるが、その見えない場所にこそ、電気設備工事の技術と信念が込められている。", "ヘルメットと安全靴を身につけ、静かな真剣さで仕事に向き合う。彼らが扱う配線や機器一つひとつに、専門的な知識と高度な技術が必要とされる。誤りが許されない緊張感の中で作業を行う職人たちの姿には、職人魂とも言える誇りと責任感がある。", "電気設備工事は、ただ電気を通すだけではない。防犯や通信設備、空調や消防設備といった私たちの安心や快適さを支えるさまざまな仕組みもまた、彼らの手によって実現されているのだ。つまり彼らの仕事は、暮らしの快適さや安全性そのものを設計し、支えているといっても過言ではない。こうした仕事に必要なのは、技術力だけでなく誠実さも然りであり、また安全への徹底したこだわりでもある。電気が持つ危険性を熟知し、常に最高の品質と安全性を追求する姿勢こそが、信頼につながる。"], "imgs": ["assets/photos/post-3722_b1.jpg"]}, {"h": "驚異的な成長スピード", "ps": ["学生時代は自由奔放で、勉強には縁遠い青年だったと話す高杉。しかしある日、真摯に人々のために尽力する現在の妻と出会い、人生が一変したという。「自分も世のため人のために本気で生きなければならない、直感でそう思いました」そう語る高杉は奮起し、電気設備工事の世界に身を投じる。そこからの高杉の熱量は凄まじく、独学で第一種電気工事士と消防設備士甲種4類という難関資格を取得、なんとその勢いで自らの会社を立ち上げた。", "もちろん猪突猛進的に会社を作ったわけではない。高杉はある人物に出会ったからこそ、SAHエレテクティカルワークスという船が必要だと判断したのだ。", "1人は、多田大輝。つねに冷静沈着で、仕事の完成度も高杉を唸らせるほどに完璧な男だ。すでにSAHエレテクティカルワークスで役員を担っており、クライアントからも絶大な信用を勝ち得ている。そしてもう1人は、三田村健太。オールラウンドプレイヤーとして、どんな現場であっても任務遂行能力がケタ外れに高く、その実力と人柄ゆえに社員からの信頼も厚い人物である。"], "imgs": ["assets/photos/post-3722_b2.jpg"]}, {"h": "エレ「テ」クティカル", "ps": ["現在、高杉は社員や役員と共に資格取得に注力し、企業の競争力を高めることを使命としている。彼の経営哲学には儒学が強く影響している。「地の利は人の和に如かず」、つまり土地の利便性や市場の有利性も重要だが、人の結束や和には及ばないという理念だ。この言葉は彼の父親から伝えられたものであるが、すでに高杉自身のことばとして、SAHエレテクティカルワークスの経営の根幹を成している。", "会社としてのこだわりも明確だ。社名の「テ」には、人の手を加えるという意味が込められている。機械化やAIの普及が進む現代において、人の手による丁寧な仕事にこだわり、顧客目線でのサービス提供を徹底していることを示している。「お客様が、ああここまでやってくれるのか、と喜んでいただけるような仕事がつねにできるように、目の前の仕事に毎日、真摯に向き合い続けなければならないと思っています。そのためには人の手が必ず必要ですから」", "とはいえ課題も少なくない。建設業界における若手人材不足や、労働環境の改善。問題意識を明確に持っているからこそ、社員に対しては他社を凌ぐ報酬と福利厚生を用意し、根本から働き方改革を強く推進している。「よく働き、よく遊び、よく学び、よく休む」というSAHエレテクティカルワークスの社是が、その理念を象徴する。"], "imgs": ["assets/photos/post-3722_b3.jpg"]}, {"h": "これからもまっすぐに", "ps": ["若者へのメッセージとして高杉が特に強調するのは、目標の明確さの重要性だ。「一生懸命、正しい努力をすれば、必ず実を結ぶものじゃないですか。ただし、受験や資格取得そのものがゴールになってしまうと、その後に向き合わなければならない本当の学びを吸収できないと思うんです。何のためにそれを達成したいのか、その後のビジョンを具体的に描いて初めて、本気で頑張れるし、頑張った甲斐があると心の底から感じると思うんです」そう語る高杉の言葉には、やけどしそうな熱量がある。", "SAHエレテクティカルワークスは今後、関西圏やさらなる全国展開を視野に入れており、産業廃棄物収集運搬業への参入も計画しているという。そして宅地建物取引士の資格を取り、リノベーションや出張医療サービスにも挑戦することで、社会貢献の幅を広げるつもりだ。まさに挑戦の人、行動の人という表現が彼にピッタリと当てはまる。", "高杉旭という人物の魅力は「一途さ」に尽きる。人生を劇的に変えた愛する人との出会いをきっかけに、まっすぐに突き進む彼のその姿勢は、周囲を巻き込み、大きなエネルギーを生んでいる。彼のこれからの歩みに期待が寄せられる所以である。"], "imgs": ["assets/photos/post-3722_b4.jpg"]}]},
{"no": 16, "corp": "Healing Sea", "name": "若山 みどり", "role": "", "star": 2, "head": "銚子の海で健康を取り戻す", "prof": "幼少期の体調不良を機に自己改善を決意。ヨガやマクロビオティックを学び、全米ヨガアライアンス認定や日本サップヨガ協会公認、シニアヨガ、アーユルヴェーダ、薬膳など多彩な資格を取得。2022年のJAPAN CHALLENGER AWARDグランプリ受賞後、Healing Seaを創業。", "url": "https://www.healing-sea.com/", "photo": "assets/photos/healing-sea_t.jpg", "hero": "assets/photos/healing-sea_h.jpg", "secs": [{"h": "銚子の海で健康を取り戻す", "ps": ["銚子の青い海と、荒々しくも美しい自然の息吹が漂う街角。そこに「Healing Sea」がある。この会社は、酵素風呂、カフェ、ヨガ、そして海の上でおこなうサップヨガといった、心身の健康を根底から変革する事業を展開している。", "会社設立は2024年2月、代表は若山みどり。彼女は、幼少期からアレルギーという身体の弱さと闘いながら、その体験を糧にして自らの道を切り拓いてきた。"], "imgs": ["assets/photos/healing-sea_b1.jpg"]}, {"h": "トリガーはビジネスグランプリ受賞", "ps": ["「実は、私も息子もアトピー性皮膚炎に苦しんでいて、常に自分の身体と向き合う日々を過ごしていました。度重なる体調不良を通じて、アレルギー体質や遺伝的要因が関与しているのではないかと思い、体質改善を志すようになりました」と若山は話す。", "その苦悩の中で、彼女はマクロビオティックやヨガに出会う。バリに渡り、ヨガインストラクターとしての資格を取得した彼女は、ただのエクササイズを超えた、魂を揺さぶる生き方を手に入れる。その後、全米ヨガアライアンス認定をはじめ、日本サップヨガ協会公認の資格、シニアヨガインストラクター、アーユルヴェーダや薬膳、さらにはマクロビオティックやローフードの資格を次々と手中に収め、まるで多彩な才能の化身のように成長を遂げた。", "転機となったのは2022年。JAPAN CHALLENGER AWARDin銚子でグランプリを受賞した瞬間だった。彼女の中で何かが閃いた。その情熱が、自らの体験を基盤にした「Healing Sea」という事業を立ち上げる決意に至ったのだ。"], "imgs": ["assets/photos/healing-sea_b2.jpg"]}, {"h": "そこにあるのは究極の自然感覚", "ps": ["Healing Seaの事業内容は一見するとシンプルだが、その裏には深い哲学と洗練された技術が息づいている。自然発酵による酵素風呂は、電気やガスを一切使わず、檜の香りとともに心地よいリラックス効果をもたらす。ここで得られるのは、単なる健康の域を超え、現代人が失いかけている「本来の自分自身」を取り戻すための鍵となる。さらに、海を望むヨガやサップヨガは、銚子の壮大な屏風ヶ浦や歴史ある千騎ケ岩といった自然の力を背景に、心と身体を解き放つ究極のリトリートとして多くの人々を魅了している。そしてカフェでは、地元農家が丹精込めた新鮮な野菜や果物を使い、地産地消の理念を体現。これらの取り組みは、地域活性化や地方創生にも大きなインパクトを与えており、単なるビジネスの枠を超えて地域社会に根差した共生感覚を呼び起こしている。", "そんな事業展開をおこなっている若山みどりの仕事に対するこだわりは、その一挙手一投足に如実に表れている。たった1人で運営を始めたHealing Seaは、文字通りお客様一人ひとりと向き合う時間を大切にしている。彼女自身が直接接客し、体験談を交えながらサービスを提供するのだ。", "時に、急激な需要に追われる中でも、自分の手でお客様の笑顔を守るという信念を貫き、決して妥協を許さない。その情熱と責任感は、周囲の人々に刺激を与え、口コミを通じてHealing Seaの輪は日増しに広がっていく。"], "imgs": ["assets/photos/healing-sea_b3.jpg"]}, {"h": "「満たされた状態」を目指せ", "ps": ["今、彼女はただ現状に甘んじることなく、常に新たなチャレンジを模索している。次なるステージとして、ウェルネスに特化した宿泊施設の実現や、地域全体の健康意識を底上げする取り組みを計画中だ。空き家のリノベーションを進め、未来の銚子を「健康と癒しのオアシス」へと変革しようとするその姿勢は、まさに時代の先駆者と呼ぶにふさわしい。彼女のビジョンは、単なる利益追求ではなく、心身が真に「満たされた状態」へと変貌する未来への架け橋なのだ。​", "そして、何よりも彼女が大切にしているのは「挑戦する精神」だ。若者たちへ向けたメッセージは、厳しい現実に押し潰されそうな中でも、「一歩踏み出す勇気」を持つことの大切さを訴える。過去の失敗や辛い経験も、すべては自分を鍛えるための宝物。やってみなければ何も変わらないという熱い思いから、「チャレンジし続けることこそが未来を切り拓く唯一の道」であると、自らの生き様をもって示している。Healing Seaは、若山みどりという一人の情熱的な魂が紡ぎ出す、生命力と革新が混ざり合った芸術作品であり、地域とともに成長する生きたプラットフォームなのだ。"], "imgs": ["assets/photos/healing-sea_b4.jpg"]}]},
{"no": 17, "corp": "開成鉄筋株式会社", "name": "藪 建次", "role": "専務取締役", "star": 2, "head": "日本の礎を創る会社", "prof": "千葉県佐倉市生まれ。帝京平成大学卒。2005年開成鉄筋入社、現場見習いを経て2年目で職長に抜擢。2015年課長、2021年部長を歴任し、2023年に専務取締役に就任。工程管理と若手育成で組織を牽引し、週休3日制やSDGs導入などの働き方改革の推進を目指している。", "url": "http://www.kaisei-tekkin.co.jp/", "photo": "assets/photos/post-3790_t.jpg", "hero": "assets/photos/post-3790_h.jpg", "secs": [{"h": "日本の礎を創る会社", "ps": ["鉄筋工事とは建物の心臓部を構築することであり、完成してしまうと目には見えないが、その建造物の最も重要な部分を担う。鉄筋がなければ、私たちの社会は成立しないとも言い切れるだろう。都市という集合体は、鉄筋が生み出した現代文明の結晶とも言える。", "鉄筋加工・組立から圧接工事、積算、施工図作成までを一気通貫で担い、千葉をはじめとした関東各地に、開成鉄筋株式会社は鋼の血管を這わせ続けてきた。現場で汗を噴き上げる作業員たちの背後に、ひときわ静かな焔のように立つ男がいる。専務取締役・薮建次。開成鉄筋の中枢を支える人物だ。"], "imgs": ["assets/photos/post-3790_b1.jpg"]}, {"h": "受けた恩は忘れない", "ps": ["1982年に創業した開成鉄筋。1998年には、長年取引していたゼネコンからの依頼が急遽途絶え、明日の仕事さえ保証されない危機に直面したこともあった。しかし、そのときに手を差し伸べたのは、多くの他社ゼネコン会社、そして開成鉄筋を支え続けてきた仲間たちだったという。彼らのおかげで今があると語る藪。受けた恩は忘れず継がれてゆくのが、開成鉄筋の魅力だ。", "そんな藪は千葉県佐倉市出身。子どものころ、社長である父の背中越しに職人たちの笑い声と火花を見て育った。大学卒業後の2005年、入社と同時に修行と称して現場に放り込まれる。初年度は「見習い」、2年目からはいきなり職長になった。工程表と溶接音の間で右も左もわからぬまま指揮を執っていた藪は、深夜の現場事務所でも図面にひたすら目を凝らしていた。悪戦苦闘の入社2年目の混乱こそが、彼の鉄筋道の原点だった。", "2015年に課長、2021年に部長、そして2023年に専務取締役に就任。就任後に彼がまず手を付けたのは「若返り」と「働き方改革」であった。現場週休2日制がやっと浸透し始めた業界で、藪は「週休3日」を視野に入れ動き出す。そしてSDGsの一環として成田工場屋上に太陽光パネルを敷き、2024年には自家消費電力の30％の再エネ化を達成した。"], "imgs": ["assets/photos/post-3790_b2.jpg", "assets/photos/post-3790_b3.jpg"]}, {"h": "歴史を刻め", "ps": ["変革の中にも変わらないものがある。彼の目指すのは、信頼される企業としての地位を揺るぎないものにすることだ。藪が望むのは、その歴史が何十年、何百年と残ること。開成鉄筋が手がける建物は、そのまま街の歴史となる。", "最後に、若い世代へのメッセージを尋ねると、彼はためらいなく答えた。「昔気質かもしれませんが、目の前の課題を全力で乗り越える気合いさえあれば、大抵のことはなんでもできると思います。もしかしたら最初の一歩は少しためらうかもしれませんが、その一歩があなたを変える重要な布石です。私は逆にそれさえあれば、どんな場所でも充実した仕事ができると確信しています」。"], "imgs": ["assets/photos/post-3790_b4.jpg"]}]},
{"no": 18, "corp": "アクシビワーズ株式会社", "name": "久保 大海", "role": "", "star": 2, "head": "教師から経営者へ", "prof": "1988年、東京都生まれ。専修大学卒業後、中学校講師や飲食業界での経験を経て、2015年に起業。その後、2021年にアクシビワーズ株式会社を設立し、建設機械販売など多角的な事業を展開している。", "url": "https://axiviwords.co.jp/", "photo": "assets/photos/post-3688_t.jpg", "hero": "assets/photos/post-3688_h.jpg", "secs": [{"h": "教師から経営者へ", "ps": ["時代が進み、街並みが変わっても、人が地面を掘り、土を盛り上げる行為に変わりはない。それを支える建設機械は、大きな轟音とともに、われわれの暮らしの基盤をつくる静かな縁の下の力持ちである。", "アクシビワーズ株式会社は、2021年5月に千葉県柏市に設立された、自動車・建設機械の販売買取および修理を行う企業である。代表取締役の久保大海氏は、1988年東京都出身。専修大学を卒業後、非常勤講師、飲食業など異色の経歴を経て起業した人物だ。設立間もない企業ながら、中古建設機械や特殊車両の取り扱いに特化し、解体系や林業系の希少なユンボを仕入れ、独自の修理・塗装技術を駆使して市場に送り出すことで、業界内での存在感を高めている。"], "imgs": ["assets/photos/post-3688_b1.jpg"]}, {"h": "潰れてたまるか", "ps": ["雇われ人生からの脱却、そして借金返済。久保の起業の動機は極めてシンプルで、ある意味衝撃的でもある。「やらないと、死ぬ。あのときはただそれだけを感じて、目の前のことに必死になっていました」と語る彼の起業時の覚悟は、並大抵のものではない。", "起業したあとも大変だった。彼が事業を立ち上げたばかりの頃、取引相手から一方的に契約を破棄され、大きな損害を被った詐欺まがいの被害を食らったこともあったという。周囲には撤退を勧める者もいたが、久保はその窮地に際し、自分の中に眠っていた闘争心を発見した。「こんなことで潰れてたまるか、と思いました」強烈な反骨心が彼を奮い立たせた。この出来事をきっかけに、久保は経営に対して今まで以上にシビアに数字を追求するようになった。ただ漫然とビジネスを続けるのではなく、利益を生むための戦略と緻密な計画を徹底して練り上げ、短期間での業績改善を実現したのだ。"], "imgs": ["assets/photos/post-3688_b2.jpg"]}, {"h": "口ではなく行動で語れ", "ps": ["経営に対する彼の姿勢は一貫して「口動より行動」、つまり理想や目標を語ることは誰にでもできるが、それを現実のものにするには具体的な行動が絶対的に必要だと、彼はつねに強調している。その信念を証明するように、久保は創業後間もなく中古車販売から始まり、建設機械販売、中古車や建機の修理業、軽運送業と、次々に事業領域を拡大していった。何か一つがうまくいかないときも立ち止まることなく、新しい事業機会を模索し、積極的な挑戦を継続してきた。その結果、現在では業界内で確かな地位を築きつつある。", "現在、久保が最も力を注いでいる建設機械販売事業では、林業や解体業界向けの特殊な機械を仕入れること自体容易ではないものの、久保独自のネットワークを活用して希少な機械を入手し、それら一つひとつに、高い修理技術と丁寧な再生工程を経て、新たな価値を生み出している。古びた機械を再び生命を吹き込むかのように再生させる彼の手腕には、絶大な信頼がある。そして他社が手掛けられないような難易度の高い案件にも積極的に挑戦し、その成功が市場での評価をさらに高めている。", "地域に根差した経営も、久保の大きな特徴だ。千葉県柏市に本拠を置いた理由として彼はこう述べている。「やはり首都圏のなかでは土地が安価であるという地理的要因もあります、ただやはり、この土地に互いに助け合える仲間がいるのが大きいですね」。久保は日常的に地域の人々と交流を深め続け、そして困ったことがあれば、お互いに助け合いながらビジネスを展開している。こうした地元との強固な絆が、企業の安定運営と急速な成長を支えているのだ。"], "imgs": ["assets/photos/post-3688_b3.jpg"]}, {"h": "自分自身に許可を出す", "ps": ["建設機械のシャベルが土を掘り返すたび、過去に埋もれた思い出や歴史がむき出しになる。これまで誰も気づかなかった層が、まるで剥き出しの神経のように外気に触れ、一瞬だけ光を浴びる。そして、またすぐに押しつぶされ、新しいコンクリートの下へ消えてゆく。それでも人は掘り続ける。新たな高層ビルを建て、より快適な生活を求めて。", "果てしない破壊と創造の循環のなかに、久保は今立っている。壊し、再び生み出す。新たな価値を発見し、古いものに新しい生命を吹き込む。久保はこの現場に、自らの経営哲学を重ねる。どれほどの成功を掴んだとしても、次の目標を掲げ、それに向かって掘り続けることをやめない。", "「なぜか”自分にはできない”と、自分自身にあえて枷をかけている若い方が非常に多いなと思います。でもそれって、なんだかおかしいんじゃないかと思うんです。あなただってビジネスをやって構わないし、考えを発信したって誰も不幸にはならない。自分もやっていいんだって、言うなれば許可を出すように自分に問い質してみると、一歩でも前に動けるようになるんじゃないかなと思います。自分でやってみると、人生きっと、よりよくなります」"], "imgs": ["assets/photos/post-3688_b4.jpg"]}]},
{"no": 19, "corp": "サン・ジオテック株式会社", "name": "大石 哲", "role": "代表取締役", "star": 2, "head": "立体世界を映し出す測量会社", "prof": "1963年東京都生まれ。日本大学理工学部土木工学科を卒業後、測量会社大手に入社。GPSや合成開口レーダーの研究、国土地理院への出向、アフリカのニジェール共和国での国家基準点のプロジェクトにGPSのチームリーダーとしての参画を経験。アジア航測に入社後、執行役員を経て、2023年にサン・ジオテック代表取締役に就任。", "url": "https://www.sungeo.co.jp/index.html", "photo": "assets/photos/post-3773_t.jpg", "hero": "assets/photos/post-3773_h.jpg", "secs": [{"h": "立体世界を映し出す測量会社", "ps": ["古代から続く職業のひとつに、測量がある。アスワン・ハイ・ダムが未完成だったその昔、エジプトのナイル川が氾濫するたびにその土地を正確に測り直し、農地を分け直したという。あのピラミッドこそ、多数の測量結果をもとに、綿密に手順を考えて建築に至ったとされている。そして現在。千葉市中央区に、地域に根ざしながら世界全国へ技術を還元し、まるで目の前の風景に命を吹き込むかのごとく測量情報を刻み続ける会社がある。", "サン・ジオテック株式会社は1969年、航空写真測量を礎に、アジア航測株式会社のグループ会社として誕生した。以来、50年以上にわたって空間情報技術の最前線を走り続けてきた。緻密な点群、赤色立体地図、3Dサービス…提供するその技術は業界のなかでも幅広く、平面図だけでは見えない世界を、航空機からUAV（無人航空機）、車両や地上型機器まで、多種多彩なプラットフォームを用いた計測データを活用することで「立体地図」としてモニターの上に描き出す。", "この世界を操るサン・ジオテックの代表が、大石哲だ。大学の土木工学科を卒業後、GPS黎明期に測量業界大手へ入社。山岳の三角測量から国土地理院での部外研究員、そして社内の「空間情報大学」開校…あらゆる場所へ飛び込み続けたその歩みは、まさしく冒険譚という名にふさわしい。"], "imgs": ["assets/photos/post-3773_b1.jpg"]}, {"h": "ドラマのような高校3年間の寮生活", "ps": ["大石の学校生活は、令和の高校生では想像できないほど刺激的なものだった。「全国でも珍しい全寮制の公立高校でした。まず、朝6時にアラームで叩き起こされます。6時半の点呼で仲間と顔を合わせます。そこから教室へ向かい、17時45分の帰寮後も、入浴、食事、そして22時半まで学習の時間が続きます。23時の就寝まで一瞬の隙も許されなかったです。しかも8人部屋でした。今でこそまるでドラマのようかもしれませんが（笑）…あの3年間で養われた、洗練された協調性と継続力は、現場の仕事で大きく役に立ちました」", "大学では測量学を学び、卒業後は業界大手に入社。GPS黎明期の山岳三角測量から、合成開口レーダー研究、つくばの国土地理院出向など、全国を股にかけた実測と研究に没頭した。", "さらに異国の地、ニジェールへ。日本から約12,000km離れている、治安が良いとは決して言えない、西アフリカの一国だ。その国家基準点の策定プロジェクトに参画した大石は、一面砂漠のエリアを、15名ほどのメンバーと共に測量。砂塵と熱波に囲まれながら、1年かけて現地でその国家体系を築いた体験は「どんな困難も仲間と越えられる」という自信の源泉となった。"], "imgs": ["assets/photos/post-3773_b2.jpg"]}, {"h": "実は“学長”", "ps": ["サン・ジオテックの最大の矢は「応用測量」だ。道路建設の中心線を決める路線測量、用地買収に不可欠な境界測量、河川の氾濫リスクを数値化する縦横断測量、この三本柱に、航空レーザーや車載レーザー（MMS）、地上型レーザーをハイブリッドに組み合わせる。災害現場の迅速把握、都市計画のシミュレーション、文化財保護の精密解析…。大容量の点群処理から赤色立体地図、さらには３次元サービスまで、地域の声を受け止めて形にする技術は、高く評価されている。", "一方、社内の人材育成にも熱い。週次ブリーフィングでは、一人ひとりの成果を可視化し「報・連・相」「挨拶」「議事録」の書き方まで細部にわたって指導。現場でのOJTも重視している。また大石はアジア航測時代、社内にグループ全体で視聴可能な「空間情報大学」を開設。約400講座をYouTube形式で配信する体制を構築し、いつでも、どこでも、誰でも、社会人の基礎から測量の応用まで学べる環境を整えた。属人的になりがちな「技術の空洞化」問題に対し、最適な布石を打ったのである。"], "imgs": ["assets/photos/post-3773_b3.jpg"]}, {"h": "愚痴と改善案をこぼすこと", "ps": ["大石は、今後現在の業績を2倍に引き上げることを目標としている。そして、社員一人ひとりが努力の果実を実感し、地域社会から信頼される企業ステータスを確立する。そしてそのために、人材への投資、キャリア採用の強化、新領域への設備投資を惜しまない。大石の掲げるこれらの目標は明確そのもので、聞いていて気持ちがいい。", "地図を作るとは、人と環境の関係性を可視化すること。地形図もヒトの営みも、どちらも“見えないものを見せる”という点で変わらないのだ。サン・ジオテックは、その理想を体現し続けられるモデルケース・カンパニーだろう。", "「つねに社内では、“どんなじんざいになりたいか”を説いています。人罪、人在、人材、そして人財。特に若い方々には、組織の役割や連携を発展させる“人財”になってほしい。実はそのためには、会社の愚痴を言ってもらうのが重要だったりします。愚痴は、ものごとを理解して初めてこぼすもの。つまりその愚痴には、会社が成長する課題や伸びしろが隠されているんです。"], "imgs": ["assets/photos/post-3773_b4.jpg"]}]},
{"no": 20, "corp": "ホオジロ行政書士事務所", "name": "日向 麻里", "role": "", "star": 2, "head": "依頼者の思いを丁寧に汲み取る行政書士", "prof": "東京都立大学理学部卒。システム開発会社、コンサルティング会社を経て、特許事務所勤務中の2004年に弁理士試験に合格。結婚と子育てを経て、自己実現と家庭両立を求め行政書士に転身、独立後はホオジロ行政書士事務所を設立。相続、成年後見、外国人在留資格申請、事業承継など多岐にわたる法務サービスを展開し、事業承継士としても活躍中。", "url": "https://hojiro-firm.jp/", "photo": "assets/photos/post-3749_t.jpg", "hero": "assets/photos/post-3749_h.jpg", "secs": [{"h": "依頼者の思いを丁寧に汲み取る行政書士", "ps": ["法律や行政手続きというものは、確かに冷淡に見える。しかし、それを扱う人の中に温かみがあれば、人は救われるものである。書類ひとつにも人生が宿る。その生命を活かすのが行政書士の腕の見せどころだ。", "千葉市若葉区の一角にあるホオジロ行政書士事務所。代表を務める日向麻里は行政書士として、外国人の在留資格申請、相続・遺言・成年後見、さらには中小企業向けの事業承継支援など、幅広い法務サービスを提供する。まるで多様な風景が一つのキャンバスに描かれるかのように、依頼者一人ひとりの思いを丁寧に拾い上げ、その一端を担う。"], "imgs": ["assets/photos/post-3749_b1.jpg"]}, {"h": "「本当にやりたいことは何か？」", "ps": ["もともとは、国家資格である弁理士に合格し、知的財産の世界で輝かしいスタートを切った日向。しかし、当時の彼女は、特許事務所での業務に打ち込みながらも、どこか心に違和感を覚えていた。表面的な成功や安定したキャリアの先に、真の自分自身の姿が見えなくなってしまったことに気づいたのである。", "転機は、結婚という人生の大転機と共に訪れた。結婚し、母となったことで、家庭という新たなステージに踏み込んだ日向は、同時に自らの働き方や生き方にも問いを投げかけるようになった。かつての彼女は、会社員として13年半、さらにはコンサルティングファームで1年半の経験を積んだ。しかし、家族との時間、そして自分自身の内面との対話を重ねる中で、「本当にやりたいことは何か？」という問いが彼女の心に深く根付いていった。", "仕事に対する情熱が薄れ、精神的な限界を感じた。しかし、どん底に近い状態になりながらも持ち前の胆力と周囲の支えで乗り越え、夫の助けを得ながら独立。彼女は再び自分の力で未来を切り拓く道を選んだのである。"], "imgs": ["assets/photos/post-3749_b2.jpg"]}, {"h": "専門性＆柔らかな対応", "ps": ["ホオジロ行政書士事務所は、単に法律手続きの代理業務を行うだけではない。依頼者一人ひとりの不安や疑問に寄り添い、心のサポートも惜しまない。外国人のビザ申請や企業の事業承継支援、そして複雑な相続手続きなど、各分野での専門的な知識と経験は、彼女ならではの強みであり、依頼者に安心感を提供する最大の武器である。", "また、彼女の丁重で穏やかなコミュニケーションからは、依頼者が何でも話せるような温かみを感じさせ、その信頼は日増しに高まっている。日向自身、日々の業務の中で「お客様の最高のパートナーになる」という信念を貫いており、時には困難な状況にも正面から向き合い、解決への道筋を探し続ける。忙しさに追われる現代社会の中で、依頼者にとって「安心できる存在」としての役割は、計り知れない価値を持つ。"], "imgs": ["assets/photos/post-3749_b3.jpg"]}, {"h": "自分を誇りに思うこと", "ps": ["「ただひたすら前を向く」。彼女は、過去の苦悩も喜びもすべてを包み込んできた背中を持ちながらそう語る。自らの経験を通じて、今の時代に必要なのは「自分に素直に、ありのままの自分を受け入れること」であると強く訴える。", "「私自身、自分の気持ちに正直になれないまま日々を過ごしてしまった時期があります。でもそれってかなり身体に負担がかかってるんです。それって裏を返すと、例えば、どうせ私は何をやってもダメだから、というような、ある種自己否定に溺れている状態に近いですよね。時間は少しかかると思いますが、ありのままの自分に向き合って、素直に受け入れて、少しでも自分を誇りに思ってもらうことが、今の時代特に大切なんじゃないでしょうか。」"], "imgs": ["assets/photos/post-3749_b4.jpg"]}]},
{"no": 21, "corp": "浦田空調工業株式会社", "name": "浦田 裕晶", "role": "専務取締役", "star": 2, "head": "建物を呼吸させる会社", "prof": "青山学院大学卒業後、不動産関係の会社に入社。その後2022年に家業である浦田空調工業へ入社する。外部視点を武器にIT化や働き方改革を進め、祖父の時代から築きあげてきた「信頼の歴史」を継承すべく、空調ダクト業界を刷新する専務取締役として尽力している。", "url": "https://urata-ac.jp/", "photo": "assets/photos/post-3765_t.jpg", "hero": "assets/photos/post-3765_h.jpg", "secs": [{"h": "建物を呼吸させる会社", "ps": ["人間の呼気は、目に見えないからこそ、その質を保つ仕組みが欠かせない。外から新鮮な空気を運び入れ、建物のなかの汚れた空気を静かに排出することで、私たちの健康を支えている。空調ダクトという世界は、だからこそ実に奥深い。", "浦田空調工業株式会社。千葉県千葉市に根を下ろし、千葉県内を中心とした数々の商業施設や工場、オフィスビルなど、人が行き交う空間の心地よさを陰で支える企業である。その主な事業は空調ダクトの製造と取り付けで、1枚の鉄板から作り上げる製造から、現場での設置までを一貫して行うのが特徴だ。1972年の創業という老舗で、バブルの崩壊、リーマンショック、そして自然災害など幾多の試練を乗り越え、千葉県での存在感を揺るぎないものにしている。", "工場の奥へ進むほど、金属のきらめきと職人の熱気に満ちている浦田空調工業。そこで中心的な役割を担うのが、専務取締役であり、次の世代の経営を託されつつある四代目、浦田裕晶氏だ。彼の瞳には、先人たちが積み重ねてきた「信頼」という重厚な財産を、確実に未来へ引き渡す、その覚悟がうかがえる。"], "imgs": ["assets/photos/post-3765_b1.jpg"]}, {"h": "「商売は信頼第一」", "ps": ["浦田裕晶は幼少期から剣道に明け暮れ、高校までの12年間を竹刀に捧げた。勝てない日々が続いていた彼はあるとき、悔しさのなかに「努力はどう実行するかを考えた者だけが報われる」という真実に気づき、そこで“考えること”の大切さを自ら骨の髄まで叩き込んだという。", "大学卒業後、不動産関係の会社に入社。人材系のビジネスの現場にも身を置き、つねに“相手が何を求めているか”を意識する日々だった。そしてあるとき、父から二択を突きつけられた。「会社を潰すか、それとも継ぐか」。浦田空調工業を畳んで祖父から築いてきた信頼の歴史を終わらせるのか。それとも戻ってまったくの異業種であるこの家業に身を投じ、100年企業へと育て上げる礎になるのか。どちらを選んでも楽ではなかったが、答えは意外にも早く出た。なぜなら選択に迫られたとき、祖父の「商売は信頼第一」という言葉が、脳裏で何度もリフレインしたからだ。過去に、自分に向けてくれた笑顔を失いたくない…その思いで、彼は意を決し、浦田空調工業の専務取締役として新たな船出を始めたのである。"], "imgs": ["assets/photos/post-3765_b2.jpg"]}, {"h": "考える力を持つ職人集団へ", "ps": ["浦田がまず取り組んだのは“人が集まりたくなる会社”への進化だった。町工場という外観だけでは、なかなか若い人材に興味を持ってもらえない。ならば制度を整えてみよう。たとえば有給休暇の取得環境を見直したり、必要に応じて柔軟な働き方を検討したり。若い世代が入ってきても「何だ、この会社、古いな」と思わず、むしろ「ここならチャレンジできるかも」と感じられる空気を作るべく奮闘した。", "そしてDXも見逃せないポイントだ。作業工程を丸ごとIT化しようとしても、職人たちが長年培ってきた経験や勘は簡単に置き換えられない。一方で、受注管理や在庫管理、設計図面の調整など、デジタル化による効率アップが見込める場面も多い。そこを的確に仕分けし、昔ながらの“こだわり”と最新ツールの利便性を融合させるのが彼の戦略である。これにより職人は現場で考え、作業する時間をより多く捻出することができるようになる。", "特にこのダクトというニッチな業界において、会社制度の整備やDXの浸透にはまだまだ時間がかかっている。つまり今浦田が考えている「新しい働き方と、考える力を持つ職人集団」への進化が、業界においてトップスピードで、この浦田空調工業で実現しているのだ。"], "imgs": ["assets/photos/post-3765_b3.jpg"]}, {"h": "そこには必ずロマンがある", "ps": ["業界全体として高齢化や人材不足が叫ばれる中、現場の作業もさらにスピードと正確性が求められていく。だが、その“厳しさ”こそが、逆に新しい風を呼びこむチャンスだと浦田は語る。「逆に知られていないからこそ、ゼロから構築できる余地を楽しめるメリットがある。自分が開拓者になれるという夢が、ここにあるんです」そしてIT化や効率化を大胆に進め、社員や協力会社と共にこれまでの常識を再編していく、その気概があれば、職人の手仕事がより輝き、別の業界の方でさえ憧れるような世界をきっと作れるのではないか、と。", "「僕だって正直、ダクトのことなんて家に生まれていなければ知らなかったと思います（笑）。たしかに華やかさはないかもしれない。でも、自分が作り上げたものが、大勢の人の役に立つ…その達成感って、なかなか得られるものじゃないんですよ。僕らが誰かの暮らしの一部を作っているんだと思うと、本当にやりがいは尽きません。若い世代にはぜひ、自分の仕事にロマンを抱いてほしいです」"], "imgs": ["assets/photos/post-3765_b4.jpg"]}]},
{"no": 22, "corp": "株式会社きららぼ", "name": "金田 茂樹", "role": "", "star": 2, "head": "夢を形にする男", "prof": "1959年岩手県生まれ。音大卒業後、15年間音楽教師を務める。退職後、40歳でIT業界へ転身。ライブドアでポータルサイトの礎を築く。55歳からフリーランスエンジニアとして活動し、2024年2月、株式会社きららぼを設立。", "url": "https://kiralab.jp/", "photo": "assets/photos/post-3757_t.jpg", "hero": "assets/photos/post-3757_h.jpg", "secs": [{"h": "夢を形にする男", "ps": ["東京の喧騒から少し離れた場所に、株式会社きららぼがある。ウェブデザインと制作を軸に、ECサイトの構築と運用までを手掛けるこの会社は、まるで現代の錬金術師の工房だ。そこに君臨するのは、代表取締役社長の金田茂樹。衰えることのない情熱と、時代の先端を切り開く鋭い眼光を持つ男である。", "彼の手にかかれば、クライアントの夢は魔法のように形になり、それはまさにインターネットという無限の海を航海する船となる。きららぼは、単なる制作会社ではない。金田という男の人生そのものが投影された、まるで生き物のような存在だ。"], "imgs": ["assets/photos/post-3757_b1.jpg"]}, {"h": "音楽からITの海へ", "ps": ["1959年、岩手県に生まれ、音楽という聖域に身を捧げた金田。音大を卒業後、15年間にわたり高校で音楽教師として若者たちに旋律の美しさを説いた。だが、彼の心は常に別の音色に共鳴していた。音大時代に起きた出来事、コンピュータの登場である。アップルが世界に台頭してきた時代、彼はSAXを極めるべく鍛錬を重ね、同時に高田馬場の小さな店に通い詰め、果ては当時約60万円のAppleIIという最高のマシンをただ触りたい一心で、そこでバイトを始めた。そこから彼の運命は加速する。", "40歳でIT業界に飛び込んだ金田。面接90回を経て役員に拾われ、スーパーバイザーとして名刺を手にした瞬間、彼は「なんでもできる」と確信したという。ライブドア時代、彼はインターネットの未来を切り開いた。ニュース、天気予報、地図、ゲーム。今では当たり前のポータルサイトの要素を、産経新聞や気象会社に単身乗り込んで形にした。渋谷を走るライブドアのバスは、彼の勤めていたライブドアが広告媒体として初めて具現化した瞬間だった。", "だが、時代の波は無情だ。無料プロバイダーの夢はフレッツの登場で崩れ、会社は畳まれた。それでも金田は諦めなかった。50代でまたしても指導者の道を歩み、55歳からは同時にフリーランスエンジニアとしても活動。そして2024年2月、きららぼを設立する。ECサイトでバスボムを扱い始めたタイミングで、彼はスクリプトを駆使してメルカリや楽天の売れ筋を分析し、中国の工場と交渉を重ねた。初月で100万円、3年後には月に1,000万円をゆうに超える売上を叩き出すまでに成長した。"], "imgs": ["assets/photos/post-3757_b2.jpg"]}, {"h": "最高にカッコいいものを", "ps": ["きららぼの事業は、ウェブデザインとECサイト運用という二本柱で成り立っている。だが、その本質は「夢の実現」だと彼は語る。クライアントが「素敵なサイトを作りたい」「ECで自分の商品を売りたい」と願えば、金田は必ずそれを叶える。AIをすでに当たり前の道具として使いこなし、時代の流れに逆らうことなく「最高にカッコいいもの」を生み出すのだ。その強みは、最先端技術への執着と、クライアントのニーズを深く理解する鋭い感性にある。例えば、彼が開発したハンディファンは、100段階の強力な風を小さなボディで実現し、新たな市場を試すほどの革新性を持つ。", "今、金田が注力するのは、プロダクト開発とその展開だ。バスボムから始まり、ステンレス製の万能調理器具、そして最新のハンディファンまで、彼の手掛ける製品はどれも「時代のニーズ」を捉えている。"], "imgs": ["assets/photos/post-3757_b3.jpg"]}, {"h": "どんな形であっても飛び込め", "ps": ["金田茂樹の視線は、常に未来に向いている。毎月100%以上の成長を掲げ、飛躍と安定を両立させながら、無理なく楽しく事業を進める…それが彼の理想だ。「楽しくなければ仕事じゃない」と自然に思えることを大切にし、きららぼをそんな場所にしたいと願う。", "数々のAIが台頭してきたタイミングで、彼はセミナーでChatGPTを駆使し、受講生の目の前でなんということもなくで美容室のサイトを作り上げ、技術の可能性を若者たちに示した。それが3年前。今もなお、彼は最新のものを追い続け、実践を通じて証明していく。", "「私は音楽教師からITの世界に飛び込み、会社を興し、自分の理想を自分の手で叶えてきました。時代は速い。でも、そのスピードにどんな形であれ乗ってさえしまえば、夢は現実になると思います」"], "imgs": ["assets/photos/post-3757_b4.jpg"]}]},
{"no": 23, "corp": "陽光希株式会社", "name": "谷田 光希", "role": "", "star": 2, "head": "輝く可能性に満ちあふれる会社", "prof": "2019年中央工学校卒業。同年、新卒で建設関係の会社に入社。2022年、一人親方として独立。2023年陽光希ネクストという屋号で個人事業主として開業後、2024年に陽光希株式会社を設立。", "url": "https://hinatamituki.jp/", "photo": "assets/photos/post-3713_t.jpg", "hero": "assets/photos/post-3713_h.jpg", "secs": [{"h": "輝く可能性に満ちあふれる会社", "ps": ["千葉県全域を拠点に活動する陽光希株式会社は、建設業と広告業を主軸に据えた新進気鋭の企業である。僅か2名の従業員という規模でありながら、その存在感は計り知れず、建築と土木の両面で公共工事を中心として展開に加え、広告業界にも新たな風を送り込んでいる。", "2024年3月に設立されたこの会社の舵を取るのは、代表取締役を務める谷田光希だ。彼の経営哲学と行動力は、まさにその社名が示すように、多くの人々に希望と活力を与えている。"], "imgs": ["assets/photos/post-3713_b1.jpg"]}, {"h": "社名の真意", "ps": ["1998年に千葉県で生まれ、千葉県で育った。2019年に中央工学校を卒業後、建設会社に入社しキャリアをスタート。その後、一人親方として現場で経験を積み、2023年には個人事業主として陽光希ネクストを立ち上げる。そして2024年、自らの企業理念とビジョンを具現化するため、陽光希株式会社を設立した。", "自身、20歳の頃に交通事故に遭い、大きな怪我を負った。「命の儚さ」そして「自分の使命」を考えさせる契機となった。その後、なんと交通事故によって弟を失った。乗らなくなり谷田が弟に引き渡したバイクに乗っていた最中での事故だった。渡さなければ死ななかったのかもしれない…そんな後悔も相まって、彼は深い葛藤と向き合うことになる。", "しかし、「亡くなった者は二度死んではならない」という僧侶の言葉に深く心を動かされた。谷田の心には「どこかに弟の名前を残したい」という強い思いが芽生えた。陽光希という名前には、弟への追悼とともに未来への希望が込められている。"], "imgs": ["assets/photos/post-3713_b2.jpg"]}, {"h": "営業職は設置しない", "ps": ["陽光希株式会社は、建築と土木工事という二つの柱で地域社会に貢献している。公共工事から民間リフォームまで幅広い分野で実績を積み上げており、その柔軟性と対応力は顧客から高く評価されている。", "また、営業職を設置しないという独自方針も特徴的だ。無理な押し売りではなく、本当に必要とする顧客へ丁寧なサービスを提供する姿勢は、谷田自身が実家や家族との経験から得た「家」というものへの深い思い入れによるものだ。", "さらに広告業では、動画編集やSNSコンテンツ制作など、新しい時代に即したサービスも展開している。学生時代から趣味として動画制作に親しんできた谷田ならではの発想力が、この分野でも活かされている。"], "imgs": ["assets/photos/post-3713_b3.jpg"]}, {"h": "日本人の魅力を再び", "ps": ["谷田が目指す未来像は明確だ。「現場監督という職人」を育成し、日本人主体の建設業界を再び活性化させることである。外国人労働者が増える中、日本人職人特有の「丁寧さ」や「こだわり」を次世代へ継承することに情熱を注いでいる。また、空き家再生プロジェクトにも意欲的であり、新築同様の耐震性やデザイン性を持たせたリノベーション事業にも挑戦していく計画だ。", "「弟の死を通して、人生は有限であること、そしてだからこそ、よっぽどのことがない限り、人はそう簡単には死なないと感じています。だから失敗を恐れず、とりあえずでいいから、したいことをやってみてほしいと思っています」"], "imgs": ["assets/photos/post-3713_b4.jpg"]}]},
{"no": 24, "corp": "いちずリフォーム株式会社", "name": "市川 大祐", "role": "", "star": 2, "head": "疲れた住まいを蘇らせるリフォーム会社", "prof": "大手リフォーム会社で営業職を経験後、顧客本位でない業界慣行に疑問を抱き、個人事業主として「いちずリフォーム」を創業。昨年、法人化し、千葉市緑区を拠点に外壁塗装や屋根工事を中心とした地域密着型のリフォーム事業を推進している。", "url": "https://www.ichizu-reform.info/", "photo": "assets/photos/post-4078_t.jpg", "hero": "assets/photos/post-4078_h.jpg", "secs": [{"h": "疲れた住まいを蘇らせるリフォーム会社", "ps": ["住宅に“定期点検”が必要であるという発想は、どこか私たちの生活の奥底に忘れられがちである。時間が経つにつれ、外壁や屋根は外壁や屋根は疲れ、くたびれてゆく。だが、その変化は日々の営みに溶け込み、住む人にとっては当たり前の風景になってしまう。そういった中で、家を守るという、地道で力強い使命を、静かにそして誠実に貫く会社がある。", "千葉市緑区に拠点を持つ、いちずリフォーム株式会社だ。同社の主力は外壁塗装や屋根工事、そして住宅の各種リフォームなど、それは単なる修繕ではない。10年、20年を共に過ごした住まいを、もう一度家族の心地よい拠点として蘇らせる、そんな役割である。", "代表取締役の市川大祐はこう語る。「車に車検があるように、住宅にもメンテナンスが必要です。早め早めに手を入れることで、余計な負担やコストを防ぐことができるんです」"], "imgs": ["assets/photos/post-4078_b1.jpg"]}, {"h": "納得できる仕事を自分の手で", "ps": ["市川がリフォームの世界に足を踏み入れたのは、大手リフォーム会社に勤めていたときのこと。顧客ではなく数字重視の営業体質に感じた歯がゆさ、そして金額は同じでも工事の中身がバラバラなことについて違和感を持ったことが独立への原動力となった。", "納得できる仕事を自分の手でやりたかった。満を持して、個人事業として「いちずリフォーム」を立ち上げる。利益よりも顧客満足を優先する、これが社名の由来でもある「一途＝いちず」な理念だ。", "試行錯誤の時を経て、昨年ついに法人化を果たし、少数精鋭のチームとともに地域密着型の事業モデルを確立した。この仕事に特別な憧れがあったわけではない。それでも「ありがとう」と直接言ってもらえる喜び、手ごたえが続ける原動力になっていると語る。"], "imgs": ["assets/photos/post-4078_b2.jpg"]}, {"h": "多角的な視点から顧客を支える基盤", "ps": ["いちずリフォームの社内は数名の少数精鋭。千葉県出身のスタッフが和気あいあいと働き、現場の声も代表の想いもダイレクトに共有される風通しの良い環境だ。急なトラブルにも機動力を発揮し、社員一人ひとりが「地域の役に立っている」という自覚と誇りを持っている。", "外壁塗装・屋根塗装を主力としつつ、雨漏り修理や防水工事、室内の水回り改修など、サービスメニューも拡充中のいちずリフォーム。最近では、給湯器エコキュート関連の地域密着サービスや、内装リフォームにも力を入れ始めた。", "小さな補修から大きな改修まで、住まいの困りごとにワンストップで対応可能で、社内には外壁劣化診断士や雨漏り診断士といった資格保有者も在籍しており、最新塗料の積極導入、地元メーカーとの連携もスムーズ。様々な視点から住まいを守る体制が整っている。"], "imgs": ["assets/photos/post-4078_b3.jpg"]}, {"h": "なによりもまっすぐに", "ps": ["市川に会社としての展望を尋ねると「まずはこのエリアで一番信用される会社になりたい」と力強い答えが返ってくる。次に富里や成田方面へ給湯器専門店のような形で店舗を展開し、エリアを限定せず複数拠点での事業拡大を検討中。将来的には住宅のことなら何でも応えられる、総合的な存在を目指しているという。", "「私たちの仕事には、地域の方々の住まいを支え続けるという大きな意義があります。だからこそ、この仕事をより多くの方々に、身近に感じてほしいですね」", "暮らしに根ざし、一途に…地域の風景に溶け込むような、いちずリフォーム株式会社。その存在はその土地に暮らす人々の心に、やさしい温もりをもたらしている。"], "imgs": ["assets/photos/post-4078_b4.jpg"]}]},
{"no": 25, "corp": "笑顔グループ", "name": "松永 平太", "role": "", "star": 2, "head": "南房総で“いい人生”を形つくれるところ", "prof": "1992年に東京医科歯科大学（現：東京科学大学）卒業。みさと健和病院、柳原病院等で働いたのち、1997年に父の診療所を継承。2000年に介護保険制度施行にあわせ有限会社ハイピースにて訪問看護・介護ステーションそよかぜを創設。2001年に医療法人社団優和会創設。2002年デイサービスセンターあそぼを創設後、2005年社会福祉法人おかげさまを創設。その後、老人保健施設夢くらぶ、夢ほーむ、認知症対応型デイサービスおかげさまを創設し、2009年に松永醫院をリニューアルオープンする。2023年には看護小規模多機能居宅介護にこにこを創設、2024年に地域包括支援センターえがおを創設する。", "url": "http://egao-group.jp/", "photo": "assets/photos/post-4053_t.jpg", "hero": "assets/photos/post-4053_h.jpg", "secs": [{"h": "南房総で“いい人生”を形つくれるところ", "ps": ["潮騒が子守唄のように響く千倉のまち。そこで笑顔グループを率いる松永平太理事長は、「人が笑い、食べ、愛され続ける時間を最後の瞬間まで延ばすこと」を使命に掲げる。白い病室に押し込められがちな最期を、ありのままの暮らしの延長に引き戻す。その挑戦が、地域にひとつの“生のモデル”を芽生えさせた。", "医療法人社団優和会、社会福祉法人おかげさま、有限会社ハイピース。およそ200名の仲間が「その人らしく地域で生きる」を支えている。たとえ認知症があっても、独居であっても、本人が望む生き方を支える自己決定の尊重をよりどころとしている。", "松永は、内科を軸に全身を診る総合医でありながら、命の灯火（ともしび）を最後まで見守る介護福祉の専門家としても活躍している、稀有な存在だ。"], "imgs": ["assets/photos/post-4053_b1.jpg"]}, {"h": "命を支える仕組みごとデザインする", "ps": ["父親が医師、母親が看護師という医療者夫婦の次男として生まれた松永。α、β、γのベータからとって平太と名付けられた。1992年に東京医科歯科大学（現：東京科学大学）を卒業後、下町の病院にて勤務し、現場で地域医療を学んだ。1997年、同じ医師として地域の医療に貢献していた父が急逝したとき、当初は閉院するつもりだったという。しかし、父が診ていた患者、そして父を長年支えてきたスタッフの姿を目の当たりにしたとき、そんな気持ちが吹っ飛んでしまった、と松永は語る。", "継承した診療所を、地域包括ケアの砦へと改装した。2000年に訪問看護・介護ステーションそよかぜ、翌年に医療法人社団優和会を設立し、その後デイサービスあそぼ、老人保健施設夢くらぶ、夢ほーむなど、次々と介護施設を展開する。", "彼が拡げる輪は医療に留まらない。「命を支える仕組みごとデザインする」その思いが、医療・介護・福祉の垣根を溶かし、住民同士が寄り添い支えあう風土を目指す。"], "imgs": ["assets/photos/post-4053_b2.jpg"]}, {"h": "生き切る設計図", "ps": ["大切な人生の最期、どこで過ごしたいですか？ 心臓が止まったらどうします？心臓マッサージを希望しますか？ 食べられなくなったらどうします？経管栄養を希望しますか？", "「死」そのものを避けずに語ることで、むしろ“どう生きるか”が鮮明になる…松永はそう説く。問いの答えをもとに、在宅・施設・病院を編み合わせた柔らかなケアプランを描き、一人ひとりの“生き切る設計図”を形にしていく。", "松永は、人生を全うし納得のいく最期を迎える医療こそが真の姿だと喝破する。「よく、ぽっくり死にたいと言うじゃないですか。たしかにこの世の中の全員がそんな感じで一生を終えられたらいいですが、だいたいは全員ぽっくり…とはいかないものです。だからこそ私は一人ひとりに、先ほどの3つの質問をします。話し始めると、だんだんと、より生に対する輪郭がはっきりとする。必ず納得して、生き切ってほしいんです」"], "imgs": ["assets/photos/post-4053_b3.jpg"]}, {"h": "幸せは配るほど大きくなる", "ps": ["松永が目指すのは、単なる延命ではない。患者がいい人生だったと振り返り、この先生に診てもらってよかったと思ってくれる、その瞬間のために医療従事者は心血を注ぐべきだと語る。", "生の三徴候とは、笑うこと、食べること、愛されること。世界一長寿日本の25年未来をいく南房総で、その人らしく生き切ることができる理想の高齢者ケアが広がる地域を目指す。南房総から放たれたこのメッセージは、やがて日本各地の未来図を塗り替える灯となるだろう。", "松永の視線は医療の枠を超え、地域全体へと広がっている。南房総の喫緊の課題である少子化を憂い、「命の産業」を「第四次産業」と位置づける。そこには、金銭的価値の先にある命、元気、幸せへの貢献という、崇高な理念が息づく。そして、消え行く地方が100年未来にも生き続ける鍵は10次産業。つくって、加工して、サービスする6次産業に命の産業である第四次産業を加えることである。たとえばヘルスツーリズムなどがある。そんな新たな価値観の創造に、彼の情熱が注がれている。"], "imgs": ["assets/photos/post-4053_b4.jpg"]}]},
{"no": 26, "corp": "テクニカルワークス", "name": "杉田 大", "role": "", "star": 2, "head": "四街道市のカスタムパーツ専門メーカー", "prof": "1980年、東京都出身。高校中退後、製造・溶接業の現場で経験を積みつつ、自らの興味でCAD/CAMや工作機械の技術を習得。20代半ばより車・バイク部品の製造を手がけ、20年以上にわたり、設計から製作まで一貫対応するエンジニアとして活躍している。", "url": "https://technical-works.jp/", "photo": "assets/photos/post-4066_t.jpg", "hero": "assets/photos/post-4066_h.jpg", "secs": [{"h": "四街道市のカスタムパーツ専門メーカー", "ps": ["千葉県北西部の住宅街を抜けると、鉄と油の匂いがわずかに漂う小さな工場に行き当たる。看板には「Technical Works」の文字。オートバイや四輪の金属部品を一気通貫で設計・製造している会社である。他社に真似できない高い技術と豊富な経験を基に、基本整備、修理から高度なチューニングまで対応が可能だ。", "テクニカルワークス代表の杉田大（すぎたまさる）が工作機械の切削音を背に「やっぱインチキははしたくないし、ハッタリや嘘もつかないように心がけています」と言い切る様子は、職人というより修行僧の風格すら漂う。"], "imgs": ["assets/photos/post-4066_b1.jpg"]}, {"h": "独学で積み重ねてきた技術と誇り", "ps": ["創業は2004年、と登記の上ではそう記されるが、実の年月はもっと深い。杉田は1980年生まれ。高校を約2週間で辞め、工場で働きながら溶接と切削を覚えた。20代半ばで旋盤を買い、30代でNC旋盤とマシニングセンターを導入。CADやCAMも独学で身につけ、気づけば二十余年、金属と向き合い続けてきた。「好きなバイクでサーキットを走っているうちに、手に入らないパーツは自分で作ればいいや、と思って始めたのがきっかけでしたね」", "コツコツ積み重ねた研鑽は、いつしか誰にも真似できない類まれなる技術となって、削り出した部品や溶接などに伝わって成果として現れる。あなたのパーツを積んだマシンが各ショーで優勝した、対応していただいたおかげでタイムが良くなった…表彰台で輝くマシンを遠巻きに眺めながら、杉田さんはこぶしを握りしめる。OEM供給だから社名はほぼ出ない。それでも、自分が削り出したりした部品やバイクが風を切り、タイムを縮めたり、楽しんでもらえたら。そう思うだけで胸が熱くなる。以来、“表には出ない誇り”こそ会社の礎となった。"], "imgs": ["assets/photos/post-4066_b2.jpg"]}, {"h": "「他社でできないモノこそ」", "ps": ["旋盤2台、フライス盤3台、マシニング2台、溶接機、治工具など。工房にはプロトタイプ開発を一人で完結できる機械が並ぶ。要望があればミルシートなどを付けたり、材料や処理、加工工程など聞かれれば丁寧に答えるようにしているという。「正直者がバカを見ない」ためだと杉田は語る。", "「他社で出来ないと断られたんです、何とかなりませんか？という依頼が来ることがよくありますが、そういうときは特にやる気になりますね」と言うその言葉どおり、依頼主が北海道でも沖縄でも、部品が届けば即座に杉田は加工プランを提案して対応する。リピーター率が高いのは、そんな負けず嫌いの気質ゆえかもしれない。", "もちろん、順風満帆とはいかないこともある。機械が壊れれば修理費は数十万はくだらない。狭いながらも何台もの機械があり、維持するだけでもかなりのランニングコストがかかる。落胆もつかの間、翌朝には復旧プランを練り、さらに高精度の治具を考えている自分に気づく。失敗しても「次はどう挽回するか」という材料になり、寸暇を惜しんで工具を研ぐ日々が続く。"], "imgs": ["assets/photos/post-4066_b3.jpg"]}, {"h": "やってみなきゃ始まらない", "ps": ["これからの目標は、さらなる品質向上とブランド力の確立だと杉田は語る。「お客様が“これ、テクニカルワークス製だぜ”、と誇ってもらえるような部品を更に増やしたいですね」", "最後に、これから飛び込んでくる世代をどう見ているか尋ねた。「たとえ失敗しても、損しても、やはり自分でやってみなきゃ始まらない。今日がマイナスでもプラスにしてやるぜ！みたいな覚悟があれば、道は開けると思います」", "静かな工房で今日も切削音や溶接音がリズムを刻む。言葉は朴訥でも、出来上がったパーツの輝きや装着されたバイクの佇まいがその真意を雄弁に物語っていた。"], "imgs": ["assets/photos/post-4066_b4.jpg"]}]},
{"no": 27, "corp": "メールセンター株式会社", "name": "有場 正人", "role": "代表取締役", "star": 2, "head": "柏市にあるDM発送のスペシャリスト", "prof": "1981年佐賀県立佐賀工業高等学校を卒業。同年に八雲製作所（本社：佐賀県）に入社。1985年佐川急便に入社、2005年株式会社KTSを複数名で立ち上げ専務取締役に就任。2011年メールセンター株式会社を設立、代表取締役、現在に至る。", "url": "https://mailcenter.co.jp", "photo": "assets/photos/post-4088_t.jpg", "hero": "assets/photos/post-4088_h.jpg", "secs": [{"h": "柏市にあるDM発送のスペシャリスト", "ps": ["東京に隣接しながら、歴史と文化の香りを残す千葉県柏市。縄文の貝塚に始まり、北原白秋や永井荷風ら文人が愛した街は、いまや再開発が進む都市と梨園の面影が共存する場となった。", "DM発送代行を手がける、メールセンター株式会社が、その街の一角にある。印刷から封入、郵便番号区分、結束、差出までを自社で一気通貫させる希少な現場だ。創業から10年以上が経過した今、約50名体制で、年間数千万通もの宛名をさばく。", "そんなメールセンター株式会社の現場に漂う空気は、どこか家庭的であたたかい。この空気をつくったのが代表取締役・有場正人だ。"], "imgs": ["assets/photos/post-4088_b1.jpg"]}, {"h": "「助け合いが当たり前の職場でありたい」", "ps": ["佐賀県生まれの彼は、男ばかり6人兄弟という賑やかな家に育った。「あまり裕福な暮らしはできなかったけれど、母はいつも笑っていましてね」そう語る表情には、幼い日を明るく照らした母の苦労への感謝がにじむ。", "18歳で上京。製造業、運送業と職を渡り歩き、40代でDM業界へ。やがて前職の社長に背中を押され、独立を志すことになる。", "しかし道は平坦ではなかった。共に立ち上げた先輩に裏切られ、受注の多くを失う痛恨の一撃を食らう。追い打ちをかけるようにコロナ禍で最大顧客が撤退した。"], "imgs": ["assets/photos/post-4088_b2.jpg"]}, {"h": "一視同仁", "ps": ["有場の経営哲学は「まず自分の体と家族を優先、最後に会社」というかたちだ。出勤時間はフレキシブルに設定が可能で、子どもの送り迎えをしてからの出社も構わない。昼下がりには決まって15分のリフレッシュタイムがある。コーヒーの香りが漂う休憩室で、社員たちは和気あいあいと談笑する。一視同仁…全員に同じ温度で向き合う座右の銘が、ここで生きている。", "そんなメールセンターの強みは、DMの一貫処理に加え、細かい作業への対応力にある。特に不動産関係のDMでは、マンション別に内容が異なる場合でも正確にマッチングさせる技術を持つ。過去には国勢調査の封入作業や、同じ種類のトレーディングカードが偏って入ってしまわないようにランダムに封入する作業など、高度なマッチング技術を要する仕事も請け負ってきた。"], "imgs": ["assets/photos/post-4088_b3.jpg"]}, {"h": "困っていたらまず手を差し伸べる", "ps": ["来月には「従業員の肩と腰を守る投資」として新型封入封函機が導入される。年間売上10億円の目標は、その先にある働きやすさの裏返しだという。早朝にひとり現場を整える姿は、黙して語らぬリーダーシップそのものだが、仕事が楽しいから、と本人は照れ笑いを見せる。", "「人を裏切ることはしません。困っていたらまず手を差し伸べるようにしています。それが回り回って、いつしか必ず自分を救うことにつながりますから」", "DMを載せたトラックが今日も郵便局へ走り出す。メールセンター株式会社は、千葉の片隅から“約束を守る”という手紙を届け続ける。"], "imgs": ["assets/photos/post-4088_b4.jpg"]}]},
{"no": 28, "corp": "株式会社柏斎苑", "name": "小林 裕応", "role": "代表取締役", "star": 3, "head": "「さよなら」を「ありがとう」に変える会社", "prof": "2012年日本大学卒、株式会社柏斎苑入社。2016年株式会社柏斎苑取締役就任。2016年一級葬祭ディレクター資格取得。2021年一般社団法人こもれびの和設立。2022年株式会社柏斎苑代表取締役就任。2023年柏ライオンズクラブ会長拝命。", "url": "https://www.kashiwasaien.com/", "photo": "assets/photos/post-54_t.jpg", "hero": "assets/photos/post-54_h.jpg", "secs": [{"h": "「さよなら」を「ありがとう」に変える会社", "ps": ["株式会社柏斎苑は、千葉県柏市を中心に、葬祭業や身元保証事業をはじめとしたライフエンディングサポートに特化した事業を多角的に展開している。", "「人と人とのつながりをもって、ご利用者の「さよなら」を「ありがとう」に変えていきたい。そのために、社員一人ひとりの長所を磨き上げています。 特に葬祭事業部では、Googleレビューやお客様アンケートでも高い平均点を誇っています。その理由はまさに人が創りだす「親切さ」や「迅速さ」であり、当社の最大の特徴です。」", "また生活支援サービス、高齢者の施設紹介、空き家の買取再販、霊園事業など、ライフイベントにまつわる事業を多数展開。葬儀会社の枠に留まらず、遺族会を通じて地域の方の終活をワンストップで支えている企業だ。"], "imgs": ["assets/photos/post-54_b1.jpg"]}, {"h": "「社員の笑顔を守りたい」二代目の覚悟と戦略", "ps": ["柏市は、創業者である小林代表の父が学生時代から過ごしている街だ。株式会社柏斎苑は創業当時の「地元に貢献できる場所で事業がしたい」という想いを今も変わらず大切にしている。それは、育ててもらった地に事業を通じて恩返しをするという父の意志が原点にあるからだ。", "代表取締役を父から受け継ぎ、登記簿に載る自分の名前を見た小林代表。そのときに浮かんだのは、柏斎苑を父とともに支えてくれていた社員の笑顔だった。そして同時に「社員みんなの笑顔をどのように守ったらよいのか」という恐怖を感じたという。 そこで、経営者としての勉強をゼロから始めなければならないと覚悟した小林代表は、1年間のビジネススクールを通じて徹底的に自分を変え、後継経営者としての心の在り方を修得した。", "そして、代表に就任してまず着手したことは葬儀事業に関わる周辺事業の展開だった。霊園事業、高齢者施設紹介事業、空き家の買取再販事業を展開し、葬儀事業の依存からの脱却を図ったのである。また社外研修や社内の学習ツールを手厚くすることで、社員全員の人間的な成長につながるような学びの環境を構築するなど人財育成にも力を注いだ。"], "imgs": ["assets/photos/post-54_b2.jpg"]}, {"h": "理念は必ず行動に。柏斎苑の「見える化」戦略とは", "ps": ["株式会社柏斎苑において最も大切にしていることは「理念経営」だ。 なぜ重要なのか。それは自社がどのような価値観を大切にし、事業を進めているのかという認識を共有する日々があってこそ、自らを信じ行動に変えていけるという確固たる意志を持っているからだ。", "ただ、その理念は社員の人格を高めるためのものでなければ淘汰されてしまう、と小林代表は語る。 だからこそ株式会社柏斎苑は「ありがとう」を送り合う姿勢を大切にしている。さらに、その姿勢がわかる行動をアプリを通じて見える化したり、毎月の社内表彰で共有したりすることで理念を社内全体に浸透させる仕組みを構築しているのだ。"], "imgs": ["assets/photos/post-54_b3.jpg"]}, {"h": "「それなり」から「なくてはならない」存在へ", "ps": ["今最も注力していることは、空き家の有効活用と遺族会支援事業だと、小林代表は語る。", "空き家の増加が社会問題として懸念されている昨今、不動産の所有者変更の手続きも義務化され、近年は社会的な解決に向け取り組みが加速している傾向にある。また同時に核家族化が進み、子が別世帯を持つという時代の流れも顕著に感じているのだという。 そこで、お客様の両親が残した自宅をリノベーションし、空き家だった場所に新しい住民を招くことで、地域に活気をもたらしていく。今後はこの空き家の買取再販事業を第二の主力事業として注力していくつもりだ。", "またこの核家族化は、遺された高齢者のコミュニティ形成にも強く影響している。「家族が遠方に住んでいるなどの理由で、誰とも会話しないまま1日が終わってしまうこともあると伺っております。」と小林代表は神妙な面持ちでことばを紡ぐ。 そこで、同じ悩みや苦しみを抱える方々のコミュニティ形成の一助になるべく「遺族談話会 こもれびの会」を継続的に開催。このように、株式会社柏斎苑はグリーフケアについての体系的理解や実学の習得を優先的な課題に据えているのだ。"], "imgs": ["assets/photos/post-54_b4.jpg"]}]},
{"no": 29, "corp": "アイコミュニケーションズ株式会社", "name": "布留川 剛仁", "role": "代表取締役", "star": 2, "head": "再生可能エネルギー普及を目指す風雲児！", "prof": "商業高校卒業後、東京電力ホールディングス株式会社に入社。2010年、アイコミュニケーションズ株式会社専務取締役に就任。2021年、同社代表取締役に就任。現在に至る。", "url": "https://ai-comm.net/", "photo": "assets/photos/post-64_t.jpg", "hero": "assets/photos/post-64_h.jpg", "secs": [{"h": "再生可能エネルギー普及を目指す風雲児！", "ps": ["千葉市稲毛区にあるアイコミュニケーションズ株式会社は、2006年に設立された会社だ。「再生可能エネルギーの普及」に向け、太陽光や蓄電池、そしてEVなどの大容量バッテリーから家庭電力として給電するシステム：V2Hといったさまざまな商品・サービスの営業および設計、施工、保守を行っている。"], "imgs": []}, {"h": "電力の“当たり前”の概念を破壊する存在との出会い", "ps": ["アイコミュニケーションズ株式会社は、当初はその名の通り通信・OA機器やPCネットワーク構築などの通信系の専門会社として2006年に設立されたのがはじまりだ。現在の主力事業の一つとなるエコキュートの施工請負事業を開始したのは2010年、布留川代表がアイコミュニケーションズ株式会社に取締役として入社し新規事業として立ち上げる。", "元々は東京電力で12年もの間、電力マンとして働いていた布留川代表。巨大な組織の中でやってきた仕事は、基本的に「マイナスを0にする仕事」だったと語る。電力がなければ経済は停止するため、絶対に止めてはならない。電力が当然に供給される状態、つまり「0の状態」を維持することが求められていた布留川代表は日々奮闘していた。", "2010年ごろから、太陽光などの再生可能エネルギーの存在と投資の必要性を感じていたという布留川代表。しかし、大きな組織において攻めの仕事をしていくことの難しさも同時に感じた。そこで、下方硬直的な電力マーケットでのベンチャー企業的な動きを活発化させていく必要性を見出すことになるが、リスクは一切感じなかったという。それは蓄電池という存在を知っていたからだ。"], "imgs": ["assets/photos/post-64_b1.jpg", "assets/photos/post-64_b2.jpg"]}, {"h": "「電気工事会社」であることの強み", "ps": ["現在アイコミュニケーションズ株式会社は電気工事業を中心に、太陽光発電、蓄電池、V2Hなどを主力商品として住宅設備の販売や保守。直近では大企業とタッグを組み、なんとブロックチェーン関連技術の利用による系統マイニング事業を計画中、日本の電力インフラに根幹から携わっていくという。", "そんなアイコミュニケーションズ株式会社の最大の強みは「電気工事会社であること」にほかならないと布留川代表は語る。かつて電気工事業は「３Ｋ（きつい、汚い、危険）」とされ、就職先として避けられていた業界だった。しかし最近の人工知能の発展により知的労働が削減されている現状を鑑みると、電気工事業がもたらす「リアルな仕事の価値」が明確になる。つまり単に「ブルーカラーとして稼ぐ」というだけではなく、実際に目の前で成果を見ることができる仕事を通じて、論理的思考、チームマネジメント、マーケティング、財務といったスキルを日々学べる環境が整っているという。", "また、この業界は社会の課題を解決し、未来を形作る強みを持っている。日々の業務を通じて、時に逆境に遭遇することもあるが、そのような状況を乗り越えることで人は成長し、進化する。脳に刺激を与え五感を働かせることで、人々を進化させていくことこそが、電気工事業の最大の強みであり、優位性であると考えていると布留川代表は語る。"], "imgs": ["assets/photos/post-64_b3.jpg"]}, {"h": "事業が成功する秘訣は「思考の順番」", "ps": ["私自身は弱い人間です、とつぶやく布留川代表。入社当時は再生可能エネルギーに熱意を持って挑戦したが、現実は厳しく、苦労する日々だったという。その中で「信用」と「継続は力なり」という原則の重要性を学んだ代表は、当初数千万円だった年商をいかにして1億円超えに導くか試行錯誤の末、「ヒト⇒モノ⇒カネ」という思考の順番に基づく商品開発とマーケティングを進めることが成功への鍵だと気付いた。", "「たとえば、スタッフがノンストレスで働ける環境を作ることが現場の作業をスムーズにし、良い結果をもたらし、リピート顧客を獲得します。関わる全ての人が喜ぶ商品を提供することで自然と売り上げや評判が上がるということを経験してきました。お客様に対しても同様で「お客様が必要と感じている商品である、太陽光や蓄電池やV2Hは高価でちょっと不安、だからリーズナブルで安心して購入できるようにする」私たちはまだ完璧な成果を出してはいませんが、事業が成功するために最も重要なことは「ヒト⇒モノ⇒カネ」の思考の順序を大切にすることだと確信しています。」と布留川代表は語る。"], "imgs": ["assets/photos/post-64_b4.jpg"]}, {"h": "日本国内のさらなる普及を目指して", "ps": ["今後も「再生可能エネルギーの普及」を目標に取り組みを続けるアイコミュニケーションズ株式会社。資源の乏しい日本だからこそ最適な組み合わせを通じて持続可能な社会への展開をお手伝いしていくことが、会社の発展・成長に寄与すると信じ、「本当の再生可能エネルギーは人である」という想いを胸に今日も布留川代表は事業を進めていく。"], "imgs": []}]},
{"no": 30, "corp": "THE BONDSビーチSPAリゾートグランピング千葉御宿", "name": "生方 孝幸", "role": "代表取締役", "star": 3, "head": "御宿にたたずむ日本初のグランピングエリア", "prof": "1999年、明治大学卒。マーケティングや飲食、出版社等様々な業種を経て、東京都港区の不動産総合ディベロッパー会社にてマンションやオフィス、ホテル等多数の開発を行う。2019年、ブランニューアセット株式会社代表取締役就任。2021年、THE BONDSリゾートグループとして「THE BONDSビーチSPAリゾートグランピング」開業。2022年「THE BONDSオーシャンプライベートヴィラ-千葉いすみ-」開業。2024年3月「THE BONDS SPA オーシャンプライベートヴィラ-千葉白浜-」開業予定。", "url": "https://www.glamping-chibaisumi.com/", "photo": "assets/photos/post-41_t.jpg", "hero": "assets/photos/post-41_h.jpg", "secs": [{"h": "御宿にたたずむ日本初のグランピングエリア", "ps": ["千葉県夷隅郡御宿町。美しい海の景色・雄大な山の自然を同時に堪能でき、都会の生活に疲れた老若男女がゆったりとしたひとときを過ごすことができるリフレッシュスポットとして有名だ。", "海に沿って立ち並ぶ大小様々なリゾート施設のなかで、ひときわ別世界の空間を醸し出しているグランピング施設がある。", "「THE BONDS ビーチSPAリゾートグランピング 千葉御宿」。グランピングでは日本初となる雲海に浮かぶ4棟のドーム型テントと、オーシャンビューが一望できるTHE BONDSビーチハウスからなるアウトドアリゾート施設だ。グランピングではテントサウナやプライベートジャグジー、貸切温泉「御宿温泉」など充実した設備を楽しめるのはもちろん、御宿海水浴場から徒歩1分という好立地にあるため、サーフィンやフィッシングの拠点としても活用できる。"], "imgs": ["assets/photos/post-41_b1.jpg"]}, {"h": "育ててくれた地へ、恩返しがしたくて", "ps": ["生方氏は大学卒業後、さまざまな職業を経て都内の不動産総合ディベロッパー会社に就職。マンションやオフィス、ホテルといった大規模な不動産開発を多数手掛ける。その後THE BONDSリゾートグループの基となる不動産総合ディベロッパー会社、ブランニューアセット株式会社（Brand U Asset.inc）を千葉県に設立。これまでの実績を基にその土地、環境、自然に適したモノづくりを心がけながら、事業に取り組んでいる。", "元々生まれも育ちも千葉県だという生方氏は、ずっと千葉に恩返しがしたいという気持ちを持っていたという。", "「千葉は都心エリアにも近い上に他県にも負けないほどの綺麗な海、そして山の自然がたくさんあります。僕は特に生まれ育った千葉県の綺麗な海を感じることが好きでした。だから社会人として働き始めてから、育んでくれた千葉県へ恩返しができる仕事がしたいと思うようになってきたんですよね。"], "imgs": ["assets/photos/post-41_b2.jpg"]}, {"h": "どんなことにも「人」が関わっている", "ps": ["そして地域の農業や漁業者との連携や、ゴミ拾い等のクリーン活動など、一見事業とは大きく関係のない地域の活動にも生方氏は力を注いでいるという。", "「もちろん千葉に恩返しをしたいからという気持ちもありますが、私はどんな事業、果てはどんなこともすべて「人」によって成り立っていると信じています。そう考えるとゴミ拾いだって、我々の事業に大きく関わっていると思いませんか。」生方氏はそう熱く語った。"], "imgs": ["assets/photos/post-41_b3.jpg"]}, {"h": "THE BONDSリゾートグループで実現させる理想郷", "ps": ["2021年には「THE BONDSビーチSPAリゾートグランピング」を開業。翌年2022年には「THE BONDSオーシャンプライベートヴィラ-千葉いすみ-」を開業。さらに2024年3月には「THE BONDS SPA オーシャンプライベートヴィラ-千葉白浜-」の開業を予定している。", "今後もさらなる施設の拡大とサービスの充実を図っていくTHE BONDSリゾートグループ。生方氏は不動産という唯一無二のその立地特性の資源を最大限に活用し、徹底的なマーケティングをすることで、他にはない独自の魅力をもったオンリーワンの癒やしを提供していくという。", "「会社・事業などすべては「人」で成り立っています。都度目標はあり、状況も日々刻々と変化しますが、これからも自然や地域を尊び、関わる人との調和を大切にし続けることで、それらが結果として会社や事業の継続・発展、この千葉の魅力が最大限感じられる理想のリゾートの実現につながると信じています。」"], "imgs": ["assets/photos/post-41_b4.jpg"]}]},
{"no": 31, "corp": "株式会社TuberVision", "name": "工藤 淳", "role": "", "star": 3, "head": "管工業界の革命児", "prof": "配管工事会社にて22年勤務し、そこで設計や施工管理技術を学ぶ。43歳で退職し株式会社TuberVisionを設立。現在に至る。", "url": "https://tubervision.co.jp/", "photo": "assets/photos/post-62_t.jpg", "hero": "assets/photos/post-62_h.jpg", "secs": [{"h": "管工業界の革命児", "ps": ["株式会社TuberVision。千葉県市原市にあるこの会社では、さまざまな建設現場における管工事の設計から施工までを手掛けている。着目すべきは彼らの扱う革新的な技術だ。3Dレーザースキャナーで現場の空間を迅速に3Dスキャンし、そのデータを即座にPCに取り込む。そして、「3Dシームレス方式」と名付けられた独自の設計手法を用いることで、3D点群データの段階から設計を行う。この方法により、従来の工法に比べて圧倒的な速度と精度で、ズレのない正確無比の設計図を作成し、実用化している。", "「私の地元の市原市は京葉工業地域の中心ということもあり、我々の長所が最大限活用できる土地だと考えています。2018年に創業したばかりですから、これからさらに我々が実績を重ねていくにあたって、これ以上ない最適な舞台です。」そう朗らかに語る工藤代表。業界が注目している新進気鋭の会社が臨む景色を追ってみた。"], "imgs": ["assets/photos/post-62_b1.jpg"]}, {"h": "現場の悩みをすべて解決！3DCADとの出会い", "ps": ["配管工事会社にて22年勤務し、そこで設計や施工管理技術など工事に関わる多くを体得した工藤代表。43歳で退職し、2018年に株式会社TuberVisionを設立した。独立に至るまでのその道のりは決して順風満帆なものではなかったという。", "「若いころはロックバンドで食っていこうと思っていて、ベーシストとして活動していた時期がありました。縁あって本場アメリカに音楽を見に行ったときのことです。当時シアトルのブロードウェイでは、週末になると多くのオープンカフェがライブハウスに早変わりするんです。", "ダウンタウンからブロードウェイにバスで向かう途中で、バンドマンたちが、楽器をケースにも入れずに同じバスに乗り込んできたんですが、バスの中で音を出し始めるんです。その人達がバスから降り、店に走って行ったと思ったら、ジャックをアンプにつないでそのまま演奏し始めるんですよ。そのときに聞いた1音目で、なんだか自分の小ささを感じてしまって、心が折れちゃったんですね。こりゃダメだ勝てない、と思ってすぐ帰国しました。」と語る工藤代表。本場のスケールに圧倒され失意のなか帰国し、母の知り合いから紹介されたのが、管工事の仕事だったという。"], "imgs": ["assets/photos/post-62_b2.jpg", "assets/photos/post-62_b3.jpg"]}, {"h": "「スムーズに行き過ぎて逆に怖い」現場も驚くその技術", "ps": ["手作業での調査となると精度が低くなり間違いも多く発生し、それが設計に影響を与えてしまう。一度ズレたときの現場の損失は大きく、追加で調達する資材や工事のやり直しは珍しくなかった。工賃は追加で発生し、長時間労働による作業員のケガなども起こりやすかったという。", "しかし3Dスキャナーによるリアルキャプチャー技術を現場に導入すると、ミリ単位の現場情報が、より高精度、且つ短時間で入手することができる。必要最小限の資材と人員で、当初計画していた時間よりも格段に早く、そして正確に現場作業を完了することが可能となっている。まさに業界の革命とも言えるだろう。", "「正直業界では図面の信頼度は低く、あいまいな計画をしていることがほとんどでした。ところが、この技術を使って図面の信頼度が高まったことで、追加の資材購入や人員など無駄なコストの削減に貢献しています。3D技術に興味を示してくれたクライアントからは「信じられないほどスムーズだ、トラブルが起こらなすぎて逆に怖い」と言っていただいたこともありますね（笑）。」と工藤代表は語る。"], "imgs": []}, {"h": "「夢ではなく目標」自社工場設立と海外進出", "ps": ["業界で堅実な功績を刻んでいる株式会社TuberVision。目下の課題は会社規模の拡大だ。調査から設計、現場での施工までを一貫して請け負っている株式会社TuberVision、関東の枠を越え全国各地からの依頼が殺到しているという。より素早く柔軟な対応ができるよう、直近では自社工場の設立を目標にしているのだ。そして供給力が確保でき次第、関東各地、大阪、九州方面への積極的な進出を目指していると工藤代表は語る。", "「設計分野のみでいうと、海外案件でも対応させて頂いている状況です。東南アジアをはじめ、海外では日本よりも3D技術が浸透していると聞いています。今後、日本も負けないように積極的に実績を積んで、得た知見を日本で普及していきたいですね。」"], "imgs": ["assets/photos/post-62_b4.jpg"]}, {"h": "3Dスキャンで守る日本の美しさ", "ps": ["今後は今持っている技術を新しい分野で活用することを考えているという工藤代表。工事現場に留まらず、農業、林業、自然環境保護、さらには文化遺産の保護に至るまで、その活用範囲の拡大を模索、検討しているという。事実、千葉県長生郡の国指定重要文化財、笠森観音の3Dスキャン計測を行い、その3Dデータを保存することで地域社会に貢献してきた実績がある。", "とりわけ文化財に関しては手作業での計測が困難な状況に置かれているケースが多い。3Dスキャン技術で保存されたデータこそが社会貢献につながるのだ。", "さらに、同社は独自に開発した工法を習得した技術者を「3Dスペースコーディネーター®」と称し、これを商標登録している。現在この「3Dスペースコーディネーター®」の育成にも注力しているという株式会社TuberVision。今後のさらなる展開に期待したい。"], "imgs": ["assets/photos/post-62_b5.jpg"]}]},
{"no": 32, "corp": "株式会社Shu Electricity and Railway Consultant", "name": "小倉 秀文", "role": "", "star": 3, "head": "松戸が誇る世界規模で活躍中の鉄道コンサルティング会社", "prof": "東京電機大学大学院電気工学専攻博士課程（前期）修了。新卒で大手鉄道会社に入社、電気関係の設計・工事監理、設備保守等を経験した後、研究開発分野にてエネルギー有効活用に関する研究に従事。その後コンサルタント会社へ出向し、数件の円借款事業案件に参画。2019年11月に株式会社Shu Electricity and Railway Consultantを設立。現在は、海外の鉄道建設事業案件（数件）にサブコンサルタントとして従事するとともに電気関係事業の案件形成に携わっている。", "url": "http://shu-eandr-consul.co.jp/", "photo": "assets/photos/post-55_t.jpg", "hero": "assets/photos/post-55_h.jpg", "secs": [{"h": "松戸が誇る世界規模で活躍中の鉄道コンサルティング会社", "ps": ["株式会社Shu Electricity and Railway Consultantは松戸市を拠点としている世界規模で活躍しているコンサルティング会社だ。国内外の都市計画の要となる「鉄道」分野のコンサルティングに強みを持ち、スリランカやフィリピンといったさまざまな国家プロジェクトに日本技術の導入を実現する専門家として携わっている。", "日本で培った知見、そして技術に対する思いを胸に世界諸国を駆け回っている代表の小倉氏に話を伺った。"], "imgs": ["assets/photos/post-55_b1.jpg"]}, {"h": "「海外の技術者へ伝えたい」覚悟", "ps": ["大学院では電気工学を学んでいた傍ら、就職する以前から語学研修のために約1カ月アメリカに渡航したり、英会話に積極的に取り組むなど、海外交流や海外業務に興味を持っていた小倉代表。大手鉄道会社に入社後、現場の知見を積んだのち、海外案件を複数担当しているコンサルティング会社に出向する。当時担当していたのはJICA（国際協力機構）における海外コンサルティングの案件だったという。", "出向先の会社で働くうち「海外でコンサルタント事業を行う方が自分には向いている」と感じるようになった小倉代表は、「さらに自らの経験を海外の技術者へ伝えたい」という使命感、そして当時のプロジェクトマネージャーなどの誘いもあり、2019年に退職し株式会社Shu Electricity and Railway Consultantを設立、本格的に海外プロジェクトに参画することとなる。"], "imgs": []}, {"h": "重要なのは「誰にでもわかるように伝える」こと", "ps": ["海外でのプロジェクトではその国が今何を望んでいるのかを掴み、正確に形にすることを大事にしていると語る小倉代表。事業的な側面も踏まえて現実的に何ができるのか、どんな相手でもわかりやすく説明することが重要だと思って仕事に臨んでいるという。「コンサルタント業としては当たり前のことではあるものの、とくに文化の異なる方々と接することになる海外では、相手の意見を正しく理解できているかを非常に意識しています。」と小倉代表は語る。", "また、日本では新技術を活用した様々な実証がなされているが何らかの理由で導入できないでいる技術が多数存在する。それらの技術を海外に紹介し、対象国における課題を解決すると同時に事業可能性を検討している。", "鉄道事業としては、電気システムや鉄道運営に関わる内容を理解している日本人従事者が非常に少ない現実がある。小倉代表は、数少ない専門家の一人として活動しているのだ。"], "imgs": []}, {"h": "異国の自治体との共同プロジェクトとは", "ps": ["新しい事業としてAgri-Voltaic事業というビジネスも展開中だ。Agri-Voltaicとはある土地に太陽光発電と農業を同時に活用するという意味を指す。現在小倉代表は、フィリピン国において太陽光発電設置予定用地が農地としても活用できることをアピールしており、現地のLGU（Local Goverment Unit；フィリピン国における地方自治体）と導入に向けた協議を実施しているところだという。また、発電した電力をどのように活用するのかについても議論がなされており、電力ネットワークが脆弱なケースを想定した事業可能性を検討している。小倉代表は鉄道事業のコンサルタント事業だけでなく、新たな事業としてAgri-Voltaic事業展開を次の柱として取り組めるようにしたいと考えているという。"], "imgs": []}, {"h": "技術をその国が受け入れてくれるために", "ps": ["事業を行ううえで大切にしていることは、誰もがわかるような説明をすることだと小倉代表は語る。「私は技術者なのでどうしてもその分野における専門的な内容を議論することが多い環境下にあります。もちろん、技術者同士の議論はこれでよいと思っています。", "しかしその技術を広めようとする場合は、非常に難しいですがその内容を万人が理解できるようわかりやすく伝える必要があります。今後伝えていく私たちの技術を伝える相手が全員技術者というわけではないからです。」その国の誰もが受け入れてくれるような伝え方を心がけていくと語る小倉代表、そしてShu Electricity and Railway Consultantの今後に注目していきたい。"], "imgs": ["assets/photos/post-55_b2.jpg"]}]},
{"no": 33, "corp": "WORKS ZERO", "name": "澤田 岳典", "role": "", "star": 3, "head": "野田市が育てた万能型ガラスフィルム職人", "prof": "1977年、千葉県野田市(旧関宿町)に生まれる。2001年、東京国際大学を卒業。その後、設備メーカー、ビール会社、保険業界を経て2016年に窓ガラスフィルム施工「WORKS ZERO」を創業。2020年に建築ガラス用フィルム施工技能士１級を取得。アメリカ大使館、防衛庁、筑波大学等の公共施設をはじめオフィス、工場、商業施設、介護施設、個人宅など、今までに1000件以上の施工実績をもつ。", "url": "https://www.workszero.com", "photo": "assets/photos/post-75_t.jpg", "hero": "assets/photos/post-75_h.jpg", "secs": [{"h": "野田市が育てた万能型ガラスフィルム職人", "ps": ["千葉県の北西部・野田市を拠点に活動しているWORKS ZREOは窓ガラスフィルム専門の施工会社だ。澤田代表は生まれも育ちも野田市。故郷であるこの地を愛する現れとして、そのまま事業の拠点にしている。", "窓ガラスフィルム施工1級技能士の資格をはじめ、ゴンドラ・フルハーネス・足場組立作業…澤田代表が身につけている技術は計り知れない。", "帝国ホテル、防衛庁をはじめとした輝かしい実績を持っているWORKS ZREO。澤田代表はこの事業を1人でおこなっているというのだから驚きだ。今も現場に足を運んでおり、その数はなんと年間約200件。その仕事ぶりが認められ、地元の商工会から招聘され、高校生へ働くことについての講演もした経験もあるという。"], "imgs": ["assets/photos/post-75_b1.jpg"]}, {"h": "人生最大の危機をチャンスに変えた瞬間", "ps": ["前職は営業マンだった澤田代表。必死に仕事に取り組んでいたある日、なんの前触れもなく来たのが解雇通知の連絡だった。", "呆然とする時間もなく、このままではまずいと必死になって就職活動に取り組んだものの、内定をもらえない日々が続く。そんな折、窓ガラスのフィルムが災害や防犯の対策として非常に有効であるということを発見した。「これだ！と思いました。ちょうど東日本大震災、相模原の殺傷事件の後ということもあり、この一枚のフィルムが必ず世の中の役に立つと確信したんです。」", "そして2016年に独立。創業当時の一番の思い出は、意外にも仕事用の車についてだった。 開業資金もほとんどないなか、車だけはどうしても必要だった澤田代表。限られた予算でなんとか買える車を探し、当時なけなしのお金で手に入れたことを今でも思い出すという。「当時ネットオークションで買うのが一番安かったんです。ただ当時はトラブルも多かったので、購入先の方と連絡がとれなくなったらどうしようと思い、ずっとハラハラしていました。」"], "imgs": ["assets/photos/post-75_b2.jpg"]}, {"h": "価格や技術より大切なのは「正しいニーズの把握」", "ps": ["WORKS ZREOは「フィルム1枚で快適な空間のご提供」をモットーに、お客様がより過ごしやすい空間作りを実現している。 そのうえで大切にすることが「お客様のニーズを徹底して聞くこと」だという。", "ある日、エステのオーナーさんから「ここは女性が自分のごほうびの場所にしたいから、それに合うフィルムを貼って欲しい」と依頼があった。大切なのは「女性が自分のごほうびの場所にしたい」とは何か、どのようなニーズが隠れているのかを徹底して聞き出していくことであり、その作業が「フィルム1枚で快適な空間をご提供する」というモットーにつながるというのだ。", "一方で、お客様自身に商品を理解していただくこともより良い生活空間を提供するためには必要であると考え、窓ガラスフィルムの認知度や理解度をあげるために、SNSを活用した動画配信や、ビルオーナーや経営者へのプレゼンなどを精力的に行っている。"], "imgs": []}, {"h": "「三方良し」の精神で、目指すは海外進出", "ps": ["目下考えているのは事業の横展開だ。窓ガラスフィルムとの相乗効果が期待できる事業を調査し、どんどん取り入れていくつもりだ。", "そして長期目標として海外進出も視野に入れている。狙っているのは東南アジア。日本より暑く、そして台風も多い地域に、遮熱・災害対策として効果的な窓ガラスフィルムは必ず普及するはずだと澤田代表は語る。", "もちろん、地域へ貢献する姿勢はこれからも変わらない。近江商人の「売り手良し」「買い手良し」「世間良し」の「三方良し」をつねに意識し、お客様のもとへ足を運んでいる。"], "imgs": []}]},
{"no": 34, "corp": "山田食品株式会社", "name": "櫻井 健二", "role": "代表取締役社長", "star": 3, "head": "関東の麺処を支える老舗の製麺会社", "prof": "長野県出身。日本大学経済学部卒。1996年新日本証券株式会社（現みずほ証券株式会社）に入社。京都支店、IPOコンサル、投資銀行企画、社長秘書、人事部採用チームを経て、法人業務部副部長に。2022年5月山田食品株式会社に入社し、同年8月代表取締役社長に就任。", "url": "https://yamada-syokuhin.co.jp/", "photo": "assets/photos/post-34_t.jpg", "hero": "assets/photos/post-34_h.jpg", "secs": [{"h": "関東の麺処を支える老舗の製麺会社", "ps": ["山田食品株式会社は千葉県船橋市にある習志野駐屯地の近くに居を構える、主に生麺を中心に製造している老舗の食品会社だ。添加物を大量に加えた長期保存可能な麺ではなく、小麦本来の味が楽しめる生麺に特化した製造を行っているのが特徴で、地域密着の商圏で細かな顧客ニーズに対応している。", "7代目となる櫻井代表が背負う山田食品株式会社の100年の歴史、そして次の100年に向けた経営戦略とは。"], "imgs": ["assets/photos/post-34_b1.jpg"]}, {"h": "大手証券会社から第二のステップへ", "ps": ["櫻井代表が代表取締役に就任したのは2022年。それまでの26年間、サラリーマンとして大手証券会社に勤務していた。1996年に新卒で証券会社に入社、8年間は京都支店でリテール営業に従事し、本部に異動後はIPOコンサルティング、投資銀行業務の企画管理、社長秘書、新卒採用の統括、そして最終的には中堅上場企業のファイナンスやM&Aを手掛ける投資銀行ビジネスの企画部門の副部長に。結果的に証券会社時代の様々な経験が経営を行うための基礎になったという。", "そんな櫻井代表が山田食品株式会社と出会ったのは、今の奥様だという。「妻の実家が山田食品を経営していて、妻を通じて社長として力を貸してほしいと話が来たんです。当時48歳だった私は、50歳に近づいて第2の人生をどう歩むか考えていた最中でしたから、新しい場所で再出発したいと思って代表に就任したんです。もちろん前提としてラーメンが好きだからというのもありますが…（笑）。」と櫻井代表は語った。", "まだ就任して数年の櫻井代表だが、生産ラインにおける最新設備の導入や、社内勉強会を通じた働き方の意識改革の実施、そして社内チャットツールなどのDXの実施など、多岐に渡る社内整備を実行してきた。"], "imgs": ["assets/photos/post-34_b2.jpg", "assets/photos/post-34_b3.jpg"]}, {"h": "「なぜ100年続いたのか」たどり着いたシンプルな答え", "ps": ["山田食品株式会社は昭和3年（1928年）に、初代店主の山田石松氏が船橋市海神町で配給の小麦粉を委託して加工し、屋台用のワンタンを作ったことからその歴史は始まった。そして今年で97年を迎え、会社は次の100年を見据えるステップに突入する。これからの山田食品株式会社として、櫻井代表はこれからの会社方針を決めなければと思い、会社自体をさまざまな視点から紐解いていた。", "「なぜ山田食品という会社が100年も続けてこれたのか、それを言語化することが重要だと思いました。まずは100年ということで、老舗の多い京都の企業の特徴について研究したり、この会社の経営の流れなどを改めて調べてみたり…。ですが、そこから「これだ！」というものはなかなか見つからなかったんです。」と櫻井代表はことばを重ねた。", "「なんとなくですが、見えてきているのは」と続ける櫻井代表。「毎日、真面目に麺をつくってお客様に配達することを続けていたから。すごいシンプルですが…よくよく考えると、いろんな時代のなかで一貫しておこなっていたのがこれなんですよね。なにか複雑な戦略があったというわけでもなく、自分たちができる最大限を尽くして、各地に麺を届け続けてここまできたわけです。つまりひたすらにお客様にサービスを提供してきた実績そのものが、信頼となり今の会社を支え続けているのではないか、と思っています。」"], "imgs": ["assets/photos/post-34_b4.jpg"]}, {"h": "「人を育てるために」今求められている役割とは", "ps": ["もちろん新しいことにもどんどん挑戦している山田食品株式会社。自社製品のほか千葉にある取引先のスープやチャーシューなどを総合的に販売するECプラットフォームの構築や一般の方が購入できる直売所の運営、ラーメン屋独立開業コンサルティング、ラーメン研究家の石山勇人氏がプロデュースした「香麺（こうめん）」の開発など、食品会社の枠を越えたビジネスを多数展開している。", "そして何より櫻井代表が大切にしていきたいと語るのは、代表が言語化した山田食品株式会社の“使命”の落とし込みだ。", "山田食品のミッションは「日本の麺文化に貢献する」こと。そしてビジョンは「①船橋・千葉県に愛される会社 ②麺作りにこだわり、選ばれる会社 ③製麺のプロフェッショナルを輩出する会社 ④誇りを持って、楽しく、活き活きと働ける会社」だ。"], "imgs": ["assets/photos/post-34_b5.jpg"]}]},
{"no": 35, "corp": "株式会社エフディーきむら", "name": "木村 政照", "role": "代表取締役", "star": 3, "head": "千葉を代表する実力派フラワーショップ", "prof": "2002年、株式会社エフディーきむらに入社。数年の下積み・先代社長や先輩方から指導・教育を受け、2006年10月同社取締役に就任。花き業界の花に対する専門知識(花の生産者別の産地の特性や品質の目利き等)を学び、仕入れから業務全般のマニュアル化を進め社内の基盤を構築。2018年、代表取締役に就任。2019年、事業の一環としてフラワーデザインスクール花Laboを開講。2022年、葬儀会社 花葬～はなそう～を設立。", "url": "https://fd-kimura.com", "photo": "assets/photos/post-48_t.jpg", "hero": "assets/photos/post-48_h.jpg", "secs": [{"h": "千葉を代表する実力派フラワーショップ", "ps": ["株式会社エフディーきむらは、我孫子市と柏市に合計3店舗のフラワーショップを展開している。", "花キューピット主催「ジャパンカップ」南関東代表選手権で12回の優秀賞受賞、2度の花キューピット会長賞受賞など、数々の受賞歴を持つ同社は、花のデザイン技術力が卓越している企業として業界でも一目置かれている存在だ。", "現在も現場に立ち、お客様へ一級品のデザインを提供している木村代表に、これまでの歩みと今後の展開について詳しく話を聞いてみた。"], "imgs": ["assets/photos/post-48_b1.jpg"]}, {"h": "比類なき2代目の躍進", "ps": ["1968年に創業者である木村代表の父が創業したエフディーきむら。FDとは「フラワーデパート」の頭文字からとっており、我孫子市に本店を構えている。2002年に入社した木村代表は一人前になるべく父や先輩方から3年みっちりと指導を受け、2005年に取締役に就任。その後も産地の特性や品質の目利きといった花き業界の専門知識をひたむきに学んだ。", "その後2018年に代表取締役に就任。社内のシステム基盤の構築からはじまり、2019年には事業の一つとしてフラワーデザインスクール「花Labo」の開講、2022年には新規会社として葬儀会社「花葬」を設立するなど、とてつもない勢いで拡大を続けている。"], "imgs": ["assets/photos/post-48_b2.jpg"]}, {"h": "地域に貢献するために必要な「2つの視点」", "ps": ["「お客様が求めるものと提供できるサービスがしっかりと合致しているか、そしてプラスαの提案ができているか。この2つの視点があって初めて私たちの会社が社会に貢献できていると考えています。なので、くどくてもいいから毎日のように社員に伝え、常に会社全体でお客様目線を持ってサービスを提供するように意識しています。」と語る木村代表。", "より地元の人たちに必要とされる会社であり、地域に貢献できる会社を目指し、今日も世界で一つだけのフラワーデザインをつくっていく。"], "imgs": ["assets/photos/post-48_b3.jpg"]}]},
{"no": 36, "corp": "司興業株式会社", "name": "相澤 翔平", "role": "代表取締役", "star": 2, "head": "「当たり前」をつくる鎌ケ谷市のプロフェッショナル集団", "prof": "高校卒業後、司興業株式会社に入社。2015年、同社代表取締役に就任。", "url": "https://www.tsukasa-kougyo.com/", "photo": "assets/photos/post-30_t.jpg", "hero": "assets/photos/post-30_h.jpg", "secs": [{"h": "「当たり前」をつくる鎌ケ谷市のプロフェッショナル集団", "ps": ["千葉県鎌ヶ谷市にある司興業株式会社は、千葉県全域の水道整備を中心とした管工事を行っている会社だ。約10名で千葉の水道インフラを支えている、少数精鋭のプロフェッショナルチームである。", "代表の相澤氏は語る。「日本の水道普及率は98％です。そして日本の地下には地球18周分以上、約73万㎞の水道管が埋まっています。実はそのうち地球3周分以上の約13万㎞が既に耐用年数を超えている状態で、全ての管路を更新するのに130年以上かかるとも言われています。", "でも普通に生活していたら気をつけることもありませんよね。人々の生活を守る水道インフラ工事、蛇口をひねれば水が出るという当たり前を作る仕事を、私たちは誇りに思っています。」"], "imgs": ["assets/photos/post-30_b1.jpg"]}, {"h": "創業者から渡されたバトンを受け継いだ2代目", "ps": ["すでに20年以上の歴史を持つ司興業株式会社。相澤代表は2代目の代表取締役として会社を運営している。", "高校を卒業後、司興業株式会社に就職。仕事に対する真面目で勤勉な姿勢が評価され、次第に当時の創業者の右腕的存在となった。", "「ですが入社して10年が過ぎたころ、先代の創業者が亡くなってしまったんです。亡くなる直前、創業者から「会社を頼む」と言われたことがきっかけで2015年に代表取締役に就任しました。就任してからはすべてが大変になってしまいましたが、頼むと言われたからにはそのことば通りこの会社を守らないといけないじゃないですか。当時は自分ともう一人しかいない状況でしたが、必死になっていろんなことに挑戦して、ここまで大きくしてきた自負はあります。そしてこれからもその気持ちは変わらないですね。」と相澤代表はことばを重ねていた。"], "imgs": ["assets/photos/post-30_b2.jpg"]}, {"h": "司興業が考える「千葉ダントツの機動力・技術力・団結力」とは", "ps": ["昨年1月に新社屋に移転し、新しい地で千葉の水道インフラを支えている司興業株式会社。相澤代表がバトンを受け取ってからの司興業株式会社の勢いは凄まじい。代表に就任してから、現在の売上規模は先代の3倍を記録している。", "同業他社とくらべ20代の若手が多く、スピードとガッツはどの会社よりも負けないと相澤代表は語る。また他社に先駆けて、2016年から現場に電子黒板などを導入。常に現場の効率化に励んでいる。", "相澤代表は「使ったことがないから対応できない、という従来の慣習を重んじる役所との調整に苦労しましたね…。でもこういった技術を使えば、より効率的に施工が仕上げられるはずです。スピードとガッツ、そして最新技術の活用力で他社に負けない施工を心がけています。」と語った。"], "imgs": ["assets/photos/post-30_b3.jpg"]}, {"h": "よりライフラインの大切さを感じてほしい", "ps": ["今後はさらに事業を拡大していきたいと考えている相澤代表。水という人間にとって欠かせない存在に関わる仕事に、大きなやりがいを感じているという。", "「1月1日に能登半島で起きた大地震では、最大で約6.6万戸が断水していたと聞きます（総務省令和6年2月5日発表より）。水道のインフラ復旧は急務だったでしょう。こういう機会を通じて、改めて皆さんには水の大切さを感じてほしいと思います。", "そして少しでも我々のようなライフラインの仕事に就く人が増えればいいなと、そう感じています。」と相澤代表は語った。"], "imgs": ["assets/photos/post-30_b4.jpg"]}]},
{"no": 37, "corp": "東部重工業株式会社", "name": "豊永 健", "role": "", "star": 3, "head": "浦安の「つかむ」専門の会社って？", "prof": "大学院修士課程終了後電機メーカーに入社。特許事務所に転職し弁理士資格を取得後に独立。2018年に東部重工業に入社。", "url": "https://www.tobugrab.com/", "photo": "assets/photos/post-7_t.jpg", "hero": "assets/photos/post-7_h.jpg", "secs": [{"h": "浦安の「つかむ」専門の会社って？", "ps": ["東部重工業株式会社は、千葉県浦安市にある会社だ。グラブバケットやコイルリフターといった「つかむ」専門の産業用機械を製造、設置、販売している。本社から少し離れた海岸沿いには製品のテストを行うことができる大規模な生産工場があり、なんとサッカーコート約1面分の敷地面積を誇る。", "港や倉庫で石炭や木材チップなどのバラ積み貨物を移動させるときに活躍するグラブバケット。この造船所向け・港湾事業者向けのグラブバケットの完成品メーカーとして高い認知度を誇り、アフターサービスも充実していることから、60年以上にわたり国内外からの取引先から信頼され続けている存在だ。", "ニッチでビッグスケールな事業を展開している、東部重工業株式会社の今、そしてこれからについて聞いてみた。"], "imgs": ["assets/photos/post-7_b1.jpg"]}, {"h": "全社一丸となって目指す100年企業", "ps": ["東部重工業株式会社は、前身の会社の設立から60年の長きにわたりグラブバケットなどの荷役運搬機械を設計・製造・販売する事業を続けている。豊永社長は、先代社長とのつながりで2018年に入社してすぐに取締役に就任し、先代の体調不良もあり、入社半年後には副社長、その一年後には社長となった。", "副社長就任以降は、長い歴史で蓄積してきた「信頼」を維持し、さらに厚くしていくことを念頭に経営してきたと語る。現在は、全社一丸となって「100年続く企業」を目指し、さらに世界No.1のグラブバケットメーカーとなるべく、海外生産も視野に入れながら、生産力拡大・海外拡販に力を入れている。"], "imgs": ["assets/photos/post-7_b2.jpg"]}, {"h": "世界一のグラブバケットメーカーになるために", "ps": ["なによりも誠実であることを重視しているという豊永代表。「完成品メーカーとして、協力会社やお客様に誠実に対応しなければ、継続的に事業を行うことができないと考えています。」と語る。", "60周年を迎えた今、100年続く企業を目指している東部重工業株式会社。100年目の実現のためには従業員一人ひとりが自ら考え、環境の変化に対応していく必要があると考えており、現在は従業員教育に力を入れているという。そしてさらに外注先を拡大し、生産能力を拡大することで社内工場の余力を作り、より付加価値の高い業務に専念できる体制を構築中だ。", "世界でNo.1のグラブバケットメーカーとなるように、これからは海外生産に取り組み、また海外顧客との取引拡大も目指しているという東部重工業株式会社。自分たちの目標をつかみ獲るため、今日もお客様のもとに駆けつける。"], "imgs": ["assets/photos/post-7_b3.jpg"]}]},
{"no": 38, "corp": "コストコホールセールジャパン株式会社", "name": "", "role": "", "star": 3, "head": "“小売店”の概念を変える異次元の品揃え", "prof": "コストコのはじまりは1976年、カリフォルニア州サンディエゴにある飛行機の格納庫を改造して作られた「プライスクラブ」という名前の倉庫店でした。 1983年には「コストコ」の最初の倉庫店がワシントン州シアトルにオープン。 1993年には「コストコ」と「プライスクラブ」が合併し「プライスコストコ」となり、1997年にコストコカンパニーに社名変更。 1999年8月30日には、コストコホールセールコーポレーションに社名変更し米国のナスダックに上場しました。 コストコの本社はワシントン州イサクア、コストコジャパンの本社は千葉県木更津市。", "url": "https://www.costco.co.jp", "photo": "assets/photos/post-57_t.jpg", "hero": "assets/photos/post-57_h.jpg", "secs": [{"h": "“小売店”の概念を変える異次元の品揃え", "ps": ["コストコホールセールジャパン株式会社は、高品質な商品とサービスを低価格で提供することを理念に掲げている会員制倉庫店だ。本社のアメリカをはじめ、カナダ、オーストラリア、イギリス、そして日本など世界規模で875倉庫店を展開しており、会員数は全世界1億人以上、各倉庫店の取扱い商品は約3,500種類を誇る。", "装飾や広告活動などを極力行わずシンプルな経営を行うことで会員様に還元する経営スタイルが特長で、バイヤーが国内外から選び抜いた商品を取り扱い、常に会員様がわくわくするような新しい商品を提供している。", "また会員様に「宝探し」を楽しんでもらうために、商品の付加価値にも強いこだわりを持つ。例えば売場に並べられている精肉は飼育から輸送手段、カット方法に至るまで細かな工夫がいくつも施されており、一度も冷凍されていない良質な精肉を低価格で味わえるのが魅力だ。さらには調剤薬局やガスステーション*（ガソリンスタンド）、眼鏡・補聴器センターまで併設しており、世界中の小売店が追従できない総合サービスを提供している。そしてコストコの商品やサービスに万が一満足できない場合への保証として商品保証と年会費保証というシステムを設けていることは、コストコブランドでしか実現できない唯一無二の強みだ。*限定倉庫店のみ"], "imgs": ["assets/photos/post-57_b1.jpg", "assets/photos/post-57_b2.jpg"]}, {"h": "コロナ禍でも止まらない成長", "ps": ["コストコは1976年、カリフォルニア州で「プライスクラブ」としてスタートしたのが始まりだ。そして1983年に最初の「コストコ」倉庫店がワシントン州でオープン。1993年に「プライスクラブ」と合併し、後にコストコホールセールコーポレーションとなる。1998年4月には日本法人が設立され、1999年に福岡県に第一号店をオープンした。それから拡大を続け、今では日本国内で33倉庫店、アメリカ、カナダ、メキシコに次ぐ第4位の倉庫店数を誇る。", "日本との関わりも創業当初から深い。日本各地で自然災害が起これば、倉庫店の安全の確保はもちろんのこと、被災した人々と地域に寄り添い、迅速な物品支援を行うなど、その時にできる最大限の行動や支援をその都度行っている。どのような局面においても、いつでも迅速で的確に対応できる会社でありたいと、常に構え、備えているという。", "コロナ禍では、コストコにとっても大きな影響があった。まとめ買いの需要の高まりと在宅勤務の広がりにより、利用者動向が変化し、平日の来店が増加したのだ。特に水やキッチンペーパー、消毒液から家電やAV機器への需要が高まり、オンライン利用者も増加するという結果となった。"], "imgs": ["assets/photos/post-57_b3.jpg"]}, {"h": "木更津から見据えるジャパンマーケット戦略", "ps": ["従業員数が増え、更にコロナ感染防止対策として各従業員のソーシャルディスタンスを保つために、前拠点の川崎ではオフィスを3拠点に分割して運営していたコストコホールセールジャパン株式会社。実は業務効率を図るために自社ビルの本社計画は何年も前から行っていたという。", "新しい拠点には、前拠点の川崎から程遠くなく、倉庫店に併設することができる広大な土地があり、さらに全国/海外への出張も多くあるため交通の便も良いところという3つの条件が必要だった。そして見つけたすべての条件が揃っている土地が、木更津の町だったという。アクアラインを渡れば川崎、横浜、東京にも便が良く、2つのデポ（物流センター）の内の1つが市原市にあること、そして何より木更津倉庫店の横の土地を見つけられたため、移転を決行したのだ。", "木更津市を拠点にしたことの最大のメリットは、やはりアクアラインによる快適な通勤と富士山まで一望できる見晴らしのいい5階のカフェテリアだろう。また倉庫店出店数が県内最多の千葉県で、デポにも近い拠点に本社を構えることにより、運営面での効率化も図れている。また日本列島のほぼ中心部に位置しているため、今後のさらなる倉庫店の展開を目標としているコストコの拡大計画にも、木更津という土地は非常に有利に働いているという。"], "imgs": ["assets/photos/post-57_b4.jpg"]}]},
{"no": 39, "corp": "ジャパンフーズ株式会社", "name": "細井 富夫", "role": "代表取締役社長", "star": 3, "head": "長生郡にある国内屈指の飲料製造会社とは", "prof": "1980年4月、伊藤忠商事株式会社入社。2005年4月、同社欧州繊維グループ長（兼）伊藤忠イタリー会社社長就任。2007年4月、伊藤忠（中国）集団有限公司経営企画グループ長就任。2011年4月、ジャパンフーズ株式会社顧問就任。2011年4月、当社執行役員・CIO就任。2012年6月、当社取締役CFO就任。2013年4月、当社常務取締役就任。2015年6月、当社代表取締役社長（現任）。", "url": "https://www.japanfoods.co.jp/", "photo": "assets/photos/post-42_t.jpg", "hero": "assets/photos/post-42_h.jpg", "secs": [{"h": "長生郡にある国内屈指の飲料製造会社とは", "ps": ["千葉県長生郡長柄町に存在しているジャパンフーズ株式会社は、国内でも屈指の製造能力を誇る、飲料受託製造を基軸とした会社だ。", "各飲料メーカーから生産を受託し、ペットボトル・缶・びんなどの飲料製造（ペットボトルは容器から製造）を、調合、充填、検査、出荷までトータルに対応している受託製造事業、会員制ミネラルウォーター宅配サービスとしておいしい水をご自宅やオフィスにお届けしている水宅配事業、長年培ってきた飲料充填工場経営のノウハウを活かし中国での受託製造事業を展開している海外事業、そして「房総のおいしい水」や「千葉のおいしいお茶 房総（ふさ）みどり」など、千葉の恵みを届ける自社商品事業の4事業を展開している。", "「メーカーのさまざまな要望に対応できる最新鋭の生産設備や、安定して大量に生産できる供給体制、物流コストを最小限に抑えることができる抜群な工場立地…そして我々が長年培ってきた製造ノウハウ。このような会社を見つけるのは、なかなか難しいと思います。」"], "imgs": ["assets/photos/post-42_b1.jpg"]}, {"h": "上場は通過点。「誠実な企業」を目指すために", "ps": ["ジャパンフーズ株式会社は1976年、前身である日本飲料株式会社千葉工場の製造部門と販売部門とが分離され、1976年に製造部門が独立した形で設立。設立から2ヶ月後の1977年2月には日本飲料株式会社の社員と千葉工場の製造設備を受け継いだ形で、正式に業務を開始した。", "「ひとが第一」をスローガンに、多様な価値観、チャレンジ精神、チームワークを尊重し、人材の更なる活性化に向けた人的資本経営を推進。結果、2003年には東証二部、2005年には東証一部に上場を果たす（現在は東証スタンダード）。", "もちろん設備への投資も怠らない。2012年から2020年にわたり、総額220億円をかけて製造ラインを新たに4本増設し、クライアントからのどんな要望にも答えられるようにしている。"], "imgs": ["assets/photos/post-42_b2.jpg"]}, {"h": "サービスを支えているのはすべて「人」", "ps": ["現在、経済価値と社会価値を両立させた「100年企業」を目指しているジャパンフーズ株式会社。コア事業である飲料受託製造事業と新規事業（事業会社及び新ビジネス）の2つのセグメントでの持続的成長に注力している。", "また品質経営を全社を挙げて推進しており、製品・サービスと業務プロセスの品質向上に取り組んでいると語る細井代表。新製品の積極受注や新たな販売領域の創出を通じて収益を最大化し、財務体質の改善に努めているという。", "「しかしこれらをすべて支えているのは、実は無形資産（人的資本・技術・ノウハウ）なんです。うちはメーカーだからこそ、無形資産の拡充に向けた経営方針を第一に掲げています。」と語る細井代表。「ひとが第一」の考えのもと、これからもひとづくりに注力する。"], "imgs": ["assets/photos/post-42_b3.jpg"]}, {"h": "企業価値向上で、100年企業へ", "ps": ["千葉を拠点にしている理由は、豊かな自然環境を経営に活用できる点にあると語る細井代表。自然豊かな千葉の地で育まれた会社風土を大切にし、環境・人権に配慮したサステナビリティに関する課題に取り組みながら、今後も地域住民や町との深いつながりを大切にしていく方針だという。", "ジャパンフーズ株式会社は、これからも経済価値と社会価値を両立させた100年企業を目指し、現在の取り組みの継続に加えて、新規ビジネスの創出、そしてデジタル化推進によるジャパンフーズらしいスマート工場化を行い、企業価値向上に取り組む。"], "imgs": []}]},
{"no": 40, "corp": "エスポ化学株式会社", "name": "小林 晃樹", "role": "代表取締役", "star": 3, "head": "千葉の最先端都市に在る日本有数の「ニオイ対策」特化型企業", "prof": "1990年、中央大学卒。2019年、エスポ化学株式会社に入社。2019年、総務部長就任。2020年、取締役総務部長兼営業開発本部担当部長就任。2021年、常務取締役管理本部長就任。2022年。代表取締役就任（第5代目）", "url": "https://espo-chem.co.jp/", "photo": "assets/photos/post-23_t.jpg", "hero": "assets/photos/post-23_h.jpg", "secs": [{"h": "千葉の最先端都市に在る日本有数の「ニオイ対策」特化型企業", "ps": ["千葉市の最も西側にあり、幕張メッセやいなげの浜・多数の大学研究機関などが存在している千葉市美浜区。国際色豊かな都市機能と、ゆたかな住環境とを高度に融合させた未来型の都市として知られる。ここに、全国でも数少ない「ニオイのコンシェルジュ」として知られる会社が存在する。", "エスポ化学株式会社。ニオイ対策のオリジナルプロダクトの開発・販売から、クライアントごとに異なる臭気対策のコンサルティング業務までを幅広く手がける、まさに臭気対策のトップランナーだ。", "併設している開発研究ラボでは臭気の分析や、消臭剤の成分調整など行えるため、検収・納期を大幅に短縮できる一貫性が特徴で、日本のみならず海外にも複数のクライアントをもつ。"], "imgs": ["assets/photos/post-23_b1.jpg"]}, {"h": "風呂釜を改造して実験器具を自作していた創業期", "ps": ["1987年、故・小林暢生氏が大日本インキ化学工業株式会社（現DIC株式会社）在籍時に、両性高分子ポリマーをベースとした脱臭素材の開発に成功。その技術をもとに、暢生氏の弟である故・小林泰輔氏が創業したのがエスポ化学株式会社だった。社名のエスポ（ESPO）はEnvironment & Safety Protection Organizers（環境と安全を守り普及させる者）の頭文字をとって命名。これからニオイの業界の第一人者として全国を駆け抜けていくはずだった。", "しかし起業後僅か4ヵ月で、社内に衝撃が走る。初代代表の泰輔氏が急逝したのだ。その後、起業当初数年間は赤字経営という苦しい時代もあったものの、残された社員は初代代表の遺志を受け継ぎ、薬剤性能アップへのたゆまぬ研究・実験を続け、消臭脱臭総合コンサルタント企業として事業規模を広げながら現在に至っているという。", "「最初、社屋は創業者の自宅の一部を利用していたと聞いています。実験器具や製造器具も専門のものがないので、風呂釜を改良してお手製で作成したりと、大変な苦難の時代がありました…。長らく消臭剤の製造販売のみをおこなっていましたが、2020年には脱臭装置や臭気環境アセスメント業務に進出し、さらなる事業拡大に乗り出しました。そして昨年2023年には新社屋建設と、今この時期がまさに会社の転換期と言えると思います。」と小林代表は語った。"], "imgs": ["assets/photos/post-23_b2.jpg"]}, {"h": "代表就任後に着手した数々の「改革」", "ps": ["3代目代表であった父、小林俊弼氏はサラリーマンを定年退職後エスポ化学に営業開発部長として入社し、長らく会社を牽引されてきたという。しかし歳を重ね、両親から事業承継をたびたび打診されていた小林代表だが、当初は入社するつもりすらなかったという。「創業者の家系に生まれたわけでもないので、正直乗り気ではなかったんですよね。ただ、両親から色々と話を聞くうちにふと「今いる社員、そしてそのご家族はどうなるのか…？」と思ったんです。そして入社することで自分の残りの人生が少しでも誰かのためになるなら、と決心して入社したのがきっかけでした。」と、当時を懐かしみながら小林代表は語った。", "そして2022年11月、5代目として代表取締役に就任。翌年4月の新社屋設立もすでに決まっており、同社全体が大きな転換期を迎える節目も迫っていて、身の引き締まる思いだったという。しかし一方で、一社員として見た会社のあり方に疑問を感じる点も多々あったという。だからこそ、就任してからはリビルド（再構築）そしてレビュー（見直し）が最初の着手点に違いないと確信していた、と小林代表は語る。", "まずは社内におけるさまざまな申請業務（有給申請、出張申請、経費精算、営業報告など）をすべてオンライン上で済ませられるように、システムを新たに構築。そしてコロナ渦によりテレワーク業務なども増えていたため、勤務シフトのフレックス制度も採り入れた。"], "imgs": ["assets/photos/post-23_b3.jpg"]}, {"h": "「他人事ではない」小林代表が抱える“危機感”", "ps": ["実は創業37年目でありながら、エスポ化学株式会社はこれまでほとんど千葉の地元企業との接点がなかったという。しかしローカルコネクションの重要性を感じている今、千葉を拠点にする意義を考え、貢献できればと考えていると小林代表は語る。 「実は今、成田空港周辺の再開発など、千葉県では様々なビッグプロジェクトが始動しているんです。空港自体の環境はもちろん周辺のホテルの空気環境など、「居心地のいい千葉」「また訪れたくなる千葉」をめざし、どの程度か分かりませんが関われるチャンスがあればと思っています。」", "また一方で小林代表は、SDGsをはじめ世界規模での地球環境、生活環境の改善が叫ばれている中で、世間で本当に我々日本人も直面している問題だという認識があまりにも浸透していないことに危機感をつのらせている。「近隣からクレームが来たから臭気対策をしなくちゃいけない」「行政の指導があったので脱臭設備を導入しないといけなくなった」という消極的なスタンスがまだ企業側には根強くあり、自分ごととして捉えている日本人は少数なのだ。", "人間が生活を営み、またさまざまな産業活動をおこなっていくにあたり、生物の生存に関わる空気に少なからず影響を与えることは避けられない。"], "imgs": ["assets/photos/post-23_b4.jpg"]}]},
{"no": 41, "corp": "株式会社ワラカド", "name": "島田 悠一", "role": "", "star": 3, "head": "モットーは「笑門来福」6店舗を構えている千葉の若旦那", "prof": "千葉県船橋市出身。2007年、上智大学卒。2008年に株式会社リクルートスタッフィング入社後、2010年に和食居酒屋「秀吉」入社。2012年、個人事業主として居酒屋「笑かど」を設立し、2019年、株式会社ワラカドを創業。", "url": "https://www.warakado.co.jp/", "photo": "assets/photos/post-40_t.jpg", "hero": "assets/photos/post-40_h.jpg", "secs": [{"h": "モットーは「笑門来福」6店舗を構えている千葉の若旦那", "ps": ["株式会社ワラカドは『串焼きと大衆酒場 笑かど』をはじめとした飲食店を6店舗6業態、すべて自社開発で展開している千葉の会社だ。学生の方でも気軽に訪れることができるカジュアルな居酒屋から、特別な空間とぜいたくなひとときを味わえる焼肉店まで幅広く展開している。", "社名は『笑う門には福来る』ということわざから来ていると話す創業者の島田代表。地域の方はもちろん、スタッフの笑顔を守ることを大切にしつつ、『地域の方に愛される』そして『地域の方が求めている』お店づくりをモットーにしているという。", "「最初の拠点を千葉にして以来、ご縁をいただいて、現在6店舗まで出店にこぎつけてきました。そのほとんどがたまたま千葉県だったというのも深い縁を感じています。"], "imgs": ["assets/photos/post-40_b1.jpg"]}, {"h": "浪人時代を乗り越えて見つけた「大切さ」とは", "ps": ["進学校に通っていたものの、実は勉強についていけず落ちこぼれていた高校時代の島田代表。しかし1年間浪人生として死ぬ気で勉強し、そこで第一志望の大学に入学できたことで『やりきることの大切さ』を学べたという。", "そして卒業して社会人3年目、自分の夢であった起業を叶えようと真剣に考えたときに『メンバー一人ひとりが主役になれる』点に魅力を感じ、飲食業で起業することを決意。その後28歳で、地元の高根公団で串焼き居酒屋をオープンした。", "しかし設立して数年、売上も芳しくなく、社員はどんどん離れていき、代表自身が自暴自棄になりそうな時期があったという。「そんなとき父に「お前の強みはポジティブなところしかないんだから、頑張れ」と言われたんです。そこでハッと「やりきることの大切さ」を思い出して、なんとかくじけずに頑張り続けて今につながっています。あの言葉がなかったら、今の僕はいませんよ。」と島田代表は語る。"], "imgs": ["assets/photos/post-40_b2.jpg"]}, {"h": "スタッフの魅力がたっぷり詰まった店づくりを目指して", "ps": ["現在は『取材の来るようなお店作り』を掲げ、今ある店舗をさらに良い店舗へと改善するべく、日夜試行錯誤を重ねている島田代表。スタッフこそが会社の強みだと捉えており、スタッフの待遇改善や、スタッフの魅力が最大限発揮される店舗の展開の準備も進めているのだとか。", "ブランドイメージを確立出来るような再現性の高い業態と、個人の力が活きるおもてなしの魅力が詰まった業態、この2つの軸を中心に経営戦略を構築している株式会社ワラカド。多店舗展開を目指すなかで、どんなところでも『ウチの街にもワラカドのお店をつくってほしい！』と言っていただけるようなお店づくりとチームづくりを目指している。"], "imgs": ["assets/photos/post-40_b3.jpg"]}]},
{"no": 42, "corp": "花澤林産興業株式会社", "name": "花澤 直輝", "role": "代表取締役", "star": 3, "head": "5代続くあすみが丘の老舗不動産", "prof": "2005年、日本大学大学院理工学研究科海洋建築工学専攻修士課程卒。2005年、東急不動産株式会社入社。2012年、花澤林産興業株式会社入社。2016年、花澤林産興業株式会社専務取締役就任。2018年、花澤林産興業株式会社代表取締役就任。宅地建物取引士、2級土木施工管理技士、管理業務主任者、賃貸不動産経営管理士の資格をそれぞれ取得している。", "url": "https://www.hanazawarinsan.co.jp/", "photo": "assets/photos/post-29_t.jpg", "hero": "assets/photos/post-29_h.jpg", "secs": [{"h": "5代続くあすみが丘の老舗不動産", "ps": ["千葉市緑区に位置するニュータウン、あすみが丘。高層マンションや大規模公園をはじめ、あすみが丘ブランニューモール、果ては日本人画家の写実画をメインに展示しているホキ美術館が存在している、大規模開発都市だ。地区に隣接しているJR土気駅には外房線が通っており、都心部へのアクセスも良好。まさに理想的なベッドタウンと言っても過言ではない。", "花澤林産興業株式会社は、土気駅からほど近い地に拠点を構えるあすみが丘を中心とした千葉全域の不動産の売買・賃貸の仲介を手掛ける不動産会社だ。創業当初は名前の通り木材の製材などにも携わっていたが、現在は不動産業のほか自社ビルのテナント経営、太陽光発電による売電事業も手掛けている。", "花澤代表で5代目となる花澤林産興業株式会社。一体この会社は、どのような思いで地元に関わってきたのだろうか。"], "imgs": ["assets/photos/post-29_b1.jpg"]}, {"h": "先代の思いを胸に取り組んだ土地開発計画", "ps": ["創業当初は現在の本社と異なる場所で木材の製材などにも携わっていたが、不動産業中心になってからは土気を活動の拠点としている。近隣住民からの認知も高く、古くから周辺地域の相場感にも精通している点に不動産業界としての強みがある。また、稲毛海岸から鴨川までビルや別荘地などの管理物件を有しており、管理会社と連携して現地管理を行うことで安定的な物件運用を行っている。", "名前の通り当初は土気地域を中心に林業と建築業を行っていた。そして当時から所有していた山林などの不動産を、時代の変化と共に売買・交換などを経て不動産業へシフトしていき、現在の業態となっている。", "大きな転機となったのが1980年代からはじまった土地区画整理事業だった。花澤林産興業株式会社はこの事業において、あすみが丘及びあすみが丘東地区における土地区画整理組合の一員として、長年携わってきたのだ。その際、街づくりのノウハウや地権者との交渉過程など、特別な経験を数多く積むことができたという。"], "imgs": ["assets/photos/post-29_b2.jpg"]}, {"h": "事業を続ける秘訣は「人のつながり」を大切にすること", "ps": ["現在の主な業務は稼働中の物件の総点検。修繕必要箇所などを洗い出して順次必要な対応をしているという。長年使用している物件もあるものの、耐用年数を越えている箇所は交換して長寿命化させ、継続的に使用・収益化出来るよう日々メンテナンスしている。昨今のゲリラ豪雨などの異常気象や、大規模地震などの想定外の災害にも対応できるよう事前に備えるようにもしているという。", "当時代表取締役をしていた父から引き継ぐ形で入社した花澤代表。当時働いていた会社で続けていくか悩んだという。しかし、代々続いてきたこの会社を失くしてしまうのは絶対にもったいないことだと思い、先代達に恥じぬよう、より良い会社に出来るよう頑張っていくことを目指し、引き継ぐことを決意した。", "「自分が生まれ育った地域で、長く経営している会社として地域に愛されていることを少なからず誇りに思います。長いからこその認知度や、昔からの仲間とのつながりが会社を助けてくれることもあり、恵まれた環境だと感じています。商工会や法人会といった集まりでも地元の仲間がいることで安心できますね。」と語る花澤代表。学生時代に本格的に始めたゴルフから交友関係を深めたりと、人とのつながりを誰よりも大切にしている。"], "imgs": ["assets/photos/post-29_b3.jpg"]}, {"h": "地元で一番愛される企業を目指して", "ps": ["これからも地域密着型の企業として、周辺地域にお住いの方々へ恩返しできるよう、また一つ一つの案件に対して全力で迅速に取り組んでいくことを大切にしていきたいと花澤代表は語る。", "「現在まで続いた花澤林産興業株式会社という企業の長い歴史の中で、困難な時期もあったかと思います。それを乗り越え続けてこられた先人達の根底の想いは、やはり人々のお役に立ちたいというものでした。私自身もお客様から先代達の話をお聞きする機会も多く、末永く愛される地元一の企業を目指してまいります。顧客第一主義ができる、「豊かなくらしのクリエーター」となってお住まい探しのお手伝いが出来ればと考えています。」そう語る代表の表情からは、先代から受け継がれてきた、あすみが丘への愛を感じた。"], "imgs": ["assets/photos/post-29_b4.jpeg"]}]},
{"no": 43, "corp": "有限会社大川園", "name": "大川 雅樹", "role": "", "star": 3, "head": "“敷居が高い”お茶屋のイメージを変えるために", "prof": "1989年、千葉県立泉高校卒業。1989年、株式会社トムエンタープライズ入社。1991年、有限会社根古谷商会入社。1995年、有限会社大川園を創業。現在に至る。", "url": "https://www.ookawaen.com/", "photo": "assets/photos/post-44_t.jpg", "hero": "assets/photos/post-44_h.jpg", "secs": [{"h": "“敷居が高い”お茶屋のイメージを変えるために", "ps": ["有限会社大川園は、千葉都市モノレール千城台駅に直結しているショッピングセンターイコアス千城台1Fにある、日本茶と千葉県の名産品を販売している専門店だ。店内には日本茶ティースタンドを併設し、若い世代でも気楽に来店できる店づくりをしている。また遠方の方でも気軽にお茶の良さを知ってもらえるよう、キッチンカーで千葉県各所を巡行し、店頭で販売している日本茶やデザートなどを提供している。", "敷居が高いお茶屋のイメージを変えたい、そう語るのは代表の大川雅樹氏。彼が語る大川園の未来とは、いったいどんなものなのだろうか。"], "imgs": ["assets/photos/post-44_b1.jpg"]}, {"h": "過去「らしくないお茶屋」を目指して", "ps": ["高校卒業後、自動車整備会社に数年勤務していた大川代表。父親がお茶屋を経営していたことに影響を受け、1995年に有限会社大川園を創業し千葉県を代表する「お茶屋らしくないお茶屋」を目指したという。", "「以前はお茶には煎餅が合うと思い、店舗に煎餅焼き設備を構え、職人が一枚一枚手焼き煎餅をお客様の眼の前でつくって販売していたこともあります。そのときに千葉の米の良さが解り、千葉の環境は素晴らしいと感じました。こうした試行錯誤をいくつも続けて、今の大川園は成り立っていると言っても過言ではないですね。」と明るい声で、大川代表は語った。"], "imgs": ["assets/photos/post-44_b2.jpg"]}, {"h": "現在常に新しいことに挑戦する大川園", "ps": ["常にお客様目線で考える事を大切にしているという大川代表。キッチンカー事業では、日本の文化を大事にするために「和風キッチンカー協会」を設立、神社などに積極的に出店しているという。", "「学生時代のハンドボール部の恩師からいただいた「もっと上を目指さなければ人は成長しない」ということばが、今も私の中に、そして弊社の行動指針に息づいています。だからこそ、おかげさまで順調な営業を続けられている今、新しいことに挑戦しなければならないと常々感じています。」と語る大川代表。これからの大川園の活躍に、目が離せない。"], "imgs": ["assets/photos/post-44_b3.jpg"]}]},
{"no": 44, "corp": "株式会社タルブ", "name": "竹見 茂雄", "role": "", "star": 3, "head": "“千ブランド”認定。地元で人気の有名スイーツ店", "prof": "茨城県出身。1991年に辻製菓専門学校を卒業後、洋菓子専門店の株式会社ミルフィーユに就職。その後1997年にフランスの老舗菓子店ロワイヤリティにて技術を磨き、1998年、株式会社シェ・シーマに入社。2004年にパティスリータルブを創業し、2010年株式会社タルブを設立。", "url": "https://tarbes04.jp", "photo": "assets/photos/post-32_t.jpg", "hero": "assets/photos/post-32_h.jpeg", "secs": [{"h": "“千ブランド”認定。地元で人気の有名スイーツ店", "ps": ["千葉市の海浜幕張、花見川の河口近くにあるパティスリータルブは、2004年にオープンした大人気のケーキショップだ。フランス南西部の都市の名前がつけられたこのお店には、フランスの老舗菓子店ロワイヤリティで修行を重ねた代表の竹見氏によってつくられた、さまざまなスイーツが並んでいるのが特徴。各スイーツは日本人にフィットした食感や舌触りに仕上げられており、幅広い年齢の市民に親しまれている。", "特にタルブの名物商品である幕張スイーツ『昆陽』は有名だ。千葉市が選定する「千葉市「食」の“千ブランド”第三回認定品」として登録されているこのスイーツは、千葉県産のさつまいもを裏ごしした餡に、クリームチーズを詰めて求肥で包んだ極上の逸品。甘さを抑えつつ、なめらかな口当たりを楽しめるため女性からの人気が高い。 「幕張スイーツ『昆陽』は、幕張新都心賑わいづくり研究会の方たちと共同開発しました。もちろん味に自信はありましたが、やはり千ブランドに認定されたと聞くまではドキドキしていましたね。」とはにかむ竹見代表に、パティスリータルブへの想いについて語ってもらった。"], "imgs": ["assets/photos/post-32_b1.jpg"]}, {"h": "画面越しに魅了されたパティシエの背中を追って", "ps": ["竹見代表がパティシエを目指すきっかけとなったのは、中学生のときにふと見ていた料理番組だった。美しいスイーツをその手でつくり上げるパティシエの姿にひどくあこがれたのだと竹見代表は語る。", "辻製菓専門学校を卒業後、洋菓子専門店の株式会社ミルフィーユに就職。その後渡仏した竹見代表は、有名な老舗菓子店ロワイヤリティにて技術を磨くこととなる。「約1年という短い期間でしたが、日々の生活から毎日の食事の面、そして仕事に向かう姿勢といった、パティシエとしてのベースになる部分はすべてフランスで培いました。」と語る竹見代表。帰国後は全国でも有名な洋菓子店や老舗の和洋菓子屋で修行を重ね、夢だった京葉線の美しい海が広がる海浜幕張にパティスリータルブをオープンした。"], "imgs": ["assets/photos/post-32_b2.jpg"]}, {"h": "タルブならではの“こだわり”とは", "ps": ["たとえばケーキをつくるときになくてはならない卵は状況によって2種類使い分けている。卵ロールケーキや卵プリンなど卵の味を強調したスイーツをつくるときは、千葉県市原市の「川嶋農場」で放し飼いされた鶏から生まれる「有精卵」を使用。そしてムースやカスタードクリームといったより鮮度が求められるものをつくるときは、味そして衛生面においても優れているとされる千葉県君津市の無菌状態で育てられた鶏から生まれる「無菌卵」を使用している。", "またパティスリータルブでは光触媒の浄水器を水道栓自体に取り付けているため、どこの蛇口をひねっても浄水が出る構造になっている。肌にやさしい光触媒の水は特にゼリーやコーヒーと非常に相性が良く、使用する食材の味を引き立てる。", "そして、小麦や卵が食べられず誕生日ケーキを食べることができない子どもたちのためにもっと気軽に誕生日をお祝いさせてあげたいという思いから、パティスリータルブでは卵や小麦粉を使用しないケーキをつくれる体制を整えている。予約すればいつでもつくってもらえるため、特に小さい子どもがいるご家族からの注文が止まらないのだとか。"], "imgs": ["assets/photos/post-32_b3.jpg"]}, {"h": "至福のひとときを過ごしてもらうために", "ps": ["竹見代表には信念がある。「タルブのスイーツなら安心できると多くのお客様に感じていただく」ことだ。そのため、パティスリータルブに並んでいるスイーツのほとんどは地元千葉県で採れた素材、そして作り手が見える素材を使用しており、それ以外の素材は使用していない。", "パティスリータルブでつくったスイーツで、至福のひとときを過ごしてほしい。思いを届けるために、今日もまた竹見代表はスイーツをつくり続ける。"], "imgs": ["assets/photos/post-32_b4.jpg"]}]},
{"no": 45, "corp": "学校法人増田学園 千葉聖心高等学校", "name": "三浦 勤治", "role": "校長", "star": 0, "head": "受け継がれる「聖心・努力・奉仕」の精神", "prof": "1957年、山形県鶴岡市生まれ。 学生時代に打ち込んだ柔道を通じて「人を育てること」への情熱を抱き、教育の道を志した。順天堂大学卒業後は、千葉県船橋市の公立中学校教諭、県教育委員会や公立中学校・高等学校の校長、2018年より現職を務める。厳しさの中にも深い愛情を持って生徒や教職員と向き合うことを信条として公立学校での豊富な経験と、私学ならではの柔軟な発想を融合させ、「生徒が自信を持ち、笑顔で卒業できる学校づくり」にその手腕を振るっている。", "url": "https://www.chibaseishin-h.ed.jp/", "photo": "assets/photos/post-4132_t.jpg", "hero": "assets/photos/post-4132_h.jpg", "secs": [{"h": "受け継がれる「聖心・努力・奉仕」の精神", "ps": ["千葉聖心高等学校の歴史は昭和22年に創立された千葉洋裁学院に遡る。学祖・増田うめ先生が掲げた建学の精神「聖心・努力・ 奉仕」は今日に至るまで同校の教育の根幹を成している。特に「努力」という言葉には学祖自身の原体験が深く刻まれている。学祖の父は娘の将来を見据え、精神力と強い根性を養うために毎晩長時間の自己学習を課したという。「父の教育の力が現在の私に精神力、忍耐力、そして努力等を養ってくれた」と学祖が述懐するように、この精神は今の生徒たちにも脈々と受け継がれている。", "三浦校長は「二十一世紀を逞しく生きる個性豊かな女性を育成するためには、信頼関係の構築や善悪を判断する力、そして道徳心と教養が不可欠です」と語る。礼儀正しさや日常の立ち居振る舞いを重んじ、「凡事徹底」を合言葉に、挨拶が自然に交わされ、笑顔が絶えない温かい学校づくりを推進している。"], "imgs": ["assets/photos/post-4132_b1.jpg"]}, {"h": "系列校の千葉女子専門学校との連携教育", "ps": ["同校の大きな特色の一つが、系列校である千葉女子専門学校との連携教育だ。特に保育者育成においては県内でも稀有な強みを持つ。千葉女子専門学校は、千葉県内で唯一2年間で、幼稚園教諭と保育士の二つの国家資格を国家試験を受験することなく卒業と同時に取得できる認定校である。", "「近年は幼保連携型認定こども園が増加しており、幼稚園教諭と保育士の両方の資格を持つことが就職において大きなアドバンテージとなります。本校の生徒は、高校時代から附属のこども園や系列の保育園で実習を行うことができ、専門学校進学後もスムーズに学びを継続し、深めることができます」と三浦校長は胸を張る。", "生徒は2年次から「こども保育コース」「進学コース」「総合コース」を選択できる。特に「こども保育コース」では、保育の専門性をしっかりと身につけられる。2・3年次で行われる実習では、実際の現場に触れながら学べる点が大きな特徴である。保育に関する専門科目がカリキュラムに豊富に設定され、子どもの発達理解や保育技術を段階的に習得できる。また、保育検定にもチャレンジできる環境が整っており、資格取得を目指す生徒をしっかりサポートしている。全国家庭科部会で行われている保育検定1級取得者が、県内1位であることも自慢の一つであり、実践力と資格取得の両方を重視した学びができる学校である。"], "imgs": ["assets/photos/post-4132_b2.jpeg"]}, {"h": "「対話を大切にし」「寄り添う」教育", "ps": ["教員は生徒に積極的に声をかけ、生徒の小さな変化やサインを見逃さない。生徒一人ひとりのペースや背景を尊重し、教員が答えを示すのではなく、生徒自身が考え自分で判断し実践する方向へと導くことを尊重する。学校は知識を与える場であると同時に、自ら考え、成長していく場でもある。だからこそ、生徒が卒業後に自立して歩んでいけるよう、学びのプロセスを支える存在として教員が寄り添うことが重要になる。", "本校のアドミッションポリシーとして、「高校生活を頑張る生徒、自分を変えたい生徒」の希望の門戸を広げ、入学後は「リスタート」の場として全力でサポートする。「一人でも多くの生徒に『この学校に入学してよかった』多くの保護者に『この学校に通わせてよかった』と思ってもらえる学校でありたい。生徒が笑顔で生き生きと活動する姿を見ることが私たち教員にとって何よりの喜びです」と三浦校長は目を細める。"], "imgs": ["assets/photos/post-4132_b3.jpeg"]}, {"h": "柔道と恩師の言葉が導いた教育者への道", "ps": ["自身の経歴もまた、教育への情熱を物語っている。味噌醤油醸造業の家の二男として生まれた三浦校長は、幼少期から家業を手伝い、働くことの尊さを肌で感じて育った。転機となったのは、柔道との出会い、そして常に親身になって指導してくださった高校・大学の恩師の存在だった。", "「高校時代の恩師からは、人との出会いの素晴らしさを、大学時代に恩師からは、柔道の厳しさを教えられ、柔道を通して人を育てる教育者を志す決定的なきっかけとなりました」と語ってくれた。", "さらに三浦校長は、「厳しさと優しさのバランス、そして山本五十六の言葉『やってみせ、言って聞かせて、させてみせ、ほめてやらねば、人は動かじ』が示す、信頼と対話を重んじる姿勢はこれまでの経験から培われた私の教育哲学です」と話してくれた。"], "imgs": ["assets/photos/post-4132_b4.jpeg"]}]},
{"no": 46, "corp": "有限会社かし熊", "name": "椎名 航一", "role": "代表取締役", "star": 0, "head": "「創業の地」と共に歩む覚悟と、経営者としての冷静な視点", "prof": "理系大学を卒業後、IT企業にてシステムエンジニア・プログラマーとして勤務。30歳で家業である有限会社かし熊に入社。IT業界で培った知見を活かし、社内のIT化・DXを推進する。現在は代表取締役として、津田沼駅周辺および千葉市、八千代市に保有する計7棟のビルの経営管理を行う傍ら、船橋市前原商店会や第4回ふなばし市民まつり津田沼会場実行委員長を務めるなど、地域振興にも尽力している。", "url": "https://kashikuma.co.jp/", "photo": "assets/photos/post-4167_t.jpg", "hero": "assets/photos/post-4167_h.jpg", "secs": [{"h": "「創業の地」と共に歩む覚悟と、経営者としての冷静な視点", "ps": ["有限会社かし熊の事業の根幹は不動産賃貸業である。現在、同社は7棟の収益ビルを保有しており、そのうちの5棟が津田沼駅周辺、特に前原西エリアに集中している。これは単なる資産の偏りではない。椎名の曾祖父の代から脈々と受け継がれてきた「津田沼の発展と共に会社を成長させる」という創業家のアイデンティティそのものと言える配置だ。", "「私たちの歴史は、津田沼という街の歴史と不可分です。街が栄えれば会社も潤い、会社が力をつければ街に還元できる。この好循環を作ることが、代々の使命でした」と椎名は語る。", "しかし、四代目として経営の舵を取る椎名の視点は単なる郷土愛だけに留まらない。彼は就任後、事業の永続性を確保するために、あえて創業の地以外への投資も行っている。現在保有する7棟のうち2棟は千葉市や八千代市など近隣エリアに分散して取得したものだ。一極集中のメリットである管理効率の良さを理解しつつも災害リスクやエリアごとの経済変動を見据えてポートフォリオを最適化する。そこには「守るべき場所（津田沼）」を確実に守り抜くために経営基盤を盤石にするという冷徹な計算と熱い想いが同居している。"], "imgs": ["assets/photos/post-4167_b1.jpg"]}, {"h": "「0から1を生む」エンジニアの魂がアナログな家業を変えた", "ps": ["椎名のキャリアは老舗不動産会社の跡取りとしては異色だ。学生時代からプログラミングに没頭し、理系大学を経てIT企業に就職。約5年間エンジニアとしてシステム開発の最前線に身を置いてきた。「自分の書いたコードが動き、形になり、それが価値を生む。そのクリエイティブなプロセスに魅了されていました」と当時を振り返る。", "30歳を機に家業に戻った彼を待っていたのは、IT業界とは対極にある世界だった。建物というハードウェアはそこにあるものの自身が手を動かして何かを生産するわけではない不動産賃貸業。「何も作っていないのに収益が上がる」というビジネスモデルに、ものづくりに情熱を注いできたエンジニアとしての自分との間で強烈な葛藤が生まれたという。さらに、当時の社内は驚くほどアナログで、情報の管理や共有が旧態依然としたまま放置されていた。", "しかし、椎名はこの違和感を「改革の種」へと変えた。「郷に入っては郷に従え」で一度は既存のやり方を受け入れつつもエンジニア時代に培った論理的思考と技術力を武器に社内のDXを断行したのだ。紙ベースだった情報のデジタル化、検索性の向上、業務フローのシステム化。これらは単なる効率化ではない。社員が煩雑な事務作業から解放され、テナントへの細やかな対応や、後述する地域活動へとリソースを割くための「時間」を生み出す改革だった。かつて「0から1を生み出す」ことに喜びを感じたエンジニアの魂は今、組織というOSをアップデートし新たな企業文化を創造することに向けられている。"], "imgs": ["assets/photos/post-4167_b2.jpg"]}, {"h": "街の鼓動を取り戻せ――100,000人を熱狂させた市民まつり", "ps": ["椎名の活動は、社内の改革だけに留まらない。「津田沼の発展なくして、かし熊の発展なし」この信念は具体的なアクションとなって街に還元されている。その象徴と言えるのが「ふなばし市民まつり」における津田沼会場の運営だ。 コロナ禍や大型商業施設の撤退により、一時期元気を失いかけていた津田沼。その閉塞感を打破しようと立ち上がったのは、椎名を含む地元商店会のメンバーたちだった。彼らは市や関係各所に粘り強く働きかけ公道を封鎖した大規模なイベント会場の設置を実現させた。2023年に行われた第1回開催では土曜日の1日だけで約40,000人が来場。2025年の第3回では天候にも恵まれて1日あたり50,000人を超える人々が津田沼の通りを埋め尽くした。会場には屋台が並ぶだけでなく自衛隊や消防、警察の協力による特殊車両の展示、地元の子供たちによるパフォーマンスなどが行われ、まさに「地域総出」の祝祭空間が生まれた。", "「実行委員として準備に関わり、当日は裏方として走り回りました。来場された皆さんの笑顔や活気を取り戻した通りの光景を見た時に不動産業だけでは得られない種類の達成感がありました」", "かつて父親が商店会長として街のために奔走していたように椎名もまた、地域コミュニティのハブとなり人と人、人と街を繋いでいる。この泥臭くも温かい活動こそがテナントや住民からの信頼という貸借対照表には載らない無形の資産を築き上げているのだ。"], "imgs": ["assets/photos/post-4167_b3.jpg"]}, {"h": "「自分の芯」を持つこと――次世代へ繋ぐリーダーの哲学", "ps": ["激動の時代において、四代目として会社を背負うプレッシャーは計り知れない。しかし椎名の言葉には迷いがない。彼が経営者として、そして一人の人間として最も大切にしているのは「確固たる判断基準（芯）を持つこと」だという。", "「正解のない時代です。予期せぬトラブルも起きます。そんな時、周囲の声に流されるのではなく『自分はどうありたいのか』『会社として何を大切にするのか』という軸に立ち返ることが重要です。そして、一度決めたら過去を振り返って後悔しないこと。その時の自分がベストを尽くして選んだ道なら、結果がどうあれ受け入れ、そこから次の一手を考える。その積み重ねが自分らしい経営を作っていくのだと思います」", "エンジニアとしての論理的思考と老舗経営者としての伝統への敬意。そして、地域を愛する一人の住民としての情熱。これらを併せ持つ椎名は、まさに津田沼という街の「守り人」であり同時に「革新者」でもある。"], "imgs": ["assets/photos/post-4167_b4.jpg"]}]},
{"no": 47, "corp": "株式会社セーフティ・アラート", "name": "平野 征夫", "role": "", "star": 0, "head": "安定を求めた創業の原点", "prof": "大学卒業後、大手電機メーカーの特約店にて空調設備のエンジニアとしてキャリアをスタート。日々の緊急対応に追われる中で、法令に基づき計画的かつ安定した需要のある「消防設備」の業務に将来性を見出し、25歳で転身を決意する。現場での修業を経て、平成元年（1989年）、35歳で独立し同社を設立した。 現在は、一般社団法人千葉県消防設備協会の理事も務め、業界全体の発展に尽力している。", "url": "https://www.safetyalert-chiba.com/", "photo": "assets/photos/post-4177_t.jpg", "hero": "assets/photos/post-4177_h.jpg", "secs": [{"h": "安定を求めた創業の原点", "ps": ["平野がこの業界に足を踏み入れたのは意外なきっかけだった。大学卒業後、最初に就職したのは大手電機メーカーの特約店。そこでエアコンや空調設備のサービスエンジニアとしてキャリアをスタートさせた。", "「当時はとにかく忙しかったですね。夏と冬の繁忙期はもちろんですがエアコンというのは『壊れたからすぐ来てくれ』という緊急の呼び出しが常なんです。お客様にとっては死活問題ですから24時間体制で対応しなければならず精神的にも体力的にも休まる暇がありませんでした」", "「ある時、消防設備の点検業務を知り衝撃を受けました。エアコン修理のような突発的な対応とは異なり消防設備点検は消防法で『年2回』と定められた定期的な業務です。スケジュールがあらかじめ決まっていて計画的に仕事ができる。この『安定感』に強く惹かれました」"], "imgs": ["assets/photos/post-4177_b1.jpg"]}, {"h": "「点検」だけで終わらせない工事まで完結できる強みと「仲間」の力", "ps": ["「この業界には、点検の資格しか持っていない業者も少なくありません。点検で不備が見つかっても『直すのは別の業者にお願いしてください』となってしまう。しかし、お客様である管理会社やオーナー様からすれば不備が見つかったらすぐに直してほしいのが本音です。うちは点検で見つかった不良箇所を、その場で、あるいは後日すぐに工事して直すことができます。この『点検＋工事』を一貫して行える点が多くのお客様から選ばれている理由です」", "現在、同社は平野を含めた少数の精鋭社員と多くの協力会社によって支えられている。平野が大切にしているのは下請け業者を単なる「使い走り」にせず「対等なパートナー」として接することだ。", "「私が現場に出るのが好きだということもありますが現場を知らないと適切な指示が出せませんし協力会社さんの苦労も分かりません。丸投げにして管理だけするようなやり方ではミスが起きた時に大きな損害に繋がります。だからこそ、同じ釜の飯を食う仲間として協力し合い、信頼関係を築くことを何より大切にしています」"], "imgs": ["assets/photos/post-4177_b2.jpeg"]}, {"h": "「資格ビジネス」の真髄 若者が目指すべき独立への最短ルート", "ps": ["平野が特に熱を込めて語ったのが消防設備業界の「稼げる」ポテンシャルと若者へのキャリア提案だ。", "「今の若い人たちには、ぜひこの業界に入ってきてほしい。なぜなら、ここは『資格ビジネス』の世界だからです。消防設備士の資格は国家資格であり、これさえあれば仕事に困ることはありません。学歴も関係ない。やる気と資格さえあれば、誰でもプロフェッショナルになれます」", "平野代表が描くキャリアパスは明確だ。まずは会社に入り、資格を取得しながら技術を学ぶ。そして数年後に独立して個人事業主としてやっていくという道だ。"], "imgs": ["assets/photos/post-4177_b3.jpg"]}, {"h": "業界の未来を見据えて——次世代へのバトン", "ps": ["現在、平野は一般社団法人千葉県消防設備協会の理事も務め、業界全体の発展にも尽力している。業界全体で高齢化が進み後継者不足が叫ばれる中、平野の視線は常に「次世代」に向けられている。", "「消防設備という仕事は建物がある限り絶対になくなりません。しかし、それを支える人がいなくなれば地域の安全は守れません。だからこそ若い人たちにこの仕事の魅力を伝え、育てていきたい。会社を大きくすることよりも独立心のある元気な若者を育て、彼らとパートナーとして連携していく。そんな『緩やかだが強いネットワーク』を広げていくことが私のこれからの使命だと思っています」", "自らの経験に裏打ちされた平野の言葉には不確実な時代を生きる若者たちへの力強いエールが込められていた。地域の安全を守る誇りと自らの腕一本で生きていく覚悟。その両方を手に入れられる場所が、ここにはある。"], "imgs": ["assets/photos/post-4177_b4.jpg"]}]},
{"no": 48, "corp": "社会福祉法人 翠燿会", "name": "津川 恵美子", "role": "理事長", "star": 0, "head": "父の背中を追って診療所から始まった「奉仕」の心", "prof": "千葉県八千代市出身。地域医療の礎を築いた朝戸家５人きょうだいの長女として生まれ、幼少期より医療・福祉の現場を身近に育つ。大学で社会福祉を専攻後、精神科病院でのソーシャルワーカー勤務を経て父が開設した社会福祉法人翠燿会に入職。平成10年、3８歳で理事長に就任。 介護保険制度施行前より、地域ニーズに応じたデイサービスやショートステイの拡充に尽力。同窓の夫である常務理事と共に「選ばれる施設」を目指し、接遇マナーの向上や理念共有のための『グリーンヒルの心』、『クオリティブック』を導入するなど、組織改革を推進した。現在は、外国人介護人材の積極的な採用・育成や、放課後等デイサービス、自立援助ホームの開設など、時代の変化に合わせた多角的な福祉事業を展開している。", "url": "https://www.greenhill.or.jp/", "photo": "assets/photos/post-4195_t.jpg", "hero": "assets/photos/post-4195_h.jpg", "secs": [{"h": "父の背中を追って診療所から始まった「奉仕」の心", "ps": ["翠燿会の歴史は今から60年以上前の昭和37年にまで遡る。津川理事長の父が開設した「朝戸医院」がその原点だ。当時はまだ八千代市が「千葉郡八千代町」だった時代。現在の八千代台の施設から歩いて数分の場所に産声を上げた小さな診療所はその後「朝戸病院」となり、地域の人々の命と健康を守り続けてきた。", "「父が生きていれば97歳、母は94歳で今も元気です。父たちが築いた土台の上に、今の私たちがあります」", "医療から始まった朝戸家の事業は時代の変化とともに福祉の分野へと広がっていく。昭和56年、八千代市で初となる特別養護老人ホーム「グリーンヒル」を開設。昭和61年には千葉県初のデイサービス事業を開設し、その後、隣接地には弟が院長を務めるセント・マーガレット病院が開院し医療と福祉が連携した「グリーンヒル」のエリアが形成された。"], "imgs": ["assets/photos/post-4195_b1.jpg"]}, {"h": "「入り口は笑顔」 心の羅針盤 『グリーンヒルの心』 と 『クオリティブック』", "ps": ["60年以上の歴史の中で、組織が大きくなっても変わらないものがある。それは「心」だ。『グリーンヒルの心』という行動理念の標語があり、毎月の朝礼で読み合わせを行っている。また、翠燿会では全職員が携帯する『クオリティブック』という小冊子がある。これは法人の行動指針をまとめたもので、職員ひとりひとりに配布している。", "その中でも津川理事長が特に大切にしているのが「笑顔」だ。 資格のあるなし、よりも「入り口は笑顔」、「技術は後からついてくる」と年に２回の新人研修では伝える。", "「私たちの施設にいらっしゃるお客様は、ご自身やご家族のことで何らかの不安や悩みを抱えて来られます。だからこそ、スタッフの笑顔と挨拶が何より大切です」"], "imgs": ["assets/photos/post-4195_b2.jpg"]}, {"h": "国境を越えた“家族”の絆 外国人スタッフと共に", "ps": ["現在、介護業界は未曾有の人材不足に直面している。「新卒の日本人の若者が介護職を目指すことが少なくなってしまった」と津川理事長は現状を憂う。しかし、翠燿会ではそのピンチをチャンスに変え、新たな活力を生み出している。それが、外国人スタッフの活躍だ。", "現在、翠燿会ではベトナム、ミャンマー、フィリピン、インドネシア、ペルー、スリランカなどから約10名の外国人スタッフを受け入れている。「彼女たちは本当に優秀で、努力家です」", "「彼女たちが日本の国家資格である介護福祉士の試験に受かるよう、私たちも全力でサポートします。」"], "imgs": ["assets/photos/post-4195_b3.jpg"]}, {"h": "感謝のバトンを次世代へ", "ps": ["「私たちは、ただお世話をするだけじゃない。ご利用者とご家族の笑顔のために、がモットーです。」", "特養に入所すると、ご家族での外出はなかなか出来なくなる、そのような中、ご利用者とご家族が共に楽しんで笑顔になれる季節の行事を数多く計画する。その中でも年に数回、プロの歌手を招いての「昭和歌謡コンサート」は毎回５０名近くのご家族が参加され、ご家族で楽しい時間を過ごして頂く。ご家族で楽しんで下さる様子をみて、私たちも幸せな気持ちになります。", "「職員も高齢化して来ておりますので次の若い世代を育てることが急務であり、そしてこの翠燿会を盛り上げていってほしい」"], "imgs": ["assets/photos/post-4195_b4.jpg"]}]},
{"no": 49, "corp": "日触テクノファインケミカル株式会社", "name": "平尾 晴紀", "role": "代表取締役社長", "star": 0, "head": "危機を乗り越え、変革し続けた70年", "prof": "2024年6月、代表取締役社長に就任。1992年に株式会社日本触媒に入社以来、ベルギーでのプラント建設プロジェクトを完遂するなど、国内外のモノづくり現場を牽引してきたエンジニア出身のリーダー。困難な状況でも知恵を絞り、挑戦を続ける不屈の精神で、DXも取り入れた既存事業の生産効率化や新素材「ZINLEX™」の事業化を推し進める。社員とその家族が心から誇れる「100年企業」を目指し、対話を重ねながら組織の新たな可能性を切り拓いている。", "url": "https://www.ns-technofine.co.jp/ja/", "photo": "assets/photos/post-4204_t.jpg", "hero": "assets/photos/post-4204_h.jpg", "secs": [{"h": "危機を乗り越え、変革し続けた70年", "ps": ["同社の歴史は、平坦な道のりではなかった。1954年、日本触媒化学工業株式会社（現・株式会社日本触媒）の無水フタル酸事業の原料となるナフタレンを生産するために「日本蒸溜工業株式会社」として設立されたのが始まりだ。当初はタール蒸留技術を基盤としていたが時代の変化とともに主力製品の市場環境は激変した。", "「当社の70年は、変化への対応の歴史そのものです。特に2000年前後は最大の試練でした。長年の主力製品が海外との価格競争や環境規制の強化によって苦戦を強いられ、さらには品質管理の問題や海外進出の撤退など、内憂外患の危機に直面しました」", "しかし、同社はそこで歩みを止めなかった。タール系事業からの脱却を決断し有機合成分野へと大きく舵を切ることで新たな活路を見出したのだ。苦難の中で培われた「変化を恐れないDNA」は2011年の東日本大震災の際にも発揮された。液状化による甚大な設備被害を受けながらも、社員が一丸となって復旧にあたり驚異的な速さで生産を再開させたという。"], "imgs": ["assets/photos/post-4204_b1.jpg"]}, {"h": "「対話」が変える組織の未来", "ps": ["「就任直後の2ヶ月間、約100名の社員全員と1対1で対話会を行いました。一人あたり30分から1時間。大変でしたがやってよかったと心から思っています」", "大企業でのマネジメント経験を持つ平尾だが、日触テクノファインケミカルのような100名規模の組織には特有の良さと課題があるという。", "「100名という規模は社長の顔が見え社員一人ひとりの顔も見える。ちょうどいい距離感なんです。ただ、真面目で実直な社員が多い反面、どこか『上からの指示待ち』な雰囲気も感じられました。これだけ変化の激しい時代、トップダウンだけで正解を出し続けることは不可能です。現場を知る社員一人ひとりが自ら考え、発信し、議論し、行動する組織に変わらなければなりません」"], "imgs": ["assets/photos/post-4204_b2.jpg"]}, {"h": "次世代の柱「ZINLEX™」と、千葉から世界へ", "ps": ["現在、同社が総力を挙げて取り組んでいるのが、新規事業開発だ。その筆頭が独自技術により開発された可溶性アクリル酸亜鉛「ZINLEX™（ジンレックス）」である。", "「これまで固体でしか扱えなかったアクリル酸亜鉛を独自の技術で溶剤に溶ける形にした画期的な製品です。これにより、塗料やコーティング剤など、これまでは使えなかった用途への展開が可能になりました。昨年特許も取得し展示会などでも大きな反響をいただいています」", "既存の強みである「固体・粉体」の技術に新たな発想を掛け合わせることで生まれたこの新素材は、同社が100年企業となるための柱として期待されている。さらに、全社的な生産性向上活動やDXの推進にも余念がない。"], "imgs": ["assets/photos/post-4204_b3.jpg"]}, {"h": "誇りを持てる「100年企業」へ", "ps": ["「目標は経営理念の通り、『価値ある素材やサービスを安定的に供給し、社会に貢献する』ことです。しかし、それを実現するのはあくまで『人』。社員全員が『この会社で働いていてよかった』と思える、そして社員の家族も誇りに思えるような会社にしたい。あきらめずに挑戦を続ければ、必ず実現できると信じています」", "かつてナフタレン製造から始まり、幾多の変革を経て、今また「ZINLEX™」という新たな武器を手に未来へ挑む日触テクノファインケミカル。", "「白基調の作業着は汚れが目立つから、現場では不評かもしれませんね」と笑う、だがその眼差しは、汚れを恐れずに現場で汗を流す社員たちへの温かいリスペクトに満ちていた。伝統と革新、そして人間味あふれるリーダーシップが融合した同社は千葉県から世界へ向けて、化学の力で新たな可能性に挑戦し続けていくことだろう。"], "imgs": ["assets/photos/post-4204_b4.jpg"]}]},
{"no": 50, "corp": "有限会社アシストハウス", "name": "篠田 真", "role": "代表取締役", "star": 3, "head": "入社した直後、創業者が急逝して社長に就任", "prof": "1964年生まれ。福岡県にて幼少期を過ごす。明治大学法学部卒業後に千代田生命保険相互会社に入社。その後、9年間の代理店勤務を経て2009年2月にアシストハウスに入社。同年6月、創業者が病に倒れ、代表取締役として会社を継承した。", "url": "http://www.assist-house.jp/", "photo": "assets/photos/post-4261_t.jpg", "hero": "assets/photos/post-4261_h.jpg", "secs": [{"h": "入社した直後、創業者が急逝して社長に就任", "ps": ["千葉県庁に近い市の中心部に店舗を構えるアフラックの専属代理店。有限会社アシストハウスは、創業者の故鹿討秀章が千葉県で個人代理店として開業した。千葉県学校生活協同組合と団体取扱契約を締結し、県内の公立学校の教職員を対象に団体募集を開始。その後法人化して現在に至る。千葉市内の学校と市町村役場を主なマーケットとして、約1万名の顧客を有することが同社の強みだ。", "同社の代表取締役を務める篠田真は、幼少期を福岡県で過ごした。大学卒業と同時に生命保険会社に新卒で就職し、退職後も別の代理店での勤務を経て2009年2月に入社した。しかし、その半年後に兼ねてから闘病中であった創業者が病に倒れて、急遽篠田が会社を継承することになった。", "会社の今後に思いを巡らせていた社長に、「私で良ければ手伝いに行きましょうか？ と言って入社しましたが、余りにも急に会社を引き継ぐことになったので、準備はまったくできていませんでした。私以外の社員は事務員2人だけで、営業部員はいませんでした。創業者は、私がやりやすいように配慮してくれたのかもしれませんが、まずは営業の人材を揃えるところからのスタートでした」"], "imgs": ["assets/photos/post-4261_b1.jpg"]}, {"h": "社員の成長を何より重視し、叱り飛ばすことはしない", "ps": ["若い社員との接し方に悩む経営者も多いが、「もともと怒ることが好きじゃない。社員の間違いはしっかり指摘するが、叱り飛ばすことは決してしません。自分が若い頃は厳しかったし、何度も怒鳴られて嫌な思いもした。自分がされて嫌だったことはしたくない」と言う。そんな篠田が最も力を入れているのは、社員教育だ。", "「経営者としては、社員の成長を何よりも重視しています。本人にとってはもちろん、お客様に対しても、正確に対応することが大事なことですから。その結果、我が社はクレームが非常に少ないんです。営業が全ての会社ですから、優秀な社員がいなければ成り立たない」", "人を育てる上で、意識していることは、保険に対する商品知識や周辺知識を正確に身につけること。"], "imgs": ["assets/photos/post-4261_b2.jpg"]}, {"h": "代理店同士の連携を進めて、「協業」を視野に共闘", "ps": ["現在、アシストハウスは千葉県内の代理店で常に成績トップ3に入る好成績を維持する。だが、少子高齢化に加えて個人情報保護の観点から、保険営業が難しい時代になっているようだ。 「新規開拓は非常に難しくなりました。新たな販売方法を模索することにも取り組んでいるし、会社の規模もある程度大きくしないといけない。県外から大手の代理店が続々と千葉県に進出してくるなど、他社の動きも激しく、生き残るためには体力をアップする必要があります」", "そんな背景から、代理店同士の連携を高める必要性も感じている。昨年11月には、高柳大介専務取締役を迎え入れた。神奈川県で代理店を経営する同氏は、千葉県進出の足掛かりを築くために篠田社長とタッグを組んだそうだ。神奈川の高柳専務の会社とは、近い将来の協業を見据えて共闘しているところだ。", "「自分のやり方を貫いて、この会社を築き上げましたが、それが古くなっているのは自覚しています。DXとかAIと言われても正直ピンときません。若い高柳専務はデジタルにも強いので、その点でも心強い。社員採用の手法なども進んでいます。私の感覚では、まず会ってみないと判断できないと考えますが、今はリモート面接を経てから二次面接という流れが当たり前ですからね」"], "imgs": ["assets/photos/post-4261_b3.jpg"]}]},
];